// ─── tm-transfer.user.js ─────────────────────────────────────────


(function () {
    'use strict';

    const $ = window.jQuery;
    if (!$) return;

    // Only match the main transfer page, not /transfer/bids etc.
    if (!/^\/transfer\/?$/.test(location.pathname)) return;

    // ═══════════════════════════════════════════════════════════════════
    //  CONSTANTS
    // ═══════════════════════════════════════════════════════════════════

    const SAVED_FILTERS_KEY = 'tms_saved_filters';

    const { SKILL_KEYS_ALL: ALL_SKILLS, SKILL_LABELS: SKILL_NAMES } = window.TmConst;

    // Individual formation position → TM API group + side
    const FP_MAP = {
        gk: { group: 'gk', side: null },
        dl: { group: 'de', side: 'le' },
        dc: { group: 'de', side: 'ce' },
        dr: { group: 'de', side: 'ri' },
        dml: { group: 'dm', side: 'le' },
        dmc: { group: 'dm', side: 'ce' },
        dmr: { group: 'dm', side: 'ri' },
        ml: { group: 'mf', side: 'le' },
        mc: { group: 'mf', side: 'ce' },
        mr: { group: 'mf', side: 'ri' },
        oml: { group: 'om', side: 'le' },
        omc: { group: 'om', side: 'ce' },
        omr: { group: 'om', side: 'ri' },
        fc: { group: 'fw', side: null },
    };

    // ═══════════════════════════════════════════════════════════════════
    //  STATE
    // ═══════════════════════════════════════════════════════════════════

    let allPlayers = [];
    let sortKey = 'time';
    let sortDir = 1;  // 1 = asc, -1 = desc
    let isLoading = false;
    let skillsMode = false;
    let tooltipCache = {};   // pid → { recSort, ti, skills }
    let tooltipFetchAbort = false;
    let findAllRunning = false;
    let findAllAbort = false;

    // ═══════════════════════════════════════════════════════════════════
    //  CALCULATION HELPERS
    // ═══════════════════════════════════════════════════════════════════

    const fmtRec = TmTransferTable.fmtRec;
    const tiHtml = TmTransferTable.tiHtml;
    const fmtR5 = TmTransferTable.fmtR5;
    const fmtR5Range = TmTransferTable.fmtR5Range;
    const BREAKDOWN_COLS = TmTransferTable.BREAKDOWN_COLS;

    const getCurrentSession = window.TmLib.getCurrentSession;
    const CURRENT_SESSION = getCurrentSession();

    // Pre-populate tooltipCache with R5 estimates for players not yet fully fetched
    function computeAllEstimates(players) {
        for (const p of players) {
            if (tooltipCache[p.id] && !tooltipCache[p.id].estimated) continue;
            const est = TmApi.estimateTransferPlayer(p);
            if (est) {
                console.log(`[TMS] ${p.name_js || p.name} | age ${p.age} | routineMax ${est.routineMax.toFixed(1)} | R5: ${est.r5Lo != null ? est.r5Lo.toFixed(1) : '?'}-${est.r5Hi != null ? est.r5Hi.toFixed(1) : '?'} | Rec: ${est.recCalc != null ? est.recCalc.toFixed(2) : '?'}`);
                tooltipCache[p.id] = {
                    estimated: true,
                    r5Lo: est.r5Lo, r5Hi: est.r5Hi,
                    recCalc: est.recCalc,
                    r5: null, recSort: null, ti: null, skills: null,
                };
            }
        }
    }

    function processPlayer(p) {
        return TmApi.normalizeTransferPlayer(p);
    }

    function decRecToTM(val) {
        return Math.min(10, Math.max(0, Math.floor(parseFloat(val) * 2)));
    }

    // ═══════════════════════════════════════════════════════════════════
    //  TABLE RENDER
    // ═══════════════════════════════════════════════════════════════════

    function thSortClass(key) {
        if (sortKey !== key) return '';
        return sortDir === 1 ? ' sort-asc' : ' sort-desc';
    }

    const buildPlayerRow = (p) => TmTransferTable.buildPlayerRow(p, tooltipCache);
    const buildExpandRow = (p, colCount) => TmTransferTable.buildExpandRow(p, tooltipCache, colCount, skillsMode);

    // ═══════════════════════════════════════════════════════════════════
    //  FILTER + SORT + REFRESH
    // ═══════════════════════════════════════════════════════════════════

    function getPostFilters() {
        const r5min = $('#tms-r5min').val(); const r5max = $('#tms-r5max').val();
        const timin = $('#tms-timin').val(); const timax = $('#tms-timax').val();
        return {
            r5min: r5min !== '' ? parseFloat(r5min) : null,
            r5max: r5max !== '' ? parseFloat(r5max) : null,
            timin: timin !== '' ? parseFloat(timin) : null,
            timax: timax !== '' ? parseFloat(timax) : null,
        };
    }

    function passesPostFilters(p, pf) {
        const tip = tooltipCache[p.id];
        if (!tip) return true; // no tooltip yet — show until we know
        if (tip.r5 != null) {
            if (pf.r5min !== null && tip.r5 < pf.r5min) return false;
            if (pf.r5max !== null && tip.r5 > pf.r5max) return false;
        } else {
            if (pf.r5min !== null && tip.r5Hi != null && tip.r5Hi < pf.r5min) return false;
            if (pf.r5max !== null && tip.r5Lo != null && tip.r5Lo > pf.r5max) return false;
        }
        if (pf.timin !== null && tip.ti != null && tip.ti < pf.timin) return false;
        if (pf.timax !== null && tip.ti != null && tip.ti > pf.timax) return false;
        return true;
    }

    function getVisible() {
        const pf = getPostFilters();
        let arr = allPlayers.filter(p => passesPostFilters(p, pf));
        arr.sort((a, b) => {
            // Bump players always float to the top
            if (a.bump && !b.bump) return -1;
            if (!a.bump && b.bump) return 1;
            let av, bv;
            switch (sortKey) {
                case 'name': av = (a.name || '').toLowerCase(); bv = (b.name || '').toLowerCase(); break;
                case 'age': av = a.age || 0; bv = b.age || 0; break;
                case 'rec': {
                    const ta = tooltipCache[a.id]; const tb = tooltipCache[b.id];
                    av = ta && ta.recCalc != null ? ta.recCalc : (ta && ta.recSort != null ? ta.recSort : (a.rec || 0));
                    bv = tb && tb.recCalc != null ? tb.recCalc : (tb && tb.recSort != null ? tb.recSort : (b.rec || 0));
                    break;
                }
                case 'r5': {
                    const ta = tooltipCache[a.id]; const tb = tooltipCache[b.id];
                    av = ta ? (ta.r5 != null ? ta.r5 : (ta.r5Hi != null ? ta.r5Hi : -9999)) : -9999;
                    bv = tb ? (tb.r5 != null ? tb.r5 : (tb.r5Hi != null ? tb.r5Hi : -9999)) : -9999;
                    break;
                }
                case 'ti': {
                    const ta = tooltipCache[a.id]; const tb = tooltipCache[b.id];
                    av = ta && ta.ti != null ? ta.ti : -9999;
                    bv = tb && tb.ti != null ? tb.ti : -9999;
                    break;
                }
                case 'asi': av = a.asi || 0; bv = b.asi || 0; break;
                case 'bid': av = a.bid || 0; bv = b.bid || 0; break;
                default:
                case 'time': av = a.time || 0; bv = b.time || 0; break;
            }
            if (typeof av === 'string') return sortDir * av.localeCompare(bv);
            return sortDir * (av - bv);
        });

        return arr;
    }

    function startCountdowns(arr) {
        arr.forEach(p => {
            if (!p.time || p.time <= 0) return;
            const $span = $(`#tms-td-${p.id}`);
            if (!$span.length) return;

            // Reuse existing countdown if alive
            if (window.countDowns && window.countDowns[p.id]) {
                try { $span.html(window.countDowns[p.id].getJQ()); return; } catch (e) { }
            }

            if (!window.Countdown) { $span.text(p.time + 's'); return; }

            const cd = new window.Countdown(p.time, '', 'highest', true, (cntdwn) => {
                if (!cntdwn || !cntdwn.getJQ) return;
                const $row = cntdwn.getJQ().closest('tr');
                if (!$row.length) return;
                if ($row.hasClass('watched-player-currentbid')) {
                    $row.find('.tms-time-cell').text('Won').removeClass('tms-time-cell');
                } else if ($row.hasClass('watched-player-outbid')) {
                    $row.find('.tms-time-cell').text('Lost').removeClass('tms-time-cell');
                } else {
                    $row.find('td').css({ color: '#ff3636' });
                    $row.find('.tms-bid-btn').remove();
                    cntdwn.getJQ().closest('td').html('—');
                    setTimeout(() => $row.fadeOut(800, () => $row.remove()), 3000);
                }
            });

            if (window.countDowns) window.countDowns[p.id] = cd;
            try { $span.html(cd.getJQ()); } catch (e) { $span.text(p.time + 's'); }
        });
    }

    function removePlayerTip() {
        TmPlayerTooltip.hide();
    }

    function refreshDisplay() {
        const $wrap = $('#tms-table-wrap');
        if (!$wrap.length) return;

        const arr = getVisible();
        $('#tms-hits').text(arr.length);

        if (!arr.length) {
            $wrap.html('<div id="tms-loading">No players found. Try adjusting your filters.</div>');
            return;
        }

        let html;
        if (skillsMode) {
            const thSkills = ALL_SKILLS.map(s => `<th>${SKILL_NAMES[s]}</th>`).join('');
            html = `<div class="tms-table-wrap"><table id="tms-table">
<thead><tr>
  <th class="tms-col-posbar"></th>
  <th class="tms-col-flag"></th>
  <th data-sort="name" class="${thSortClass('name')}">Name</th>
  <th data-sort="age"  class="${thSortClass('age')}">Age</th>
  <th>Pos</th>
  ${thSkills}
  <th data-sort="time" class="${thSortClass('time')}">Time</th>
  <th></th>
</tr></thead>
</table></div>`;
            $wrap.html(html);
            startCountdowns(arr);
        } else {
            const thCols = BREAKDOWN_COLS.map(c => {
                if (!c.sort) return `<th class="${c.cls || ''}">${c.label}</th>`;
                return `<th data-sort="${c.key}" class="${c.cls || ''} ${thSortClass(c.key)}">${c.label}</th>`;
            }).join('');
            html = `<div class="tms-table-wrap"><table id="tms-table">
<thead><tr>${thCols}</tr></thead>
<tbody>${arr.map(p => buildPlayerRow(p)).join('')}</tbody>
</table></div>`;
            $wrap.html(html);
            startCountdowns(arr);
        }

        // Sort headers
        $('#tms-table th[data-sort]').on('click', function () {
            const k = $(this).data('sort');
            const defaultDir = k === 'time' ? 1 : (k === 'name' ? 1 : -1);
            ({ key: sortKey, dir: sortDir } = window.TmUtils.toggleSort(k, sortKey, sortDir, defaultDir));
            refreshDisplay();
        });

        // Row hover tooltip
        removePlayerTip();
        $('#tms-table tbody')
            .on('mouseenter', '.tms-player-row', function () {
                const pid = $(this).data('pid');
                const player = allPlayers.find(x => x.id == pid);
                if (!player) return;
                const nameCell = this.querySelector('.tms-col-name') || this;
                const $row = $(this);
                TmPlayerTooltip.show(nameCell, TmTransferTable.adaptForTooltip(player, tooltipCache));
                // Fetch tooltip on hover if not yet loaded
                const cachedTip = tooltipCache[pid];
                if (!cachedTip || cachedTip.estimated) {
                    fetchOnePlayer(player).then(() => {
                        if ($row.is(':hover'))
                            TmPlayerTooltip.show(nameCell, TmTransferTable.adaptForTooltip(player, tooltipCache));
                    });
                }
            })
            .on('mouseleave', '.tms-player-row', removePlayerTip);

        // Compatibility hooks
        if (typeof window.make_highlighted_rows === 'function') {
            try { window.make_highlighted_rows(); } catch (e) { }
        }
    }

    // ═══════════════════════════════════════════════════════════════════
    //  TOOLTIP BACKGROUND FETCHER
    // ═══════════════════════════════════════════════════════════════════

    function updateTooltipCells(pid, tip) {
        const recVal = tip.recCalc != null ? tip.recCalc : tip.recSort;

        // Post-filters: remove rows that no longer pass after tooltip data arrives
        const pf = getPostFilters();
        const failsRec = (() => {
            if (recVal == null) return false;
            const decMin = parseFloat($('#tms-rmin').val()) || 0;
            const decMax = parseFloat($('#tms-rmax').val());
            const maxVal = isNaN(decMax) ? 5 : decMax;
            return (decMin > 0 || maxVal < 5) && (recVal < decMin || recVal > maxVal);
        })();
        const failsR5 = tip.r5 != null
            ? ((pf.r5min !== null && tip.r5 < pf.r5min) || (pf.r5max !== null && tip.r5 > pf.r5max))
            : ((pf.r5min !== null && tip.r5Hi != null && tip.r5Hi < pf.r5min) ||
                (pf.r5max !== null && tip.r5Lo != null && tip.r5Lo > pf.r5max));
        const failsTI = (pf.timin !== null && tip.ti != null && tip.ti < pf.timin) ||
            (pf.timax !== null && tip.ti != null && tip.ti > pf.timax);
        if (failsRec || failsR5 || failsTI) {
            const $row = $(`#player_row_${pid}`);
            $row.next('.tms-expand-row').remove();
            $row.remove();
            allPlayers = allPlayers.filter(p => String(p.id) !== String(pid));
            const parts = ($('#tms-hits').text() || '').split('/');
            const shown = parseInt(parts[0]) || 0;
            const total = parseInt(parts[1]) || 0;
            $('#tms-hits').text((shown > 0 ? shown - 1 : 0) + ' / ' + (total > 0 ? total - 1 : 0));
            return;
        }

        // Remove reload button now that we have full data
        $(`#player_row_${pid} .tms-reload-btn`).remove();

        const $rec = $(`#tms-rec-${pid}`);
        if ($rec.length && recVal != null) $rec.html(fmtRec(recVal));

        const $r5 = $(`#tms-r5-${pid}`);
        if ($r5.length) {
            if (tip.r5 != null) $r5.html(fmtR5(tip.r5));
            else if (tip.r5Lo != null || tip.r5Hi != null) $r5.html(fmtR5Range(tip.r5Lo, tip.r5Hi));
        }

        const $ti = $(`#tms-ti-${pid}`);
        if ($ti.length) $ti.html(tiHtml(tip.ti));

        // Refresh open expand row for this player (legacy — no-op when no expand rows)
        const $expRow = $(`#player_row_${pid}`).next('.tms-expand-row');
        if ($expRow.length) {
            const player = allPlayers.find(x => x.id == pid);
            if (player) {
                const colCount = skillsMode ? (5 + ALL_SKILLS.length + 2) : BREAKDOWN_COLS.length;
                $expRow.replaceWith(buildExpandRow(player, colCount));
            }
        }

        // Refresh hover tooltip if it's showing this player
        const $hovRow = $(`#player_row_${pid}`);
        if ($hovRow.length && $hovRow.is(':hover')) {
            const player = allPlayers.find(x => x.id == pid);
            if (player) {
                const anchor = $hovRow[0].querySelector('.tms-col-name') || $hovRow[0];
                TmPlayerTooltip.show(anchor, TmTransferTable.adaptForTooltip(player, tooltipCache));
            }
        }
    }

    async function fetchOnePlayer(p) {
        const data = await TmApi.fetchPlayerTooltip(p.id);
        const tip = TmApi.enrichTransferFromTooltip(p, data, CURRENT_SESSION);
        if (!tip) return;
        tooltipCache[p.id] = tip;
        updateTooltipCells(p.id, tip);
    }

    async function startTooltipFetch(players) {
        tooltipFetchAbort = false;
        const uncached = players.filter(p => !tooltipCache[p.id] || tooltipCache[p.id].estimated);
        // Fire all in parallel — browser caps at ~6 concurrent naturally
        await Promise.all(uncached.map(async p => {
            if (!tooltipFetchAbort) await fetchOnePlayer(p);
        }));
    }

    // ═══════════════════════════════════════════════════════════════════
    //  SEARCH
    // ═══════════════════════════════════════════════════════════════════

    function buildHash() {
        let h = '/';
        const activeFps = $('[data-fp].active').map(function () { return $(this).data('fp'); }).get();
        if (activeFps.length) {
            const groups = new Set(), sides = new Set();
            for (const fp of activeFps) {
                const m = FP_MAP[fp]; if (!m) continue;
                groups.add(m.group);
                if (m.side) sides.add(m.side);
            }
            for (const g of groups) h += g + '/';
            for (const s of sides) h += s + '/';
        }
        if ($('#tms-for').is(':checked')) h += 'for/';

        const amin = $('#tms-amin').val(), amax = $('#tms-amax').val();
        if (amin !== '18') h += `amin/${amin}/`;
        if (amax !== '37') h += `amax/${amax}/`;

        const recMin = parseFloat($('#tms-rmin').val()) || 0;
        const recMax = parseFloat($('#tms-rmax').val());
        const tmRmin = decRecToTM(recMin);
        const tmRmax = decRecToTM(isNaN(recMax) ? 5 : recMax);
        if (tmRmin > 0) h += `rmin/${tmRmin}/`;
        if (tmRmax < 10) h += `rmax/${tmRmax}/`;

        const cost = $('#tms-cost').val();
        if (cost && cost !== '0') h += `cost/${cost}/`;

        const time = $('#tms-time').val();
        if (time && time !== '0') h += `time/${time}/`;

        for (let i = 0; i < 3; i++) {
            const sk = $(`#tms-sf-s${i}`).val();
            const sv = $(`#tms-sf-v${i}`).val();
            if (sk && sk !== '0' && sv && sv !== '0') h += `${sk}/${sv}/`;
        }
        return h;
    }

    function doSearch() {
        if (isLoading) return;
        isLoading = true;
        tooltipFetchAbort = true; // cancel in-flight tooltip fetches
        findAllAbort = true;      // cancel in-flight findAll scan
        tooltipCache = {}; // fresh cache for new search results
        $('#tms-table-wrap').html('<div id="tms-loading"><span class="tms-spinner"></span> Searching transfer market…</div>');

        // Clear old countdowns
        if (window.countDowns) {
            for (const id in window.countDowns) { window.countDowns[id] = null; }
            window.countDowns = {};
        }

        const hash = buildHash();
        const clubId = window.SESSION ? window.SESSION.id : 0;

        TmApi.fetchTransferSearch(hash, clubId).then(function (data) {
            isLoading = false;

            if (!data) {
                $('#tms-table-wrap').html('<div id="tms-loading" style="color:#ff7373">No data received. Please try again.</div>');
                return;
            }
            if (data.refresh) { location.reload(); return; }

            const raw = Array.isArray(data.list) ? data.list : [];
            window.transfer_info_ar = raw;
            allPlayers = raw.map(processPlayer);
            computeAllEstimates(allPlayers);
            refreshDisplay();
            // Start background tooltip enrichment
            tooltipFetchAbort = true; // abort any previous fetch
            setTimeout(() => startTooltipFetch(allPlayers), 300);
        }).catch(function (error) {
            console.warn('[TMS] Search failed', error);
            isLoading = false;
            $('#tms-table-wrap').html('<div id="tms-loading" style="color:#ff7373">Network error. Please try again.</div>');
        });
    }

    // ═══════════════════════════════════════════════════════════════════
    //  SAVED FILTERS
    // ═══════════════════════════════════════════════════════════════════

    function readCurrentFilterState() {
        const positions = $('[data-fp].active').map(function () { return $(this).data('fp'); }).get();
        const skills = [];
        for (let i = 0; i < 3; i++) {
            skills.push([$(`#tms-sf-s${i}`).val() || '0', $(`#tms-sf-v${i}`).val() || '0']);
        }
        return {
            positions,
            foreigners: $('#tms-for').is(':checked'),
            amin: $('#tms-amin').val(),
            amax: $('#tms-amax').val(),
            rmin: $('#tms-rmin').val(),
            rmax: $('#tms-rmax').val(),
            cost: $('#tms-cost').val(),
            time: $('#tms-time').val(),
            skills,
            r5min: $('#tms-r5min').val(),
            r5max: $('#tms-r5max').val(),
            timin: $('#tms-timin').val(),
            timax: $('#tms-timax').val(),
        };
    }

    function applyFilterState(state) {
        if (!state) return;
        $('[data-fp]').removeClass('active');
        (state.positions || []).forEach(fp => $(`[data-fp="${fp}"]`).addClass('active'));
        $('#tms-for').prop('checked', !!state.foreigners);
        $('#tms-amin').val(state.amin != null ? state.amin : '18');
        $('#tms-amax').val(state.amax != null ? state.amax : '37');
        $('#tms-rmin').val(state.rmin != null ? state.rmin : '0');
        $('#tms-rmax').val(state.rmax != null ? state.rmax : '5');
        $('#tms-cost').val(state.cost || '0');
        $('#tms-time').val(state.time || '0');
        const skills = state.skills || [];
        for (let i = 0; i < 3; i++) {
            const [sk, sv] = skills[i] || ['0', '0'];
            $(`#tms-sf-s${i}`).val(sk);
            $(`#tms-sf-v${i}`).val(sv);
        }
        $('#tms-r5min').val(state.r5min || '');
        $('#tms-r5max').val(state.r5max || '');
        $('#tms-timin').val(state.timin || '');
        $('#tms-timax').val(state.timax || '');
        // Open "More Filters" if any of those fields are active
        const hasMore = (state.cost && state.cost !== '0') ||
            (state.time && state.time !== '0') ||
            (skills.some(([sk]) => sk && sk !== '0'));
        if (hasMore) {
            $('#tms-more-toggle').addClass('open');
            $('#tms-more-body').addClass('open');
        }
    }

    function getSavedFilters() {
        try {
            return JSON.parse(localStorage.getItem(SAVED_FILTERS_KEY) || '{}');
        } catch (e) { return {}; }
    }

    function saveNamedFilter(name, state) {
        const filters = getSavedFilters();
        filters[name] = state;
        localStorage.setItem(SAVED_FILTERS_KEY, JSON.stringify(filters));
    }

    function deleteNamedFilter(name) {
        const filters = getSavedFilters();
        delete filters[name];
        localStorage.setItem(SAVED_FILTERS_KEY, JSON.stringify(filters));
    }

    function populateSavedFiltersDropdown() {
        const filters = getSavedFilters();
        const names = Object.keys(filters);
        const $sel = $('#tms-saved-filters-sel');
        if (!$sel.length) return;
        const current = $sel.val();
        $sel.empty();
        if (names.length === 0) {
            $sel.append('<option value="">— no saved filters —</option>');
        } else {
            $sel.append('<option value="">— select filter —</option>');
            for (const name of names) {
                $sel.append(`<option value="${name}"${name === current ? ' selected' : ''}>${name}</option>`);
            }
        }
    }

    // ═══════════════════════════════════════════════════════════════════
    //  FIND ALL PLAYERS (exhaustive cartesian scan: pos × age × rec)
    // ═══════════════════════════════════════════════════════════════════

    function readBaseFilters() {
        return {
            foreigners: $('#tms-for').is(':checked'),
            amin: $('#tms-amin').val() || '18',
            amax: $('#tms-amax').val() || '37',
            rmin: $('#tms-rmin').val() || '0',
            rmax: $('#tms-rmax').val() || '5',
            cost: $('#tms-cost').val() || '0',
            time: $('#tms-time').val() || '0',
            skills: [0, 1, 2].map(i => [$(`#tms-sf-s${i}`).val() || '0', $(`#tms-sf-v${i}`).val() || '0']),
        };
    }

    function buildHashRaw({ positions = [], sides = [], foreigners, amin, amax, rmin, rmax, cost, time, skills = [] }) {
        let h = '/';
        for (const p of positions) h += p + '/';
        for (const s of sides) h += s + '/';
        if (foreigners) h += 'for/';
        if (amin && amin !== '18') h += `amin/${amin}/`;
        if (amax && amax !== '37') h += `amax/${amax}/`;
        if (rmin && rmin !== '0') h += `rmin/${rmin}/`;
        if (rmax && rmax !== '10') h += `rmax/${rmax}/`;
        if (cost && cost !== '0') h += `cost/${cost}/`;
        if (time && time !== '0') h += `time/${time}/`;
        for (const [sk, sv] of skills) {
            if (sk && sk !== '0' && sv && sv !== '0') h += `${sk}/${sv}/`;
        }
        return h;
    }

    function fetchWithHash(hash) {
        const clubId = window.SESSION ? window.SESSION.id : 0;
        return TmApi.fetchTransferSearch(hash, clubId)
            .then(data => Array.isArray(data?.list) ? data.list : []);
    }

    const showModal = (opts) => window.TmUI.modal(opts);

    const promptModal = (opts) => window.TmUI.prompt(opts);

    async function findAllPlayers() {
        if (isLoading || findAllRunning) return;

        // Warn if age range > 3 years and no position/rec filter is set
        const _amin = Math.max(18, parseInt($('#tms-amin').val()) || 18);
        const _amax = Math.min(37, parseInt($('#tms-amax').val()) || 37);
        const _hasPos = $('[data-fp].active').length > 0;
        const _rmin = parseFloat($('#tms-rmin').val()) || 0;
        const _rmax = parseFloat($('#tms-rmax').val());
        const _hasRec = _rmin > 0 || (!isNaN(_rmax) && _rmax < 5);
        if ((_amax - _amin) > 3 && !_hasPos && !_hasRec) {
            const choice = await showModal({
                icon: '⚠️',
                title: 'This scan may take a long time',
                message: 'A wide age range is selected and no <strong style="color:#c8e0b4">position</strong> or ' +
                    '<strong style="color:#c8e0b4">recommendation</strong> filter is active.<br><br>' +
                    'Consider adding one to speed things up significantly.',
                buttons: [
                    { label: 'Proceed Anyway', value: 'ok', style: 'secondary' },
                    { label: 'Cancel', value: 'cancel', style: 'danger' },
                ],
            });
            if (choice !== 'ok') return;
        }

        findAllRunning = true;
        findAllAbort = false;
        tooltipFetchAbort = true;
        tooltipCache = {};

        if (window.countDowns) {
            for (const id in window.countDowns) window.countDowns[id] = null;
            window.countDowns = {};
        }

        const base = readBaseFilters();
        const rminNum = Math.max(0, decRecToTM(base.rmin));
        const rmaxNum = Math.min(10, decRecToTM(parseFloat(base.rmax) || 5));
        const aminNum = Math.max(18, parseInt(base.amin) || 18);
        const amaxNum = Math.min(37, parseInt(base.amax) || 37);

        // ── 1. Position combos: respect user's sidebar selection ──────────
        const activeFps = $('[data-fp].active').map(function () { return $(this).data('fp'); }).get();
        const fpKeys = activeFps.length ? activeFps : Object.keys(FP_MAP);
        const posCombos = fpKeys.map(fp => {
            const m = FP_MAP[fp];
            return { positions: [m.group], sides: m.side ? [m.side] : [] };
        });

        // ── 2. Age: one step per year ─────────────────────────────────────
        const ages = [];
        for (let a = aminNum; a <= amaxNum; a++) ages.push(a);

        // ── 3. Rec: one step per unit ─────────────────────────────────────
        const recRanges = [];
        for (let r = rminNum; r < rmaxNum; r++) recRanges.push([r, r + 1]);
        if (recRanges.length === 0) recRanges.push([rminNum, rmaxNum]);

        // ── 4. Full cartesian product ─────────────────────────────────────
        const tasks = [];
        for (const pos of posCombos) {
            for (const age of ages) {
                for (const [lo, hi] of recRanges) {
                    tasks.push({ pos, age, recLo: lo, recHi: hi });
                }
            }
        }

        const collected = new Map();
        const total = tasks.length;
        let done = 0;

        const updateProgress = () => {
            const pct = total > 0 ? Math.round((done / total) * 100) : 0;
            $('#tms-table-wrap').html(
                `<div id="tms-loading"><span class="tms-spinner"></span>` +
                `Scanning… <strong style="color:#c8e0b4">${done}/${total}</strong> (${pct}%) &mdash; ` +
                `<span style="color:#80e048">${collected.size}</span> players found&hellip;</div>`
            );
        };
        updateProgress();

        // Fire all tasks in parallel; browser naturally caps at ~6 concurrent
        await Promise.all(tasks.map(async (task) => {
            if (findAllAbort) return;
            const hash = buildHashRaw({
                ...base,
                positions: task.pos.positions,
                sides: task.pos.sides,
                amin: String(task.age),
                amax: String(task.age),
                rmin: String(task.recLo),
                rmax: String(task.recHi),
            });
            const result = await fetchWithHash(hash);
            if (!findAllAbort) {
                for (const p of result) collected.set(p.id, p);
            }
            done++;
            updateProgress();
        }));

        findAllRunning = false;
        if (findAllAbort) return;

        const foundCount = collected.size;
        let fetchTooltips = true;
        if (foundCount > 600) {
            const choice = await showModal({
                icon: '📊',
                title: `${foundCount} players found`,
                message: 'Fetching full stats (R5, Rec, TI) for this many players may take several minutes.' +
                    '<br><br>Or get an <strong style="color:#c8e0b4">instant R5 range estimate</strong> ' +
                    'based on transfer-data skills and assumed routine ' +
                    '<span style="color:#80e048">0 – 4.2 × (age − 15)</span>, with no API calls.',
                buttons: [
                    { label: 'Full Analysis', value: 'full', style: 'primary', sub: 'Fetches R5 · Rec · TI via tooltip API — slower' },
                    { label: 'Quick Estimate', value: 'estimate', style: 'secondary', sub: 'Shows R5 range instantly, no extra API calls' },
                    { label: 'Cancel', value: 'cancel', style: 'danger' },
                ],
            });
            if (choice === 'cancel') return;
            fetchTooltips = (choice === 'full');
        }

        allPlayers = [...collected.values()].map(processPlayer);
        computeAllEstimates(allPlayers);
        refreshDisplay();
        if (fetchTooltips) setTimeout(() => startTooltipFetch(allPlayers), 300);
    }

    // ═══════════════════════════════════════════════════════════════════
    //  LAYOUT
    // ═══════════════════════════════════════════════════════════════════

    function buildLayout() {
        console.log('Building layout');
        if ($('#tms-outer').length) return;
        const $outer = $('<div id="tms-outer"></div>');
        $outer.html(`
<div id="tms-root">
  ${TmTransferSidebar.build()}
  <div id="tms-main">
    <div id="tms-toolbar">
      <span id="tms-hits">0</span>
      <span class="tms-toolbar-label"> players</span>
    </div>
    <div id="tms-table-wrap">
      <div id="tms-loading"><span class="tms-spinner"></span> Loading transfer market…</div>
    </div>
  </div>
</div>
<div id="transfer_list" style="display:none"></div>
        `);
        $('.main_center').last().after($outer);
    }

    // ═══════════════════════════════════════════════════════════════════
    //  EVENT BINDING
    // ═══════════════════════════════════════════════════════════════════

    function bindEvents() {
        $(document).on('click', '#tms-search-btn', doSearch);
        $(document).on('keydown', '#tms-sidebar', function (e) {
            if (e.key === 'Enter') doSearch();
        });

        $(document).on('click', '.tms-reload-btn', function (e) {
            e.stopPropagation();
            const pid = $(this).data('pid');
            const player = allPlayers.find(x => x.id == pid);
            if (!player) return;
            $(this).addClass('tms-reloading');
            fetchOnePlayer(player);
        });

        $(document).on('click', '[data-fp]', function () { $(this).toggleClass('active'); });
        $(document).on('click', '#tms-findall-btn', findAllPlayers);

        $(document).on('click', '#tms-more-toggle', function () {
            $(this).toggleClass('open');
            $('#tms-more-body').toggleClass('open');
        });

        $(document).on('click', '#tms-filter-save-btn', async function () {
            const currentSel = $('#tms-saved-filters-sel').val();
            const name = await promptModal({
                icon: '💾',
                title: 'Save Current Filter',
                placeholder: 'Enter filter name…',
                defaultValue: currentSel || '',
            });
            if (!name) return;
            saveNamedFilter(name, readCurrentFilterState());
            populateSavedFiltersDropdown();
            $('#tms-saved-filters-sel').val(name);
        });

        $(document).on('click', '#tms-filter-load-btn', function () {
            const name = $('#tms-saved-filters-sel').val();
            if (!name) return;
            const state = getSavedFilters()[name];
            if (!state) return;
            applyFilterState(state);
            doSearch();
        });

        $(document).on('click', '#tms-filter-del-btn', async function () {
            const name = $('#tms-saved-filters-sel').val();
            if (!name) return;
            const confirmed = await showModal({
                icon: '🗑️',
                title: 'Delete saved filter',
                message: `Delete "<strong style="color:#c8e0b4">${name}</strong>"?`,
                buttons: [
                    { label: 'Delete', value: 'ok', style: 'danger' },
                    { label: 'Cancel', value: 'cancel', style: 'secondary' },
                ],
            });
            if (confirmed !== 'ok') return;
            deleteNamedFilter(name);
            populateSavedFiltersDropdown();
        });

        $(document).on('input', '#tms-r5min, #tms-r5max, #tms-timin, #tms-timax', function () {
            refreshDisplay();
        });


        $(document).on('click', '#tms-mode-bd', function () {
            skillsMode = false;
            $(this).addClass('active');
            $('#tms-mode-sk').removeClass('active');
            refreshDisplay();
        });

        $(document).on('click', '#tms-mode-sk', function () {
            skillsMode = true;
            $(this).addClass('active');
            $('#tms-mode-bd').removeClass('active');
            refreshDisplay();
        });
    }

    // ═══════════════════════════════════════════════════════════════════
    //  NEUTRALIZE TM'S OWN RENDER PIPELINE
    // ═══════════════════════════════════════════════════════════════════

    function neutralizeTM() {
        console.log('Neutralizing TM rendering');
        // Stop the hash-check interval TM registered on document.ready
        if (window.hashCheck) {
            clearInterval(window.hashCheck);
            window.hashCheck = null;
        }
        // Make TM's rendering functions no-ops so their AJAX callback
        // doesn't overwrite our UI (they still populate transfer_info_ar)
        window.makeTable = function (arr) { if (arr) window.transfer_info_ar = arr; };
        window.sort_it = function () { };
        window.startSearch = function () { };
        window.check_hash = function () { };
        window.popFilterImages = function () { };
    }

    // ═══════════════════════════════════════════════════════════════════
    //  INIT
    // ═══════════════════════════════════════════════════════════════════

    function init() {
        neutralizeTM();
        TmTransferStyles.inject();
        buildLayout();
        bindEvents();
        populateSavedFiltersDropdown();
        // Tiny delay gives TM's own DOM-ready callbacks time to clear,
        // then we kick off our first search
        setTimeout(doSearch, 150);
        console.log('Transfer Market Scanner initialized');
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

})();



// ─── tm-match.user.js ────────────────────────────────────────────

// ==UserScript==
// @name         TM Match Viewer
// @namespace    https://trophymanager.com
// @version      1.4.0
// @description  Enhanced match viewer with live replay, lineups, statistics, venue and H2H tabs
// @match        https://trophymanager.com/matches/*
// @require      file://H:/projects/Moji/tmscripts/lib/tm-constants.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-position.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-utils.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-lib.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-playerdb.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-services.js
// @require      file://H:/projects/Moji/tmscripts/components/shared/tm-ui.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-styles.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-utils.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-dialog.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-venue.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-h2h.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-analysis.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-league.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-statistics.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-lineups.js
// @grant        none
// ==/UserScript==

(function () {
    'use strict';

    // ─── Constants ───────────────────────────────────────────────────────
    const { REC_THRESHOLDS } = window.TmConst;

    // ─── Utility helpers ─────────────────────────────────────────────────
    const parseNum = str => Number(String(str).replace(/,/g, ''));

    const getColor = window.TmUtils.getColor;

    // ─── Player data fetching (with Promise-based cache) ─────────────────
    const tooltipCache = new Map();

    const fetchTooltip = playerId => {
        const pid = String(playerId);
        if (!tooltipCache.has(pid)) {
            tooltipCache.set(pid, window.TmApi.fetchTooltipRaw(playerId).then(data => {
                if (!data) throw new Error('tooltip fetch failed');
                return data;
            }));
        }
        return tooltipCache.get(pid);
    };

    const getPlayerData = (playerId, routineMap, positionMap) => {
        return fetchTooltip(playerId).then(rawData => {
            const player = JSON.parse(JSON.stringify(rawData.player));
            if (routineMap.has(playerId)) player.routine = String(routineMap.get(playerId));
            if (positionMap.has(playerId)) player.favposition = positionMap.get(playerId);
            const DBPlayer = window.TmPlayerDB.get(parseInt(player.player_id));
            window.TmApi.normalizePlayer(player, DBPlayer, { skipSync: true });
            return { Age: player.ageMonths, REC: player.rec, R5: player.r5 };
        });
    };

    const injectStyles = () => window.TmMatchStyles.inject();

    // ─── Match cache & rating cells ─────────────────────────────────────
    const roundMatchCache = new Map(); // matchId -> {homeR5, awayR5, data}

    // ─── Match dialog ────────────────────────────────────────────────────
    // ── Live replay state (shared across tabs) ──
    let liveState = null;
    let prematchTimer = null;
    // liveState = { min, sec, curEvtIdx, curLineIdx, playing, timer, mData, speed:1000,
    //               maxMin, ended, schedule, eventMinList, eventMinIdx }

    // ── Unity 3D integration state ──
    let unityState = {
        available: false,       // gameInstance exists on page
        ready: false,           // lineup loaded, ready to play clips
        playing: false,         // currently playing a clip sequence
        pendingMinute: null,    // minute waiting for finished_loading
        loadedMinutes: [],      // minutes that finished loading
        playedMinutes: [],      // minutes that finished playing
        canvasParent: null,     // original parent of the Unity canvas
        tmPaused: false,        // whether we've paused TM's replay
        clipTextQueue: [],      // flat list of {evtIdx, lineIdx} for current minute (first event only)
        clipTextCursor: 0,      // how many text lines we've shown
        clipTextGroups: [],     // group boundaries [{start, count}]
        clipGroupCursor: 0,     // how many groups we've shown
        clipPostQueue: [],      // remaining events' text, shown after animation
        activeMinute: null,     // the minute currently being clip-played
        clipFirstShown: false,  // whether first text group was shown on starting_clip
        clipSkippedFirst: false, // whether we skipped the first finished_clip
    };

    // ── Unity integration helpers ──
    const getUW = () => {
        return typeof unsafeWindow !== 'undefined' ? unsafeWindow : window;
    };

    const initUnity = () => {
        const uw = getUW();
        const poll = setInterval(() => {
            if (uw.gameInstance || uw.gameInstanceLoaded) {
                clearInterval(poll);
                unityState.available = true;
                unityState.ready = true;  // flash_ready already fired before our override
                console.log('[RND] Unity gameInstance detected, assuming ready');
                stopTMReplay();
                setupStargateOverride();
                // If Lineups tab already rendered, move canvas immediately
                const vp = document.getElementById('rnd-unity-viewport');
                if (vp) {
                    moveUnityCanvas();
                    vp.style.display = 'block';
                }
                // Auto-play live match if paused (e.g. page refresh)
                if (liveState && !liveState.playing && !liveState.ended) {
                    console.log('[RND] Auto-playing live match after Unity detected');
                    livePlay();
                }
            }
        }, 500);
        setTimeout(() => clearInterval(poll), 30000);
    };

    const stopTMReplay = () => {
        const uw = getUW();
        if (unityState.tmPaused) return;
        unityState.tmPaused = true;
        // Pause TM's replay system completely
        if (uw.flash_status) {
            uw.flash_status.playback_mode = 'pause';
            uw.flash_status.enabled = false;  // prevent TM from sending clips
        }
        // Kill TM's run_match loop
        uw._orig_run_match = uw.run_match;
        uw.run_match = function () { /* noop */ };
        // Also kill TM's text display functions so they don't interfere
        if (uw.show_next_action_text_entry) {
            uw._orig_show_next_action_text_entry = uw.show_next_action_text_entry;
            uw.show_next_action_text_entry = function () { /* noop */ };
        }
        if (uw.prepare_next_minute) {
            uw._orig_prepare_next_minute = uw.prepare_next_minute;
            uw.prepare_next_minute = function () { /* noop */ };
        }
        // Clear any pending setTimeout from TM's run_match chain
        // (clear a range of recent timer IDs to catch the pending one)
        const lastId = setTimeout(() => { }, 0);
        for (let i = lastId - 20; i <= lastId; i++) {
            clearTimeout(i);
        }
        console.log('[RND] TM replay stopped completely');
    };

    // Build flat text-line queue for a minute
    // Only the FIRST event is synced to the animation (distributed by groups over clip duration)
    // Remaining events are queued as postQueue, shown after animation finishes
    const buildClipTextQueue = (mData, minute) => {
        const report = mData.report || {};
        const evts = report[String(minute)] || [];
        const queue = [];
        const groups = []; // each entry = { start, count } into queue
        const postQueue = []; // remaining events' text lines
        evts.forEach((evt, evtIdx) => {
            if (!evt.chance || !evt.chance.text) return;
            let flatIdx = 0;
            if (evtIdx === 0) {
                // First event: animation-synced text
                evt.chance.text.forEach(textArr => {
                    const groupStart = queue.length;
                    let groupCount = 0;
                    textArr.forEach(line => {
                        if (!line || !line.trim()) return;
                        queue.push({ evtIdx, lineIdx: flatIdx });
                        flatIdx++;
                        groupCount++;
                    });
                    if (groupCount > 0) groups.push({ start: groupStart, count: groupCount });
                });
            } else {
                // Remaining events: post-animation text
                evt.chance.text.forEach(textArr => {
                    textArr.forEach(line => {
                        if (!line || !line.trim()) return;
                        postQueue.push({ evtIdx, lineIdx: flatIdx });
                        flatIdx++;
                    });
                });
            }
        });
        return { queue, groups, postQueue };
    };

    // Show ONE text line from the clip queue
    const advanceClipTextOneLine = () => {
        if (!liveState || !unityState.clipTextQueue.length) return;
        const idx = unityState.clipTextCursor;
        if (idx >= unityState.clipTextQueue.length) return;
        const entry = unityState.clipTextQueue[idx];
        unityState.clipTextCursor = idx + 1;

        liveState.curEvtIdx = entry.evtIdx;
        liveState.curLineIdx = entry.lineIdx;

        // Check if this event is complete
        const report = liveState.mData.report || {};
        const evts = report[String(liveState.min)] || [];
        const evt = evts[entry.evtIdx];
        const total = evt ? countEventLines(evt) : 1;
        const isComplete = entry.lineIdx >= total - 1;
        liveState.curEvtComplete = isComplete;
        liveState.justCompleted = isComplete;

        updateLiveHeader();
        refreshActiveTab();
        // Also update the unity side panels
        updateUnityFeed();
        // Only update stats when event is fully complete
        if (isComplete) updateUnityStats();
    };

    // ── Update the left-side feed panel next to viewport (current minute only) ──
    const updateUnityFeed = () => {
        const container = $('#rnd-unity-feed');
        if (!container.length || !liveState) return;
        const mData = liveState.mData;
        const report = mData.report || {};
        const playerNames = buildPlayerNames(mData);
        const curMin = liveState.min;
        const curEvtIdx = liveState.curEvtIdx;
        const curLineIdx = liveState.curLineIdx;
        const allLines = [];
        // Only show events for the CURRENT minute
        const evts = report[String(curMin)] || [];
        for (let ei = 0; ei < evts.length; ei++) {
            if (!isEventVisible(curMin, ei, curMin, curEvtIdx)) continue;
            const evt = evts[ei];
            if (!evt || !evt.chance || !evt.chance.text) continue;
            let flatIdx = 0;
            evt.chance.text.forEach(textArr => {
                textArr.forEach(line => {
                    if (!line || !line.trim()) return;
                    if (ei === curEvtIdx && flatIdx > curLineIdx) { flatIdx++; return; }
                    allLines.push({ min: curMin, text: line });
                    flatIdx++;
                });
            });
        }
        let html = '';
        allLines.forEach(item => {
            let resolved = resolvePlayerTags(item.text, playerNames);
            resolved = resolved.replace(/\[(goal|yellow|red|sub|assist)\]/g, '');
            html += `<div class="rnd-unity-feed-line"><span class="rnd-unity-feed-min">${item.min}'</span><span class="rnd-unity-feed-text">${resolved}</span></div>`;
        });
        container.html(html);
        // Auto-scroll to bottom
        container.scrollTop(container[0].scrollHeight);
    };

    // ── Update the right-side mini stats panel next to viewport ──
    const updateUnityStats = () => {
        const container = $('#rnd-unity-stats');
        if (!container.length || !liveState) return;
        const mData = liveState.mData;
        const homeId = String(mData.club.home.id);
        const homeIds = new Set(Object.keys(mData.lineup.home));
        const report = mData.report || {};
        const curMin = liveState.min;
        const curEvtIdx = liveState.curEvtIdx;
        let hShots = 0, aShots = 0, hSoT = 0, aSoT = 0, hGoals = 0, aGoals = 0;
        let hYellow = 0, aYellow = 0, hRed = 0, aRed = 0, hSetPieces = 0, aSetPieces = 0;
        const sortedMins = Object.keys(report).map(Number).sort((a, b) => a - b);
        for (const min of sortedMins) {
            const evts = report[String(min)] || [];
            for (let ei = 0; ei < evts.length; ei++) {
                if (!isEventVisible(min, ei, curMin, curEvtIdx)) continue;
                const evt = evts[ei];
                if (!evt || !evt.parameters) continue;
                evt.parameters.forEach(p => {
                    if (p.shot) {
                        const isHome = String(p.shot.team) === homeId;
                        if (isHome) { hShots++; if (p.shot.target === 'on') hSoT++; }
                        else { aShots++; if (p.shot.target === 'on') aSoT++; }
                    }
                    if (p.goal) {
                        const scorerId = String(p.goal.player);
                        const isHome = homeIds.has(scorerId);
                        if (isHome) hGoals++; else aGoals++;
                    }
                    if (p.yellow) {
                        if (homeIds.has(String(p.yellow))) hYellow++; else aYellow++;
                    }
                    if (p.yellow_red) {
                        if (homeIds.has(String(p.yellow_red))) hRed++; else aRed++;
                    }
                    if (p.red) {
                        if (homeIds.has(String(p.red))) hRed++; else aRed++;
                    }
                    if (p.set_piece) {
                        if (homeIds.has(String(p.set_piece))) hSetPieces++; else aSetPieces++;
                    }
                });
            }
        }
        const miniBar = (label, hv, av) => {
            const total = hv + av;
            const hp = total === 0 ? 50 : Math.round(hv / total * 100);
            const ap = 100 - hp;
            const hLead = hv > av ? ' lead' : '';
            const aLead = av > hv ? ' lead' : '';
            return `<div class="rnd-unity-stat-row">
                <div class="rnd-unity-stat-hdr"><span class="val home${hLead}">${hv}</span><span class="rnd-unity-stat-label">${label}</span><span class="val away${aLead}">${av}</span></div>
                <div class="rnd-unity-stat-bar"><div class="seg home" style="width:${hp}%"></div><div class="seg away" style="width:${ap}%"></div></div>
            </div>`;
        };
        let h = '';
        h += miniBar('Shots', hShots, aShots);
        h += miniBar('On Target', hSoT, aSoT);
        h += miniBar('Goals', hGoals, aGoals);
        h += miniBar('Yellow', hYellow, aYellow);
        h += miniBar('Red', hRed, aRed);
        h += miniBar('Set Pieces', hSetPieces, aSetPieces);
        container.html(h);
    };

    // Flush all remaining text lines at once (for finished_playing)
    const flushClipText = () => {
        if (!liveState) return;
        // Flush remaining animation text (first event)
        while (unityState.clipTextCursor < unityState.clipTextQueue.length) {
            advanceClipTextOneLine();
        }
        // Append and flush post-animation text (remaining events)
        if (unityState.clipPostQueue && unityState.clipPostQueue.length > 0) {
            unityState.clipPostQueue.forEach(entry => {
                unityState.clipTextQueue.push(entry);
            });
            unityState.clipPostQueue = [];
            while (unityState.clipTextCursor < unityState.clipTextQueue.length) {
                advanceClipTextOneLine();
            }
        }
    };

    // Advance the next text group (called on each finished_clip from Unity)
    const advanceClipTextGroup = () => {
        const groups = unityState.clipTextGroups || [];
        const gi = unityState.clipGroupCursor || 0;
        if (gi >= groups.length) return;
        const group = groups[gi];
        // Show all lines in this group at once
        for (let j = 0; j < group.count; j++) {
            if (unityState.clipTextCursor < unityState.clipTextQueue.length) {
                advanceClipTextOneLine();
            }
        }
        unityState.clipGroupCursor = gi + 1;
        console.log('[RND] Advanced text group ' + gi + ' (' + group.count + ' lines)');
    };

    const setupStargateOverride = () => {
        const uw = getUW();
        uw._orig_stargate = uw.stargate;
        uw.stargate = function (vars) {
            console.log('[RND] stargate:', JSON.stringify(vars));

            if (vars.flash_ready) {
                unityState.ready = true;
                console.log('[RND] Unity ready');
            }

            if (vars.finished_loading) {
                const min = vars.finished_loading.id;
                unityState.loadedMinutes.push(min);
                console.log('[RND] Clips loaded for minute', min);
                if (unityState.pendingMinute === min) {
                    unityState.pendingMinute = null;
                    playUnityClips(min);
                }
            }

            // A single clip finished → show the next text group
            // Skip the first finished_clip because its text was already shown on starting_clip
            if (vars.finished_clip) {
                if (unityState.clipFirstShown && !unityState.clipSkippedFirst) {
                    // First clip just finished; text was already shown via starting_clip
                    unityState.clipSkippedFirst = true;
                    console.log('[RND] Skipping finished_clip for group 0 (already shown on start)');
                } else {
                    advanceClipTextGroup();
                }
            }

            // A clip is starting
            if (vars.starting_clip) {
                unityState.playing = true;
                // Show first text group immediately when the first clip starts
                if (!unityState.clipFirstShown) {
                    unityState.clipFirstShown = true;
                    advanceClipTextGroup();
                }
                // Goal clip → update score after a short delay
                if (vars.starting_clip.clip && vars.starting_clip.clip.substring(0, 4) === 'goal') {
                    setTimeout(() => {
                        updateLiveHeader();
                        refreshActiveTab();
                    }, 1200);
                }
            }

            // All clips for a minute finished → let timer advance to next minute
            if (vars.finished_playing) {
                const min = vars.finished_playing.id;
                unityState.playedMinutes.push(min);
                unityState.playing = false;
                console.log('[RND] All clips finished for minute', min);
                // Show any remaining lines
                flushClipText();
                // Clear activeMinute so liveStep resumes normal schedule-based flow
                unityState.activeMinute = null;
                // Force sec to 59 so liveStep advances to next minute on next tick
                if (liveState) {
                    liveState.sec = 59;
                    // Apply deferred filter switch if pending
                    if (liveState.pendingFilterSwitch) {
                        applyFilterSwitch(liveState.pendingFilterSwitch);
                    }
                }
            }
        };
    };

    // Save canvas to a hidden container so it survives tab switches
    const saveUnityCanvas = () => {
        if (!unityState.available) return;
        const webglContent = document.querySelector('.webgl-content');
        if (!webglContent) return;
        // Don't save if already in safe container
        if (webglContent.parentElement && webglContent.parentElement.id === 'rnd-unity-safe') return;
        let safe = document.getElementById('rnd-unity-safe');
        if (!safe) {
            safe = document.createElement('div');
            safe.id = 'rnd-unity-safe';
            safe.style.cssText = 'position:fixed;top:-9999px;left:-9999px;width:1px;height:1px;overflow:hidden;pointer-events:none;';
            document.body.appendChild(safe);
        }
        safe.appendChild(webglContent);
        console.log('[RND] Canvas saved to safe container');
    };

    const moveUnityCanvas = () => {
        if (!unityState.available) return;
        const webglContent = document.querySelector('.webgl-content');
        if (!webglContent) return;
        const target = document.getElementById('rnd-unity-viewport');
        if (!target) return;
        // Remember original parent so we could restore if needed
        if (!unityState.canvasParent) unityState.canvasParent = webglContent.parentElement;
        // Move the .webgl-content into our viewport
        target.innerHTML = '';
        target.appendChild(webglContent);
        // Make .webgl-content visible (TM hides it initially)
        webglContent.style.display = 'block';
        // Clear inline dimensions on #gameContainer (it has width:300px;height:200px)
        const gc = document.getElementById('gameContainer');
        if (gc) {
            gc.style.width = '100%';
            gc.style.height = '100%';
            gc.style.margin = '0';
        }
        // Show viewport
        target.style.display = 'block';
        // Remove no-unity layout class now that canvas is present
        const row = document.querySelector('.rnd-unity-row');
        if (row) row.classList.remove('rnd-no-unity');
        console.log('[RND] Canvas moved into viewport');
        // Sync feed & stats height to viewport height
        syncUnityPanelHeights();
    };

    // Keep feed and stats panels the same height as the viewport
    const syncUnityPanelHeights = () => {
        const vp = document.getElementById('rnd-unity-viewport');
        if (!vp) return;
        requestAnimationFrame(() => {
            const h = vp.offsetHeight;
            if (!h) return;
            const feed = document.getElementById('rnd-unity-feed');
            const stats = document.getElementById('rnd-unity-stats');
            if (feed) feed.style.maxHeight = h + 'px';
            if (stats) stats.style.maxHeight = h + 'px';
        });
    };

    const loadUnityClips = (minute, mData) => {
        const uw = getUW();
        if (!unityState.available || !uw.gameInstance) return false;
        const report = mData.report || {};
        const evts = report[String(minute)] || [];
        const videoList = [];
        evts.forEach(evt => {
            if (evt.chance && evt.chance.video) {
                const v = evt.chance.video;
                if (Array.isArray(v)) {
                    videoList.push(...v);
                } else {
                    videoList.push(v);
                }
            }
        });
        if (videoList.length === 0) return false;
        console.log('[RND] Loading clips for minute', minute, videoList.length, 'clips');
        // Prepare the text queue for this minute
        const { queue, groups, postQueue } = buildClipTextQueue(mData, minute);
        unityState.clipTextQueue = queue;
        unityState.clipTextGroups = groups;
        unityState.clipPostQueue = postQueue;
        unityState.clipTextCursor = 0;
        unityState.clipGroupCursor = 0;
        unityState.activeMinute = minute;
        unityState.clipFirstShown = false;
        unityState.clipSkippedFirst = false;
        unityState.pendingMinute = minute;
        uw.gameInstance.SendMessage('ClipsViewerScript', 'PrepareMinute', JSON.stringify({
            queue: videoList,
            id: minute
        }));
        return true;
    };

    const playUnityClips = (minute) => {
        const uw = getUW();
        if (!unityState.available || !uw.gameInstance) return;
        unityState.playing = true;
        console.log('[RND] Playing clips for minute', minute);
        uw.gameInstance.SendMessage('ClipsViewerScript', 'PlayMinute', JSON.stringify({ id: minute }));
    };

    const LINE_INTERVAL = 3;  // seconds between lines within a minute
    const POST_DELAY = 3;     // seconds after last line before advancing to next minute

    // ── Count total non-empty lines in an event's chance.text ──
    const countEventLines = (evt) => {
        if (!evt.chance || !evt.chance.text) return 1;
        let n = 0;
        evt.chance.text.forEach(textArr => {
            textArr.forEach(line => { if (line && line.trim()) n++; });
        });
        return Math.max(1, n);
    };

    // ── Calculate current match minute from kickoff timestamp ──
    const calculateLiveMinute = (kickoff) => {
        const now = Math.floor(Date.now() / 1000);
        const elapsed = now - kickoff;
        if (elapsed < 0) return null; // not started
        const FIRST_HALF = 45 * 60;  // 2700s
        const HT_BREAK = 15 * 60;  // 900s
        if (elapsed < FIRST_HALF) {
            return { minute: Math.floor(elapsed / 60), second: elapsed % 60, isHT: false };
        } else if (elapsed < FIRST_HALF + HT_BREAK) {
            return { minute: 45, second: 0, isHT: true };
        } else {
            const sh = elapsed - FIRST_HALF - HT_BREAK;
            return { minute: 45 + Math.floor(sh / 60), second: sh % 60, isHT: false };
        }
    };

    // ── Check if match is currently in progress (via API's live_min) ──
    const isMatchCurrentlyLive = (mData) => {
        const lm = mData.match_data?.live_min;
        return typeof lm === 'number' && lm > 0;
    };

    // ── Check if match is in the future (not yet started) ──
    const isMatchFuture = (mData) => {
        const md = mData.match_data;
        // Negative live_min means countdown to kickoff → match is in the future
        const lm = md?.live_min;
        if (typeof lm === 'number' && lm < 0) return true;
        // Positive live_min means match is in progress
        if (typeof lm === 'number' && lm > 0) return false;
        // Fallback: check kickoff timestamp
        const ko = md?.venue?.kickoff;
        if (ko) {
            const now = Math.floor(Date.now() / 1000);
            return Number(ko) > now;
        }
        return false;
    };

    // ── Derive effective kickoff timestamp from API's live_min ──
    // live_min = total real elapsed minutes since kickoff (includes HT break).
    // calculateLiveMinute then handles the 45min/15min-HT/second-half split.
    const deriveKickoff = (mData) => {
        const lm = mData.match_data.live_min;
        const now = Math.floor(Date.now() / 1000);
        return now - Math.round(lm * 60);
    };

    // ── Build per-minute schedule: which lines appear at which second ──
    const buildSchedule = (report, keyOnly = false) => {
        const schedule = {};     // min → [{evtIdx, lineIdx, sec}]
        const eventMinList = []; // sorted list of minutes that have events
        const mins = Object.keys(report).map(Number).sort((a, b) => a - b);
        mins.forEach(min => {
            const evts = report[min] || [];
            const entries = [];
            let secCursor = 0;
            evts.forEach((evt, evtIdx) => {
                if (keyOnly && evt.severity !== 1) return;
                const lineCount = countEventLines(evt);
                for (let li = 0; li < lineCount; li++) {
                    entries.push({ evtIdx, lineIdx: li, sec: secCursor });
                    secCursor += LINE_INTERVAL;
                }
            });
            if (entries.length > 0) {
                schedule[min] = entries;
                eventMinList.push(min);
            }
        });
        return { schedule, eventMinList };
    };

    // ── Check if an event is visible at the current live step (event-level) ──
    const isEventVisible = (evtMin, evtIdx, curMin, curEvtIdx) => {
        if (evtMin < curMin) return true;
        if (evtMin === curMin && evtIdx <= curEvtIdx) return true;
        return false;
    };

    // ── Compute score up to current step ──
    const scoreAtStep = (mData, curMin, curEvtIdx) => {
        const score = [0, 0];
        const homeId = String(mData.club.home.id);
        const report = mData.report || {};
        Object.keys(report).forEach(minKey => {
            const min = Number(minKey);
            (report[minKey] || []).forEach((evt, si) => {
                if (!isEventVisible(min, si, curMin, curEvtIdx)) return;
                if (!evt.parameters) return;
                evt.parameters.forEach(p => {
                    if (p.goal) {
                        if (String(evt.club) === homeId) score[0]++; else score[1]++;
                    }
                });
            });
        });
        return score;
    };

    // ── Compute active roster at current step (subs + red cards) ──
    // Returns { home: Set<playerId>, away: Set<playerId>, subbedPositions: Map<playerId, position> }
    const computeActiveRoster = (mData, curMin, curEvtIdx) => {
        const homeIds = new Set(Object.keys(mData.lineup.home));
        const homeActive = new Set();
        const awayActive = new Set();
        // Start with starters
        Object.values(mData.lineup.home).forEach(p => {
            if (!p.position.includes('sub')) homeActive.add(String(p.player_id));
        });
        Object.values(mData.lineup.away).forEach(p => {
            if (!p.position.includes('sub')) awayActive.add(String(p.player_id));
        });

        // Track position of subbed-in players (inherit from subbed-out player)
        const subbedPositions = new Map(); // player_id → position

        const report = mData.report || {};
        Object.keys(report).forEach(minKey => {
            const min = Number(minKey);
            (report[minKey] || []).forEach((evt, si) => {
                if (!isEventVisible(min, si, curMin, curEvtIdx)) return;
                if (!evt.parameters) return;
                evt.parameters.forEach(param => {
                    if (param.sub) {
                        const inId = String(param.sub.player_in);
                        const outId = String(param.sub.player_out);
                        const isHome = homeActive.has(outId) || homeIds.has(outId);
                        // Find position of outgoing player
                        const outPlayer = mData.lineup[isHome ? 'home' : 'away'][outId];
                        const outPos = subbedPositions.get(outId) || (outPlayer ? outPlayer.position : null);
                        if (outPos) subbedPositions.set(inId, outPos);
                        if (isHome) { homeActive.delete(outId); homeActive.add(inId); }
                        else { awayActive.delete(outId); awayActive.add(inId); }
                    }
                    if (param.red || param.yellow_red) {
                        const pid = String(param.red || param.yellow_red);
                        homeActive.delete(pid);
                        awayActive.delete(pid);
                    }
                });
            });
        });
        return { homeActive, awayActive, subbedPositions };
    };

    // ── Update live header (score + minute + progress) ──
    const updateLiveHeader = () => {
        if (!liveState) return;
        // Defer score update: don't count current event's goal until all its text lines are shown
        const scoreEvtIdx = (!liveState.ended && !liveState.curEvtComplete) ? liveState.curEvtIdx - 1 : liveState.curEvtIdx;
        const s = scoreAtStep(liveState.mData, liveState.min, scoreEvtIdx);
        $('#rnd-overlay .rnd-dlg-score').text(`${s[0]} - ${s[1]}`);
        const minDisplay = liveState.ended ? 'FT'
            : liveState.liveIsHT ? 'HT'
                : `${liveState.min}:${String(liveState.sec).padStart(2, '0')}`;
        $('#rnd-live-min-head').text(minDisplay);
        const maxMin = liveState.maxMin || 90;
        const pct = Math.min(100, Math.round((liveState.min * 60 + liveState.sec) / (maxMin * 60) * 100));
        $('#rnd-live-progress-head').css('width', pct + '%');
        if (liveState.ended) {
            $('#rnd-overlay .rnd-dlg-head').removeClass('rnd-live-active');
            $('#rnd-live-play-head').html('▶');
        }
        // Live-update mentality chips from report mentality_change events
        if (liveState.mData) {
            const mentalityMapH = { 1: 'V.Def', 2: 'Def', 3: 'Sl.Def', 4: 'Normal', 5: 'Sl.Att', 6: 'Att', 7: 'V.Att' };
            const homeClubId = String(liveState.mData.club.home.id);
            const awayClubId = String(liveState.mData.club.away.id);
            const mdH = liveState.mData.match_data;
            const curMent = {
                home: Number(mdH.mentality ? mdH.mentality.home : 4),
                away: Number(mdH.mentality ? mdH.mentality.away : 4)
            };
            const rpt = liveState.mData.report || {};
            Object.keys(rpt).forEach(mk => {
                const eMin = Number(mk);
                (rpt[mk] || []).forEach((evt, si) => {
                    if (!isEventVisible(eMin, si, liveState.min, scoreEvtIdx)) return;
                    if (!evt.parameters) return;
                    evt.parameters.forEach(p => {
                        if (p.mentality_change) {
                            const tid = String(p.mentality_change.team);
                            if (tid === homeClubId) curMent.home = Number(p.mentality_change.mentality);
                            else if (tid === awayClubId) curMent.away = Number(p.mentality_change.mentality);
                        }
                    });
                });
            });
            const hChip = $('#rnd-chip-ment-home');
            if (hChip.length) hChip.find('.chip-val').text(mentalityMapH[curMent.home] || curMent.home);
            const aChip = $('#rnd-chip-ment-away');
            if (aChip.length) aChip.find('.chip-val').text(mentalityMapH[curMent.away] || curMent.away);
        }
    };



    // ── Refresh whichever tab is active ──
    const refreshActiveTab = () => {
        if (!liveState) return;
        const tab = $('#rnd-overlay .rnd-tab.active').attr('data-tab');
        if (!tab) return;
        // When match ended/skipped, always do full render
        if (liveState.ended) {
            renderDialogTab(tab, liveState.mData);
            return;
        }
        // Report tab: append/update lines from schedule for current minute
        if (tab === 'report') {
            const entries = liveState.schedule[liveState.min] || [];
            const maxLinePerEvt = {};
            entries.forEach(e => {
                if (e.sec <= liveState.sec) {
                    if (maxLinePerEvt[e.evtIdx] === undefined || e.lineIdx > maxLinePerEvt[e.evtIdx]) {
                        maxLinePerEvt[e.evtIdx] = e.lineIdx;
                    }
                }
            });
            Object.entries(maxLinePerEvt).forEach(([eidx, lidx]) => {
                appendReportText(liveState.mData, liveState.min, Number(eidx), lidx);
            });
            return;
        }
        // Details tab: re-render only when an event just became complete (all text shown)
        if (tab === 'details') {
            if (liveState.justCompleted) renderDialogTab(tab, liveState.mData);
            return;
        }
        // Statistics tab: same — only re-render on event completion
        if (tab === 'statistics') {
            if (liveState.justCompleted) renderDialogTab(tab, liveState.mData);
            return;
        }
        // Lineups tab: re-render only when an event completes (goals, subs, etc. deferred)
        if (tab === 'lineups') {
            if (liveState.justCompleted) renderDialogTab(tab, liveState.mData);
            return;
        }
        // Other tabs: don't re-render during live
    };

    // ── Build HTML for a single report event accordion ──
    // maxLineIdx: how many individual lines to show (-1 = all)
    // hideBadges: when true, hide goal/red/sub badges (show text preview instead)
    const buildReportEventHtml = (evt, min, evtIdx, playerNames, homeId, maxLineIdx = -1, hideBadges = false) => {
        const chance = evt.chance;
        if (!chance || !chance.text) return '';

        const evtClub = String(evt.club || 0);
        const isHome = evtClub === homeId;
        const isNeutral = !evt.club || evtClub === '0';

        let headerBadges = '';
        let hasEvents = false;
        if (evt.parameters && !hideBadges) {
            evt.parameters.forEach(param => {
                if (param.goal) {
                    hasEvents = true;
                    const scorer = playerNames[param.goal.player] || '?';
                    const score = param.goal.score ? param.goal.score.join('-') : '';
                    let b = `⚽ ${scorer}`;
                    if (score) b += ` (${score})`;
                    if (param.goal.assist) b += ` <span style="font-size:11px;color:#90b878">ast. ${playerNames[param.goal.assist] || '?'}</span>`;
                    headerBadges += `<div class="rnd-report-evt-badge evt-goal">${b}</div>`;
                }
                if (param.yellow) { hasEvents = true; headerBadges += `<div class="rnd-report-evt-badge evt-yellow">🟨 ${playerNames[param.yellow] || '?'}</div>`; }
                if (param.yellow_red) { hasEvents = true; headerBadges += `<div class="rnd-report-evt-badge evt-red">🟥🟨 ${playerNames[param.yellow_red] || '?'}</div>`; }
                if (param.red) { hasEvents = true; headerBadges += `<div class="rnd-report-evt-badge evt-red">🟥 ${playerNames[param.red] || '?'}</div>`; }
                if (param.injury) {
                    hasEvents = true;
                    headerBadges += `<div class="rnd-report-evt-badge evt-injury"><span style="color:#ff3c3c;font-weight:800">✚</span> ${playerNames[param.injury] || '?'}</div>`;
                }
                if (param.sub) {
                    hasEvents = true;
                    const pIn = playerNames[param.sub.player_in] || '?';
                    const pOut = playerNames[param.sub.player_out] || '?';
                    headerBadges += `<div class="rnd-report-evt-badge evt-sub">🔄 ↑${pIn} ↓${pOut}</div>`;
                }
            });
        }

        // Build lines, respecting maxLineIdx limit (flat line count)
        const lines = [];
        let flatIdx = 0;
        chance.text.forEach((textArr) => {
            textArr.forEach(line => {
                if (!line || !line.trim()) return;
                if (maxLineIdx >= 0 && flatIdx > maxLineIdx) { flatIdx++; return; }
                let resolved = resolvePlayerTags(line, playerNames);
                resolved = resolved.replace(/\[goal\]/g, '<span class="rnd-goal-text">⚽ ');
                resolved = resolved.replace(/\[yellow\]/g, '<span class="rnd-yellow-text">🟨 ');
                resolved = resolved.replace(/\[red\]/g, '<span class="rnd-red-text">🟥 ');
                resolved = resolved.replace(/\[sub\]/g, '<span class="rnd-sub-text">🔄 ');
                resolved = resolved.replace(/\[assist\]/g, '');
                const openTags = (resolved.match(/<span class="rnd-(goal|yellow|red|sub)-text">/g) || []).length;
                for (let t = 0; t < openTags; t++) resolved += '</span>';
                lines.push(resolved);
                flatIdx++;
            });
        });

        const goalCls = headerBadges.includes('evt-goal') ? ' rnd-acc-goal' : '';
        const chevron = '<svg class="rnd-acc-chevron" viewBox="0 0 24 24"><path d="M8.59 16.59L10 18l6-6-6-6-1.41 1.41L13.17 12z"/></svg>';
        let headerContent = headerBadges;
        if (!hasEvents) {
            const preview = lines.length ? lines[0] : '';
            headerContent = `<span style="color:#90b878;font-size:12px">${preview}</span>`;
        }

        const totalLines = countEventLines(evt);
        let html = `<div class="rnd-acc" data-acc="${min}-${evtIdx}" data-line-count="${maxLineIdx >= 0 ? maxLineIdx + 1 : totalLines}">`;
        html += `<div class="rnd-acc-head${goalCls}">`;
        html += `<div class="rnd-acc-home">${isHome ? headerContent : ''}</div>`;
        html += `<div class="rnd-acc-min">${min}'</div>`;
        html += `<div class="rnd-acc-away">${!isHome && !isNeutral ? headerContent : (isNeutral ? headerContent : '')}</div>`;
        html += chevron;
        html += `</div>`;
        html += `<div class="rnd-acc-body"><div class="rnd-report-text">${lines.join('<br>')}</div></div>`;
        html += `</div>`;
        return html;
    };

    // ── Append or update lines in the Report tab (line-level stepping) ──
    const appendReportText = (mData, curMin, curEvtIdx, curLineIdx) => {
        const container = $('#rnd-report-timeline');
        // If container doesn't exist, the Report tab hasn't been rendered yet — do full render
        if (!container.length) {
            renderDialogTab('report', mData);
            return;
        }

        const report = mData.report || {};
        const evts = report[String(curMin)] || [];
        const evt = evts[curEvtIdx];
        if (!evt || !evt.chance || !evt.chance.text) return;

        const playerNames = buildPlayerNames(mData);
        const homeId = String(mData.club.home.id);
        const key = `${curMin}-${curEvtIdx}`;
        const existing = container.find(`[data-acc="${key}"]`);

        // During live, hide badges until all lines of this event are shown
        const totalLines = countEventLines(evt);
        const isComplete = curLineIdx >= totalLines - 1;
        const hideBadges = liveState && !liveState.ended && !isComplete;

        if (existing.length) {
            // Event accordion already exists — update with one more line
            const oldCount = Number(existing.attr('data-line-count') || 0);
            if (curLineIdx < oldCount) return;  // already shown this line
            // Re-build the accordion with updated line count
            const newHtml = buildReportEventHtml(evt, curMin, curEvtIdx, playerNames, homeId, curLineIdx, hideBadges);
            if (!newHtml) return;
            const wasOpen = existing.hasClass('open');
            const $new = $(newHtml);
            if (wasOpen) $new.addClass('open');
            existing.replaceWith($new);
        } else {
            // New event — collapse all other accordions, then append with auto-open
            container.find('.rnd-acc.open').removeClass('open');
            const evtHtml = buildReportEventHtml(evt, curMin, curEvtIdx, playerNames, homeId, curLineIdx, hideBadges);
            if (!evtHtml) return;
            const $el = $(evtHtml).addClass('rnd-live-feed-line open');
            container.append($el);
        }

        // Auto-scroll the dialog body to show the latest content
        const dlgBody = $('#rnd-dlg-body');
        dlgBody.animate({ scrollTop: dlgBody[0].scrollHeight }, 300);
    };

    // ── Advance one second in the live replay ──
    const liveStep = () => {
        if (!liveState || !liveState.playing) return;

        // ── LIVE mode: wall-clock driven ticking ──
        if (liveState.filterMode === 'live') {
            const kickoff = liveState.liveKickoff;
            if (!kickoff) return;
            const info = calculateLiveMinute(kickoff);
            const lastMin = liveState.mData.match_data.last_min || 90;
            if (!info || info.minute > lastMin) {
                // Match ended
                liveState.min = lastMin; liveState.sec = 59;
                liveState.curEvtIdx = 999; liveState.curLineIdx = 999;
                liveState.ended = true; liveState.playing = false;
                liveState.liveIsHT = false;
                updateLiveHeader(); refreshActiveTab();
                return;
            }
            const prevMin = liveState.min;
            liveState.min = info.minute;
            liveState.sec = info.second;
            liveState.liveIsHT = info.isHT;
            if (info.isHT) {
                // Halftime — all first-half events visible, just tick clock
                liveState.curEvtIdx = 999; liveState.curLineIdx = 999;
                liveState.curEvtComplete = true;
                updateLiveHeader();
                liveState.timer = setTimeout(liveStep, liveState.speed);
                return;
            }
            // If Unity clips are playing for this minute, just tick the clock
            if (unityState.activeMinute === liveState.min) {
                updateLiveHeader();
                liveState.timer = setTimeout(liveStep, liveState.speed);
                return;
            }
            // Show all events up to current minute
            liveState.curEvtIdx = 999; liveState.curLineIdx = 999;
            liveState.curEvtComplete = true;
            const minuteChanged = liveState.min !== prevMin;
            liveState.justCompleted = minuteChanged;
            // Load Unity clips when entering a new event minute
            if (minuteChanged && unityState.available && unityState.ready) {
                const hasClips = loadUnityClips(liveState.min, liveState.mData);
                if (hasClips) {
                    // Clips loaded — animation will play, text driven by stargate callbacks
                    updateLiveHeader();
                    refreshActiveTab();
                    liveState.timer = setTimeout(liveStep, liveState.speed);
                    return;
                }
            }
            updateLiveHeader();
            if (minuteChanged) refreshActiveTab();
            liveState.timer = setTimeout(liveStep, liveState.speed);
            return;
        }

        liveState.sec++;

        // ── If Unity clips are active for this minute, just tick the clock ──
        if (unityState.activeMinute === liveState.min) {
            // Clock advances, but text is driven by stargate callbacks (advanceClipText)
            // Don't process schedule, don't advance minute — wait for finished_playing
            updateLiveHeader();
            liveState.timer = setTimeout(liveStep, liveState.speed);
            return;
        }

        // Check if current minute is finished (past last line + delay, or >= 60)
        const entries = liveState.schedule[liveState.min] || [];
        const lastSec = entries.length > 0 ? entries[entries.length - 1].sec : -1;
        const minuteEnd = lastSec + POST_DELAY;

        if (liveState.sec > minuteEnd || liveState.sec >= 60) {
            // Move to next event minute
            const nextIdx = liveState.eventMinIdx + 1;
            if (nextIdx >= liveState.eventMinList.length) {
                // Match finished
                liveState.min = liveState.maxMin;
                liveState.sec = 59;
                liveState.curEvtIdx = 999;
                liveState.curLineIdx = 999;
                liveState.playing = false;
                liveState.ended = true;
                updateLiveHeader();
                refreshActiveTab();
                return;
            }
            liveState.eventMinIdx = nextIdx;
            liveState.min = liveState.eventMinList[nextIdx];
            liveState.sec = 0;
            // Reset event tracking to prevent score from briefly showing future goals
            liveState.curEvtIdx = -1;
            liveState.curEvtComplete = false;

            // ── Unity 3D: trigger clip loading when entering a new minute with videos ──
            if (unityState.available && unityState.ready) {
                const hasClips = loadUnityClips(liveState.min, liveState.mData);
                if (hasClips) {
                    // Timer keeps running — clock ticks, text driven by clip callbacks
                    updateLiveHeader();
                    liveState.timer = setTimeout(liveStep, liveState.speed);
                    return;
                }
            }
        }

        // Check schedule for new lines at current second (non-clip minutes only)
        let hasNew = false;
        liveState.justCompleted = false;
        const curEntries = liveState.schedule[liveState.min] || [];
        const report = liveState.mData.report || {};
        const evts = report[String(liveState.min)] || [];
        curEntries.forEach(entry => {
            if (entry.sec === liveState.sec) {
                liveState.curEvtIdx = entry.evtIdx;
                liveState.curLineIdx = entry.lineIdx;
                hasNew = true;
                // Check if event just became complete (all text lines shown)
                const evt = evts[entry.evtIdx];
                const total = evt ? countEventLines(evt) : 1;
                const isComplete = entry.lineIdx >= total - 1;
                liveState.curEvtComplete = isComplete;
                if (isComplete) liveState.justCompleted = true;
            }
        });

        updateLiveHeader();
        if (hasNew) refreshActiveTab();
        liveState.timer = setTimeout(liveStep, liveState.speed);
    };

    const livePlay = () => {
        if (!liveState || liveState.ended) return;
        liveState.playing = true;
        $('#rnd-live-play-head').html('⏸');
        // If Unity was paused mid-animation, unpause it
        if (unityState.activeMinute !== null) {
            const uw = getUW();
            if (uw.gameInstance) {
                uw.gameInstance.SendMessage('ClipsViewerScript', 'OnPauseGame');
            }
        }
        liveStep();
    };
    const livePause = () => {
        if (!liveState) return;
        liveState.playing = false;
        clearTimeout(liveState.timer);
        $('#rnd-live-play-head').html('▶');
        // Immediately pause Unity animation if playing
        if (unityState.playing && unityState.activeMinute !== null) {
            const uw = getUW();
            if (uw.gameInstance) {
                uw.gameInstance.SendMessage('ClipsViewerScript', 'OnPauseGame');
            }
        }
    };
    const liveToggle = () => {
        if (!liveState) return;
        if (liveState.playing) livePause(); else livePlay();
    };

    // Apply a deferred or immediate filter mode switch (All ↔ Key ↔ Live)
    const applyFilterSwitch = (mode) => {
        if (!liveState) return;
        // LIVE mode: switch to all-events schedule and jump to current wall-clock minute
        if (mode === 'live') {
            const sch = liveState.scheduleAll;
            liveState.schedule = sch.schedule;
            liveState.eventMinList = sch.eventMinList;
            liveState.maxMin = sch.eventMinList.length ? sch.eventMinList[sch.eventMinList.length - 1] : 90;
            let kickoff = liveState.liveKickoff;
            if (!kickoff && isMatchCurrentlyLive(liveState.mData)) {
                kickoff = deriveKickoff(liveState.mData);
                liveState.liveKickoff = kickoff;
            }
            const info = kickoff ? calculateLiveMinute(kickoff) : null;
            const lastMin = liveState.mData.match_data.last_min || 90;
            if (info && info.minute <= lastMin) {
                liveState.min = info.minute;
                liveState.sec = info.second;
                liveState.liveIsHT = info.isHT;
                liveState.curEvtIdx = 999; liveState.curLineIdx = 999;
                liveState.curEvtComplete = true; liveState.justCompleted = true;
                liveState.ended = false;
            } else {
                // Match over
                liveState.min = lastMin; liveState.sec = 59;
                liveState.curEvtIdx = 999; liveState.curLineIdx = 999;
                liveState.ended = true; liveState.playing = false;
                liveState.liveIsHT = false;
            }
            liveState.pendingFilterSwitch = null;
            console.log('[RND] Filter switch applied: live (min ' + liveState.min + ')');
            updateLiveHeader(); refreshActiveTab();
            return;
        }
        liveState.liveIsHT = false;
        const sch = mode === 'key' ? liveState.scheduleKey : liveState.scheduleAll;
        liveState.schedule = sch.schedule;
        liveState.eventMinList = sch.eventMinList;
        liveState.maxMin = sch.eventMinList.length ? sch.eventMinList[sch.eventMinList.length - 1] : 90;
        // Find next event minute AFTER current (don't re-play the minute we just finished)
        const curMin = liveState.min;
        let newIdx = sch.eventMinList.findIndex(m => m > curMin);
        if (newIdx < 0) {
            // No more minutes — match finished
            liveState.min = liveState.maxMin;
            liveState.sec = 59;
            liveState.curEvtIdx = 999;
            liveState.curLineIdx = 999;
            liveState.playing = false;
            liveState.ended = true;
            liveState.pendingFilterSwitch = null;
            updateLiveHeader();
            refreshActiveTab();
            return;
        }
        liveState.eventMinIdx = newIdx;
        liveState.min = sch.eventMinList[newIdx];
        liveState.sec = -1;
        liveState.curEvtIdx = -1;
        liveState.curLineIdx = -1;
        liveState.curEvtComplete = true;
        liveState.justCompleted = false;
        liveState.pendingFilterSwitch = null;
        console.log('[RND] Filter switch applied: ' + mode);
        // Load Unity clips for the new minute (so animation + clip-driven text work)
        if (unityState.available && unityState.ready) {
            loadUnityClips(liveState.min, liveState.mData);
        }
        updateLiveHeader();
        refreshActiveTab();
    };

    const liveSkip = () => {
        if (!liveState) return;
        livePause();
        liveState.min = liveState.maxMin;
        liveState.sec = 59;
        liveState.curEvtIdx = 999;
        liveState.curLineIdx = 999;
        liveState.eventMinIdx = liveState.eventMinList.length;
        liveState.ended = true;
        updateLiveHeader();
        refreshActiveTab();
    };

    const openMatchDialog = (matchId) => {
        const cached = roundMatchCache.get(String(matchId));
        // If not cached yet, fetch on-demand
        const show = (mData) => {
            // Determine if this match is in the future
            const matchIsFuture = isMatchFuture(mData);

            // Determine if match is currently live
            const matchIsLive = !matchIsFuture && isMatchCurrentlyLive(mData);

            // Build schedules & live state only for non-future matches
            if (!matchIsFuture) {
                const rpt = mData.report || {};
                const allSch = buildSchedule(rpt, false);
                const keySch = buildSchedule(rpt, true);
                const { schedule: keySchedule, eventMinList: keyEventMinList } = keySch;
                const maxMin = keyEventMinList.length ? keyEventMinList[keyEventMinList.length - 1] : 90;

                if (liveState && liveState.timer) clearTimeout(liveState.timer);
                if (matchIsLive) {
                    const { schedule: allSchedule, eventMinList: allEventMinList } = allSch;
                    const allMaxMin = allEventMinList.length ? allEventMinList[allEventMinList.length - 1] : 90;
                    const effectiveKickoff = deriveKickoff(mData);
                    const info = calculateLiveMinute(effectiveKickoff);
                    const lastMin = mData.match_data.last_min || 90;
                    const liveMin = info ? Math.min(info.minute, lastMin) : Math.floor(mData.match_data.live_min);
                    const liveSec = info ? info.second : 0;
                    const liveHT = info ? info.isHT : false;
                    console.log('[RND] LIVE detected — live_min:', mData.match_data.live_min, '→ min:', liveMin, 'sec:', liveSec, 'HT:', liveHT);
                    liveState = {
                        min: liveMin, sec: liveSec,
                        curEvtIdx: 999, curLineIdx: 999,
                        curEvtComplete: true, justCompleted: false,
                        playing: false, timer: null, mData,
                        speed: 1000, maxMin: allMaxMin,
                        ended: info ? info.minute > lastMin : false,
                        schedule: allSchedule, eventMinList: allEventMinList, eventMinIdx: 0,
                        filterMode: 'live', liveIsHT: liveHT,
                        liveKickoff: effectiveKickoff,
                        scheduleAll: allSch, scheduleKey: keySch
                    };
                } else {
                    liveState = {
                        min: keyEventMinList.length ? keyEventMinList[0] : 0,
                        sec: -1,
                        curEvtIdx: -1, curLineIdx: -1,
                        curEvtComplete: true, justCompleted: false,
                        playing: false, timer: null, mData,
                        speed: 1000, maxMin, ended: false,
                        schedule: keySchedule, eventMinList: keyEventMinList, eventMinIdx: 0,
                        filterMode: 'key', liveIsHT: false,
                        liveKickoff: null,
                        scheduleAll: allSch, scheduleKey: keySch
                    };
                }
            } else {
                // Future match: no live state needed
                if (liveState && liveState.timer) clearTimeout(liveState.timer);
                liveState = null;
            }

            // Build dialog overlay
            const overlay = window.TmMatchDialog.build(mData, matchIsFuture, matchIsLive);

            $('body').append(overlay).css('overflow', 'hidden');

            const closeDialog = () => {
                if (liveState && liveState.timer) clearTimeout(liveState.timer);
                liveState = null;
                if (prematchTimer) { clearTimeout(prematchTimer); prematchTimer = null; }
                overlay.remove();
                $('body').css('overflow', '');
            };

            // Close handlers
            overlay.on('click', '#rnd-dlg-close', closeDialog);
            overlay.on('click', (e) => { if (e.target === overlay[0]) closeDialog(); });
            $(document).one('keydown.rndDlg', (e) => {
                if (e.key === 'Escape') { closeDialog(); $(document).off('keydown.rndDlg'); }
            });

            // Live replay controls & filters (skip for future matches)
            if (!matchIsFuture) {
                overlay.on('click', '#rnd-live-play-head', liveToggle);
                overlay.on('click', '#rnd-live-skip-head', liveSkip);
                overlay.on('click', '.rnd-live-filter-btn', function () {
                    const mode = $(this).data('filter');
                    if (!liveState || liveState.filterMode === mode) return;
                    liveState.filterMode = mode;
                    overlay.find('.rnd-live-filter-btn').removeClass('active');
                    $(this).addClass('active');
                    if (unityState.activeMinute !== null || unityState.playing) {
                        liveState.pendingFilterSwitch = mode;
                        console.log('[RND] Filter switch deferred until animation finishes');
                        return;
                    }
                    applyFilterSwitch(mode);
                });
            }

            // Tab switching
            overlay.on('click', '.rnd-tab', function () {
                overlay.find('.rnd-tab').removeClass('active');
                $(this).addClass('active');
                renderDialogTab($(this).attr('data-tab'), mData);
            });

            // Render default tab + start live replay
            // Add rnd-live-active class to header when live
            if (!matchIsFuture) {
                $('#rnd-overlay .rnd-dlg-head').addClass('rnd-live-active');
            }
            renderDialogTab('lineups', mData);
            if (!matchIsFuture) {
                updateLiveHeader();
                setTimeout(() => livePlay(), 500);
            } else {
                // Schedule auto-reload when match kicks off
                const lm = mData.match_data?.live_min;
                if (typeof lm === 'number' && lm < 0) {
                    const msUntilKickoff = Math.abs(lm) * 60 * 1000 + 5000; // +5s buffer
                    if (prematchTimer) clearTimeout(prematchTimer);
                    prematchTimer = setTimeout(() => {
                        prematchTimer = null;
                        // Close current dialog, clear cache, re-open with fresh data
                        closeDialog();
                        roundMatchCache.delete(String(matchId));
                        openMatchDialog(matchId);
                    }, msUntilKickoff);
                    console.log('[RND] Prematch timer set — auto-reload in', Math.round(msUntilKickoff / 1000), 'seconds');
                }
            }


        };

        if (cached && cached.data) {
            show(cached.data);
        } else {
            // Fetch match data on demand
            window.TmApi.fetchMatch(matchId).then(mData => { if (mData) show(mData); });
        }
    };

    const renderDialogTab = (tab, mData) => {
        // Save Unity canvas before destroying lineups tab DOM
        // Skip for lineups — it handles in-place updates without destroying viewport
        if (tab !== 'lineups') saveUnityCanvas();
        const body = $('#rnd-dlg-body');
        const curMin = liveState ? liveState.min : 999;
        const curEvtIdx = liveState ? liveState.curEvtIdx : 999;
        // For tabs showing parameters (goals/subs/reds), defer until event text is complete
        const paramEvtIdx = (liveState && !liveState.ended && !liveState.curEvtComplete) ? curEvtIdx - 1 : curEvtIdx;
        const matchEnded = !liveState || liveState.ended;
        const sharedOpts = {
            getLiveState: () => liveState,
            getUnityState: () => unityState,
            isMatchPage: true,
            moveUnityCanvas, saveUnityCanvas, updateUnityStats,
            computeActiveRoster, isMatchFuture, isEventVisible,
            getPlayerData,
            fetchTooltip, parseNum, getColor,
            REC_THRESHOLDS,
            buildPlayerNames, buildReportEventHtml, resolvePlayerTags,
        };
        const statsOpts = { liveState, isEventVisible, buildPlayerNames, buildReportEventHtml, matchEnded };
        switch (tab) {
            case 'details': renderDetailsTab(body, mData, curMin, paramEvtIdx); break;
            case 'statistics': TmMatchStatistics.render(body, mData, curMin, paramEvtIdx, statsOpts); break;
            case 'report': renderReportTab(body, mData, curMin, curEvtIdx); break;
            case 'lineups': TmMatchLineups.render(body, mData, curMin, paramEvtIdx, sharedOpts); break;
            case 'venue': TmMatchVenue.render(body, mData); break;
            case 'h2h': TmMatchH2H.render(body, mData); break;
            case 'league': TmMatchLeague.render(body, mData, curMin, paramEvtIdx); break;
            case 'analysis': TmMatchAnalysis.render(body, mData, { getPlayerData }); break;
        }
    };

    // ── Helper: build player name lookup ──
    const buildPlayerNames = (mData) => {
        const names = {};
        ['home', 'away'].forEach(side => {
            Object.values(mData.lineup[side]).forEach(p => {
                names[p.player_id] = p.nameLast || p.name;
            });
        });
        return names;
    };

    // ── Helper: resolve [player=ID] tags in text ──
    const resolvePlayerTags = (text, playerNames) => {
        return text.replace(/\[player=(\d+)\]/g, (_, id) => {
            const name = playerNames[id] || id;
            return `<span class="rnd-player-name">${name}</span>`;
        });
    };

    const renderDetailsTab = (body, mData, curMin = 999, curEvtIdx = 999) => {
        const playerNames = buildPlayerNames(mData);
        const homeIds = new Set(Object.keys(mData.lineup.home));
        const homeId = String(mData.club.home.id);

        let html = '<div style="max-width:900px;margin:0 auto">';

        // ── Parse key events from report (filtered by current step) ──
        const events = [];
        const report = mData.report || {};
        Object.keys(report).sort((a, b) => Number(a) - Number(b)).forEach(minKey => {
            const min = Number(minKey);
            report[minKey].forEach((evt, si) => {
                if (!isEventVisible(min, si, curMin, curEvtIdx)) return;
                if (!evt.parameters) return;
                evt.parameters.forEach(param => {
                    if (param.goal) {
                        events.push({
                            min, type: 'goal',
                            isHome: String(evt.club) === homeId,
                            player: playerNames[param.goal.player] || '?',
                            assist: param.goal.assist ? (playerNames[param.goal.assist] || null) : null
                        });
                    }
                    if (param.yellow) {
                        events.push({
                            min, type: 'yellow',
                            isHome: homeIds.has(String(param.yellow)),
                            player: playerNames[param.yellow] || '?'
                        });
                    }
                    if (param.yellow_red) {
                        events.push({
                            min, type: 'yellowred',
                            isHome: homeIds.has(String(param.yellow_red)),
                            player: playerNames[param.yellow_red] || '?'
                        });
                    }
                    if (param.sub) {
                        const isHome = homeIds.has(String(param.sub.player_in)) || homeIds.has(String(param.sub.player_out));
                        events.push({
                            min, type: 'sub', isHome,
                            playerIn: playerNames[param.sub.player_in] || '?',
                            playerOut: playerNames[param.sub.player_out] || '?'
                        });
                    }
                    if (param.injury) {
                        const pid = String(param.injury);
                        events.push({
                            min, type: 'injury',
                            isHome: homeIds.has(pid),
                            player: playerNames[pid] || '?'
                        });
                    }
                });
            });
        });

        // ── Build event text (icon placement depends on side) ──
        const evtText = (evt, side) => {
            const icons = { goal: '⚽', yellow: '🟨', yellowred: '🟥', sub: '🔄', injury: '<span style="color:#ff3c3c;font-weight:800">✚</span>' };
            const icon = icons[evt.type];
            let text = '';
            if (evt.type === 'goal') {
                text = `<strong style="color:#f0fce0">${evt.player}</strong>`;
                if (evt.assist) text += ` <span style="color:#90b878;font-size:11px">(${evt.assist})</span>`;
            } else if (evt.type === 'sub') {
                text = `<span style="color:#80d848">↑ ${evt.playerIn}</span>  <span style="color:#c07050">↓ ${evt.playerOut}</span>`;
            } else if (evt.type === 'injury') {
                text = `<span style="color:#ff8c3c">${evt.player}</span>`;
            } else {
                text = evt.player;
            }
            return side === 'home' ? `${text} ${icon}` : `${icon} ${text}`;
        };

        // ── Render timeline ──
        html += '<div class="rnd-timeline">';
        events.forEach(evt => {
            const cls = evt.type === 'goal' ? ' rnd-tl-goal' : '';
            html += `<div class="rnd-tl-row${cls}">`;
            html += `<div class="rnd-tl-home">${evt.isHome ? evtText(evt, 'home') : ''}</div>`;
            html += `<div class="rnd-tl-min">${evt.min}'</div>`;
            html += `<div class="rnd-tl-away">${!evt.isHome ? evtText(evt, 'away') : ''}</div>`;
            html += `</div>`;
        });
        html += '</div></div>';

        body.html(html);
    };

    const renderReportTab = (body, mData, curMin = 999, curEvtIdx = 999) => {
        const playerNames = buildPlayerNames(mData);
        const homeId = String(mData.club.home.id);
        const report = mData.report || {};
        const allMinutes = Object.keys(report).sort((a, b) => Number(a) - Number(b));

        let html = '<div style="max-width:900px;margin:0 auto"><div id="rnd-report-timeline" class="rnd-timeline">';

        allMinutes.forEach(minKey => {
            const min = Number(minKey);
            report[minKey].forEach((evt, evtIdx) => {
                if (!isEventVisible(min, evtIdx, curMin, curEvtIdx)) return;
                html += buildReportEventHtml(evt, min, evtIdx, playerNames, homeId);
            });
        });

        html += '</div></div>';
        body.html(html);

        // Accordion toggle (delegated)
        body.off('click.rndacc').on('click.rndacc', '.rnd-acc-head', function () {
            $(this).closest('.rnd-acc').toggleClass('open');
        });
    };

    // ─── Loading indicator ───────────────────────────────────────────────
    const cleanupPage = () => {
        if (liveState && liveState.timer) clearTimeout(liveState.timer);
        liveState = null;
        $('#rnd-overlay').remove();
        $('body').css('overflow', '');
        unityState = {
            available: false, ready: false, playing: false,
            pendingMinute: null, loadedMinutes: [], playedMinutes: [],
            canvasParent: null, tmPaused: false,
            clipTextQueue: [], clipTextCursor: 0,
            clipTextGroups: [], clipGroupCursor: 0,
            clipPostQueue: [], activeMinute: null,
            clipFirstShown: false, clipSkippedFirst: false
        };
    };

    const initForCurrentPage = () => {
        cleanupPage();
        injectStyles();
        initUnity();
        const matchId = window.location.pathname.match(/\/matches\/(\d+)/)?.[1];
        if (!matchId) return;
        // Remove TM's default Rounds widget and ad placeholder
        try { $('.banner_placeholder.rectangle')[0].parentNode.removeChild($('.banner_placeholder.rectangle')[0]); } catch (e) { }
        try { $('.column3_a .box').has('h2').filter(function () { return $(this).find('h2').text().trim().toUpperCase() === 'ROUNDS'; }).remove(); } catch (e) { }
        const pollInterval = setInterval(() => {
            if ($('body').length && document.readyState !== 'loading') {
                clearInterval(pollInterval);
                openMatchDialog(matchId);
            }
        }, 500);
    };

    initForCurrentPage();
})();



// ─── tm-player.user.js ───────────────────────────────────────────


(function () {
    'use strict';

    const $ = window.jQuery;
    if (!$) return;

    const urlMatch = location.pathname.match(/\/players\/(\d+)/);
    if (!urlMatch) return;
    const PLAYER_ID = urlMatch[1];

    const PlayerDB = window.TmPlayerDB;
    const PlayerArchiveDB = window.TmPlayerArchiveDB;

    /* -----------------------------------------------------------
       SHARED STATE (tooltip-derived)
       ----------------------------------------------------------- */
    let player = null;
    let club = null;


    /* Check if player belongs to the logged-in user's club */
    const getOwnClubIds = () => {
        const s = window.SESSION;
        if (!s) return [];
        const ids = [];
        if (s.main_id) ids.push(String(s.main_id));
        if (s.b_team) ids.push(String(s.b_team));
        return ids;
    };

    const injectCSS = () => window.TmPlayerStyles.inject();

    const applyTooltip = (data) => {
        if (!data || !data.player) return;
        if (data.retired) return;

        player = data.player;
        club = data.club ?? null;

        /* re-render scout if already shown */
        TmScoutMod.reRender();
        /* parse NT data before card renders (cleans DOM) */
        const parsedNTData = TmHistoryMod.parseNT();

        /* build player card after tooltip data arrives */
        TmPlayerCard.render({
            player,
            club
        });

        /* build ASI calculator with defaults after TI is computed */
        TmAsiCalculator.mount(
            document.querySelector('.column3_a'),
            { player }
        );

        /* re-render history if already loaded, so NT tab appears */
        if (parsedNTData && TmTabsMod.isLoaded('history')) TmHistoryMod.reRender();

        /* fetch scout data for Best Estimate card */
        fetchBestEstimate();

        TmSkillsGrid.mount({ player });

        TmTabsMod.mount({ player, getOwnClubIds, injectCSS });
    };

    //    INIT - run DB init and tooltip fetch in parallel
    //    -----------------------------------------------------------
    Promise.all([
        PlayerDB.init().then(() => PlayerArchiveDB.init()).catch(e => {
            console.warn('[DB] IndexedDB init failed, falling back:', e);
        }),
        TmApi.fetchPlayerTooltip(PLAYER_ID),
    ]).then(([, data]) => applyTooltip(data));

    /* -----------------------------------------------------------
       BEST ESTIMATE see components/player/tm-player-best-estimate.js
       ----------------------------------------------------------- */
    const fetchBestEstimate = () => {
        const col1 = document.querySelector('.column1');
        if (!col1) return;
        const existing = col1.querySelector('#tmbe-standalone');
        if (existing) existing.remove();
        const el = document.createElement('div');
        el.id = 'tmbe-standalone';
        const nav = col1.querySelector('.tmcn-nav');
        if (nav && nav.nextSibling) col1.insertBefore(el, nav.nextSibling);
        else col1.appendChild(el);
        TmApi.fetchPlayerInfo(PLAYER_ID, 'scout').then(data => {
            TmBestEstimate.render(el, {
                scoutData: data || {},
                player,
            });
        });
    };

    /* -----------------------------------------------------------
       SIDEBAR see components/player/tm-player-sidebar.js
       ----------------------------------------------------------- */
    const col3 = document.querySelector('.column3_a');
    if (col3) TmPlayerSidebar.mount(col3);

    /* -----------------------------------------------------------
       SIDEBAR NAV see components/player/tm-sidebar-nav.js
       ----------------------------------------------------------- */
    const col1Nav = document.querySelector('.column1');
    if (col1Nav) TmSidebarNav.mount(col1Nav);

    window.addEventListener('tm:growthUpdated', () => {
        try { TmGraphsMod.reRender(); } catch (e) { }
        try { TmSkillsGrid.reRender(); } catch (e) { }
    });

})();



// ─── tm-players.user.js ──────────────────────────────────────────


(function () {
    'use strict';

    const PlayerDB = window.TmPlayerDB;
    const PlayerArchiveDB = window.TmPlayerArchiveDB;
    const { NAMES_OUT_SHORT, NAMES_GK_SHORT, extractSkills,
        ensureAllPlayersVisible, createSquadLoader, parseSquadPage } = window.TmSquad;

    /* -----------------------------------------------------------
       Process: fetch tooltips, distribute decimals,
       log results with +/- compared to previous week.
       ----------------------------------------------------------- */
    const processSquadPage = async (players) => {
        if (!players || !players.length) return;

        /* Efficiency weight for decimal distribution (same scale as TM's internal model) */
        const eff = window.TmUtils.skillEff;

        const fetchTip = pid => TmApi.fetchPlayerTooltip(pid).then(d => d?.player ?? null);
        const delay = ms => new Promise(r => setTimeout(r, ms));

        console.log(`%c[Squad] Fetching tooltips for ${players.length} players...`, 'font-weight:bold;color:#38bdf8');

        const loader = createSquadLoader();
        const results = [];

        for (let pi = 0; pi < players.length; pi++) {
            const p = players[pi];
            loader.update(pi + 1, players.length, p.name);

            const curAgeKeyCheck = `${p.ageYears}.${p.ageMonths}`;
            const existingStore = PlayerDB.get(p.pid);
            const existingRec = existingStore?.records?.[curAgeKeyCheck];
            const weeksSince = (Date.now() - (existingStore?.lastSeen || 0)) / 604800000;
            if (existingRec?.locked || (existingRec && weeksSince < 1)) {
                const reason = existingRec?.locked ? 'locked' : `fresh (${weeksSince.toFixed(1)}w ago)`;
                console.log(`[Squad] ${p.name} — ${reason} for ${curAgeKeyCheck}, skipping`);
                continue;
            }

            const tip = await fetchTip(p.pid);
            await delay(100);

            if (!tip) {
                console.warn(`[Squad] Could not fetch tooltip for ${p.name} (${p.pid})`);
                continue;
            }

            /* tip is already normalizePlayer'd by TmApi.fetchPlayerTooltip */
            const asi = tip.asi;
            const routine = tip.routine;
            const favpos = tip.favposition || '';
            const isGK = tip.isGK;
            const N = isGK ? 11 : 14;

            const intSkills = tip.skills ? extractSkills(tip.skills, isGK) : p.skills;

            /* --- Previous DB record for decimal propagation --- */
            const dbRecord = PlayerDB.get(p.pid);
            let prevDecimals = null, prevSkillsFull = null, curDbSkillsFull = null;

            if (dbRecord?.records) {
                const keys = Object.keys(dbRecord.records).sort((a, b) => {
                    const [ay, am] = a.split('.').map(Number);
                    const [by, bm] = b.split('.').map(Number);
                    return (ay * 12 + am) - (by * 12 + bm);
                });

                const curAgeKey = `${p.ageYears}.${p.ageMonths}`;
                const curDbRec = dbRecord.records[curAgeKey];
                if (curDbRec?.skills?.length === N) {
                    curDbSkillsFull = curDbRec.skills.map(v => {
                        const n = typeof v === 'string' ? parseFloat(v) : v;
                        return n >= 20 ? 20 : n;
                    });
                }

                let prevIdx = keys.length - 1;
                if (keys.length > 1 && keys[prevIdx] === curAgeKey) prevIdx = keys.length - 2;

                if (prevIdx >= 0) {
                    const prevRec = dbRecord.records[keys[prevIdx]];
                    if (prevRec?.skills?.length === N) {
                        prevSkillsFull = prevRec.skills.map(v => {
                            const n = typeof v === 'string' ? parseFloat(v) : v;
                            return n >= 20 ? 20 : n;
                        });
                        prevDecimals = prevSkillsFull.map(v => v >= 20 ? 0 : v - Math.floor(v));
                    }
                }
            }

            /* --- ASI remainder (total decimal points not yet reflected as integer gains) --- */
            const K = isGK ? 48717927500 : 263533760000;
            const intSum = intSkills.reduce((s, v) => s + v, 0);
            const asiRemainder = asi > 0
                ? Math.round((Math.pow(2, Math.log(K * asi) / Math.log(128)) - intSum) * 100) / 100
                : 0;

            const improvementMap = {};
            p.improved.forEach(imp => { improvementMap[imp.index] = imp.type; });

            const totalGain = p.TI / 10;
            let newDecimals;

            if (prevDecimals && asi > 0) {
                newDecimals = [...prevDecimals];

                const improvedIndices = p.improved.map(imp => imp.index);
                if (improvedIndices.length > 0 && totalGain > 0) {
                    const effWeights = improvedIndices.map(i => eff(intSkills[i]));
                    const effTotal = effWeights.reduce((a, b) => a + b, 0);
                    const shares = effTotal > 0
                        ? effWeights.map(w => w / effTotal)
                        : effWeights.map(() => 1 / improvedIndices.length);
                    improvedIndices.forEach((idx, j) => { newDecimals[idx] += totalGain * shares[j]; });
                }

                for (const imp of p.improved) {
                    if (imp.type === 'one_up') newDecimals[imp.index] = 0.00;
                }

                let overflow = 0, passes = 0;
                do {
                    overflow = 0; let freeCount = 0;
                    for (let i = 0; i < N; i++) {
                        if (intSkills[i] >= 20) { newDecimals[i] = 0; continue; }
                        if (newDecimals[i] >= 1.0) { overflow += newDecimals[i] - 0.99; newDecimals[i] = 0.99; }
                        else if (newDecimals[i] < 0.99) freeCount++;
                    }
                    if (overflow > 0.0001 && freeCount > 0) {
                        const add = overflow / freeCount;
                        for (let i = 0; i < N; i++) { if (intSkills[i] < 20 && newDecimals[i] < 0.99) newDecimals[i] += add; }
                    }
                } while (overflow > 0.0001 && ++passes < 20);

                let subtleOverflow = 0;
                passes = 0;
                do {
                    subtleOverflow = 0;
                    for (let i = 0; i < N; i++) {
                        if (intSkills[i] >= 20) continue;
                        const prevInt = prevSkillsFull ? Math.floor(prevSkillsFull[i]) : intSkills[i];
                        if (!improvementMap[i] && intSkills[i] === prevInt && newDecimals[i] >= 1.0) {
                            subtleOverflow += newDecimals[i] - 0.99;
                            newDecimals[i] = 0.99;
                        }
                    }
                    if (subtleOverflow > 0.0001) {
                        let freeSlots = 0;
                        for (let i = 0; i < N; i++) { if (intSkills[i] < 20 && newDecimals[i] < 0.99) freeSlots++; }
                        if (freeSlots > 0) {
                            const add2 = subtleOverflow / freeSlots;
                            for (let i = 0; i < N; i++) { if (intSkills[i] < 20 && newDecimals[i] < 0.99) newDecimals[i] += add2; }
                        }
                    }
                } while (subtleOverflow > 0.0001 && ++passes < 20);

                const decSum = newDecimals.reduce((a, b) => a + b, 0);
                if (decSum > 0.001 && asiRemainder > 0) {
                    const scale = asiRemainder / decSum;
                    newDecimals = newDecimals.map((d, i) => intSkills[i] >= 20 ? 0 : d * scale);
                } else if (asiRemainder > 0) {
                    const nonMax = intSkills.filter(v => v < 20).length;
                    newDecimals = intSkills.map(v => v >= 20 ? 0 : asiRemainder / nonMax);
                }

                passes = 0;
                do {
                    overflow = 0; let freeCount = 0;
                    for (let i = 0; i < N; i++) {
                        if (intSkills[i] >= 20) { newDecimals[i] = 0; continue; }
                        if (newDecimals[i] > 0.99) { overflow += newDecimals[i] - 0.99; newDecimals[i] = 0.99; }
                        else if (newDecimals[i] < 0) { newDecimals[i] = 0; }
                        else if (newDecimals[i] < 0.99) freeCount++;
                    }
                    if (overflow > 0.0001 && freeCount > 0) {
                        const add = overflow / freeCount;
                        for (let i = 0; i < N; i++) { if (intSkills[i] < 20 && newDecimals[i] < 0.99) newDecimals[i] += add; }
                    }
                } while (overflow > 0.0001 && ++passes < 20);

            } else if (asi > 0) {
                const nonMax = intSkills.filter(v => v < 20).length;
                newDecimals = intSkills.map(v => v >= 20 ? 0 : (nonMax > 0 ? asiRemainder / nonMax : 0));
            } else {
                newDecimals = new Array(N).fill(0);
            }

            const newSkillsFull = intSkills.map((v, i) => v >= 20 ? 20 : v + (newDecimals[i] || 0));
            const diffSkills = curDbSkillsFull ? newSkillsFull.map((v, i) => v - curDbSkillsFull[i]) : null;

            /* --- R5 / REC per position --- */
            const allPositions = favpos.split(',').map(s => s.trim()).filter(Boolean);
            let R5 = null, REC = null, R5_DB = null;
            let bestPos = allPositions[0] || '';
            const r5ByPos = {};

            if (asi > 0) {
                let bestR5 = -Infinity;
                for (const pos of allPositions) {
                    const posIdx = TmLib.getPositionIndex(pos);
                    const r5v = TmLib.calculatePlayerR5(posIdx, newSkillsFull, asi, routine);
                    const recv = TmLib.calculatePlayerREC(posIdx, newSkillsFull, asi);
                    r5ByPos[pos] = { R5: r5v, REC: recv };
                    if (r5v > bestR5) { bestR5 = r5v; R5 = r5v; REC = recv; bestPos = pos; }
                }
                if (curDbSkillsFull) {
                    R5_DB = TmLib.calculatePlayerR5(TmLib.getPositionIndex(bestPos), curDbSkillsFull, asi, routine);
                }
            }

            results.push({
                pid: p.pid, name: p.name, number: p.number,
                ageYears: p.ageYears, ageMonths: p.ageMonths,
                position: favpos, isGK, asi, routine,
                TI: p.TI, TI_change: p.TI_change,
                intSkills, newDecimals, newSkillsFull,
                prevSkillsFull, curDbSkillsFull, diffSkills,
                improved: p.improved,
                R5, R5_DB, REC, r5ByPos, bestPos,
                asiRemainder, hadPrevData: !!prevDecimals
            });
        }

        /* --- Console output --- */
        console.log(`%c[Squad] --- Processed ${results.length} players ---`, 'font-weight:bold;color:#6cc040');

        const fv = v => v >= 20 ? '★' : v.toFixed(2);

        for (const r of results) {
            const SHORT = r.isGK ? NAMES_GK_SHORT : NAMES_OUT_SHORT;
            const N = r.isGK ? 11 : 14;
            const rows = [];

            for (let i = 0; i < N; i++) {
                const imp = r.improved.find(x => x.index === i);
                const marker = imp ? (imp.type === 'one_up' ? '↑+1' : '↑') : '';
                rows.push({
                    Skill: SHORT[i],
                    DB: r.curDbSkillsFull ? fv(r.curDbSkillsFull[i]) : '-',
                    New: fv(r.newSkillsFull[i]),
                    Diff: r.diffSkills
                        ? (Math.abs(r.diffSkills[i]) < 0.005 ? '' : (r.diffSkills[i] >= 0 ? '+' : '') + r.diffSkills[i].toFixed(2))
                        : '',
                    Train: marker
                });
            }

            const totalNew = r.newSkillsFull.reduce((s, v) => s + v, 0);
            const totalDb = r.curDbSkillsFull ? r.curDbSkillsFull.reduce((s, v) => s + v, 0) : null;
            rows.push({
                Skill: 'TOTAL',
                DB: totalDb != null ? totalDb.toFixed(2) : '-',
                New: totalNew.toFixed(2),
                Diff: totalDb != null ? ((totalNew - totalDb) >= 0 ? '+' : '') + (totalNew - totalDb).toFixed(2) : '',
                Train: ''
            });

            const posR5Str = Object.entries(r.r5ByPos).map(([pos, v]) => `${pos}:${v.R5.toFixed(1)}`).join(' ');
            console.log(
                `%c-- ${r.name} (#${r.number}) -- Age:${r.ageYears}.${String(r.ageMonths).padStart(2, '0')} | ${r.position} | ASI:${r.asi} | Rtn:${r.routine} | TI:${r.TI}(${r.TI_change >= 0 ? '+' : ''}${r.TI_change}) | Best:${r.bestPos} R5_DB:${r.R5_DB != null ? r.R5_DB.toFixed(2) : '?'} R5_New:${r.R5 != null ? r.R5.toFixed(2) : '?'} | R5[${posR5Str}] | REC:${r.REC != null ? r.REC.toFixed(2) : '?'} | Rem:${r.asiRemainder.toFixed(2)} | DB:${r.curDbSkillsFull ? '✓' : '✗'}`,
                'font-weight:bold;color:#fbbf24'
            );
            console.table(rows);
        }

        /* --- Sync to IndexedDB --- */
        loader.update(0, results.length, 'Syncing to DB...');
        const bar = document.getElementById('tmrc-loader-bar');
        if (bar) bar.style.width = '0%';

        let syncCount = 0;
        for (const r of results) {
            if (r.asi <= 0) { syncCount++; continue; }

            const ageKey = `${r.ageYears}.${r.ageMonths}`;
            let store = PlayerDB.get(r.pid);
            if (!store?._v) store = { _v: 1, lastSeen: Date.now(), records: {} };

            store.records[ageKey] = {
                SI: r.asi,
                REREC: r.REC,
                R5: r.R5,
                skills: r.newSkillsFull.map(v => Math.round(v * 100) / 100),
                routine: r.routine,
                locked: true
            };
            store.lastSeen = Date.now();
            if (!store.meta) store.meta = { name: r.name, pos: r.position, isGK: r.isGK };

            await PlayerDB.set(r.pid, store);
            syncCount++;

            const pct = Math.round((syncCount / results.length) * 100);
            if (bar) bar.style.width = pct + '%';
            const txt = document.getElementById('tmrc-loader-text');
            if (txt) txt.textContent = `Syncing ${syncCount}/${results.length} — ${r.name}`;
        }

        console.log(`%c[Squad] ✓ Synced ${syncCount} players to IndexedDB`, 'font-weight:bold;color:#6cc040');
        loader.done(syncCount);

        return results;
    };

    /* -----------------------------------------------------------
       INIT — wait for IndexedDB, then start
       ----------------------------------------------------------- */
    const runSquadSync = async () => {
        await ensureAllPlayersVisible();
        const parsed = parseSquadPage();
        if (!parsed?.length) { console.warn('[Squad] No players parsed from table'); return; }

        await processSquadPage(parsed);

        /* Watch for hash changes (toggle clicks) to re-process newly visible players */
        const processedPids = new Set(parsed.map(p => p.pid));
        let hashProcessing = false;
        window.addEventListener('hashchange', async () => {
            if (hashProcessing) return;
            hashProcessing = true;
            try {
                await new Promise(r => setTimeout(r, 600));
                const reParsed = parseSquadPage();
                if (!reParsed) { hashProcessing = false; return; }
                const newPlayers = reParsed.filter(p => !processedPids.has(p.pid));
                if (newPlayers.length > 0) {
                    console.log(`%c[Squad] Detected ${newPlayers.length} new players after toggle`, 'font-weight:bold;color:#38bdf8');
                    newPlayers.forEach(p => processedPids.add(p.pid));
                    await processSquadPage(newPlayers);
                }
            } catch (e) { console.error('[Squad] Re-process error:', e); }
            hashProcessing = false;
        });
    };

    PlayerDB.init().then(() => PlayerArchiveDB.init()).then(() => {
        runSquadSync().catch(e => console.error('[Squad] Squad sync error:', e));
    }).catch(e => {
        console.warn('[DB] IndexedDB init failed, falling back:', e);
        const parsed = parseSquadPage();
        if (parsed?.length) processSquadPage(parsed);
    });

})();



// ─── tm-squad.user.js ────────────────────────────────────────────


(function () {
    'use strict';

    /* ═══════════════════════════════════════════════════════════
       CONSTANTS
       ═══════════════════════════════════════════════════════════ */
    const PlayerDB = window.TmPlayerDB;
    const PlayerArchiveDB = window.TmPlayerArchiveDB;

    /* ═══════════════════════════════════════════════════════════
       DATA PROCESSING
       ═══════════════════════════════════════════════════════════ */
    let processed = false;
    let allPlayers = [];
    let bTeamPlayers = [];
    let bTeamFetched = false;
    const onSaleIds = new Set();

    const scanForSales = () => {
        document.querySelectorAll('img[src*="auction_hammer"]').forEach(img => {
            const tr = img.closest('tr');
            if (!tr) return;
            const link = tr.querySelector('a[href*="/players/"]');
            if (!link) return;
            const m = link.getAttribute('href').match(/\/players\/(\d+)/);
            if (m) onSaleIds.add(m[1]);
        });
    };

    // When syncPlayerStore finishes it fires tm:growthUpdated.
    // Update the player in-place from DB and re-render.
    window.addEventListener('tm:growthUpdated', e => {
        const pid = String(e.detail?.pid || '');
        if (!pid) return;
        const player = allPlayers.find(p => String(p.id) === pid)
            || bTeamPlayers.find(p => String(p.id) === pid);
        if (!player) return;
        const dbRec = window.TmPlayerDB?.get(pid)?.records?.[`${player.age}.${player.month}`];
        if (!dbRec || (dbRec.R5 == null && dbRec.REREC == null)) return;
        if (dbRec.R5 != null) player.r5 = dbRec.R5;
        if (dbRec.REREC != null) player.rec = dbRec.REREC;
        if (dbRec.routine != null) player.routine = dbRec.routine;
        player.fromDB = true;
        renderPanel();
    });

    const fetchBTeamInfo = clubId => {
        fetch(`/club/${clubId}/`)
            .then(r => r.text())
            .then(html => {
                const idMatch = html.match(/B-Team:\s*<\/strong>\s*<a\s+href="\/club\/(\d+)\//)
                    || html.match(/B-Team:[\s\S]*?\/club\/(\d+)\//);
                if (!idMatch) return;
                const bTeamId = idMatch[1];
                const nameMatch = html.match(/B-Team:\s*<\/strong>\s*<a[^>]*>([^<]+)<\/a>/)
                    || html.match(/B-Team:[\s\S]*?club_link='\d+'>([^<]+)<\/a>/);
                bTeamName = nameMatch ? nameMatch[1].trim() : 'B-Team';
                TmApi.fetchSquadRaw(bTeamId).then(data => {
                    const players = data?.post ? Object.values(data.post) || [] : [];
                    if (players.length) {
                        bTeamPlayers = players.map(p => ({ ...p, isBTeam: true }));
                        renderPanel();
                    }
                });
            })
            .catch(() => { });
    };

    /* ═══════════════════════════════════════════════════════════
       RENDERING
       ═══════════════════════════════════════════════════════════ */
    const renderPanel = () => {
        scanForSales();

        let panel = document.getElementById('tmsq-panel');
        if (panel) panel.remove();
        panel = document.createElement('div');
        panel.id = 'tmsq-panel';

        TmSquadTable.render(panel, [...allPlayers, ...bTeamPlayers], { onSaleIds });

        const target = document.querySelector('.column2_a');
        if (target) {
            target.innerHTML = '';
            target.appendChild(panel);
        } else {
            const fallback = document.querySelector('#middle_column') || document.body;
            fallback.insertBefore(panel, fallback.firstChild);
        }
        widenLayout();
    };

    /* ═══════════════════════════════════════════════════════════
       INITIALIZATION
       ═══════════════════════════════════════════════════════════ */
    // Remove column3_a and widen column2_a
    const widenLayout = () => {
        const col3 = document.querySelector('.column3_a');
        if (col3) col3.remove();
        const col2 = document.querySelector('.column2_a');
        if (col2) col2.style.width = '790px';
    };

    const tryFetch = () => {
        if (processed) return;
        const clubId = location.pathname.match(/\/club\/(\d+)/)?.[1];
        if (!clubId) return;

        const waitForJQ = setInterval(() => {
            if (typeof $ === 'undefined') return;
            clearInterval(waitForJQ);
            PlayerDB.init().then(() => {
                PlayerArchiveDB.init();
                TmApi.fetchSquadRaw(clubId).then(data => {
                    if (data?.post.length) {
                        allPlayers = data?.post;
                        processed = true;
                        renderPanel();

                        if (!bTeamFetched) {
                            bTeamFetched = true;
                            const clubId = location.pathname.match(/\/club\/(\d+)/)?.[1];
                            if (clubId) fetchBTeamInfo(clubId);
                        }
                    }
                });
            })
        }, 200);
    };

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', () => setTimeout(tryFetch, 800));
    } else {
        setTimeout(tryFetch, 800);
    }

})();



// ─── tm-league.user.js ───────────────────────────────────────────

// ==UserScript==
// @name         TM League Enhanced Panel
// @namespace    https://trophymanager.com
// @version      1
// @description  Enhanced league overview for TrophyManager: squad skill ratings, TOTR, standings, transfers, top scorers, and quick league switcher
// @match        https://trophymanager.com/league/*
// @grant        none
// @require      file://H:/projects/Moji/tmscripts/lib/tm-constants.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-position.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-utils.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-lib.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-playerdb.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-dbsync.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-services.js
// @require      file://H:/projects/Moji/tmscripts/components/shared/tm-ui.js
// @require      file://H:/projects/Moji/tmscripts/components/match/tm-match-utils.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-styles.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-panel.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-standings.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-fixtures.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-totr.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-stats.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-picker.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-skill-table.js
// @require      file://H:/projects/Moji/tmscripts/components/league/tm-league-rounds.js
// ==/UserScript==

(function () {
    'use strict';

    // ─── Constants ───────────────────────────────────────────────────────
    const STORAGE_KEY = 'TM_LEAGUE_LINEUP_NUM_ROUNDS';

    const SKILL_NAMES_FIELD = window.TmConst.SKILL_DEFS_OUT.map(d => d.label || d.key);
    const SKILL_NAMES_GK = window.TmConst.SKILL_DEFS_GK.map(d => d.label || d.key);

    const { REC_THRESHOLDS, R5_THRESHOLDS, AGE_THRESHOLDS } = window.TmConst;

    // ─── Squad fetching via TmApi (one call per club per run) ─────────────
    const squadCache = new Map(); // clubId → Promise<{post:{id:player}}>

    const fetchSquad = clubId => {
        if (!squadCache.has(clubId)) {
            squadCache.set(clubId, window.TmApi.fetchSquadRaw(clubId).then(data => {
                if (!data?.post) return { post: {} };
                if (Array.isArray(data.post)) {
                    const postObj = {};
                    data.post.forEach(p => { postObj[String(p.id)] = p; });
                    data.post = postObj;
                }
                return data;
            }).catch(() => ({ post: {} })));
        }
        return squadCache.get(clubId);
    };

    // ─── Per-player R5 resolution ─────────────────────────────────────────
    // squadPost is the full fetchSquad response: {post: {pid: normalizedPlayer}}.
    // Players in post are already normalized by fetchSquadRaw (r5/rec/positions/ageMonths present).
    // Tooltip fallback only for players no longer in the current squad (transferred), with a cache.
    const tooltipCache = new Map(); // pid → Promise<player|null>

    const getPlayerDataFromSquad = async (pid, squadPost, matchPos) => {

        let player = squadPost.post?.[String(pid)];
        if (!player) {
            if (!tooltipCache.has(pid)) {
                tooltipCache.set(pid, window.TmApi.fetchPlayerTooltip(pid)
                    .then(r => r?.player ?? null).catch(() => null));
            }
            player = await tooltipCache.get(pid);
        }
        if (!player) return { Age: 0, R5: 0, REC: 0, isGK: false, skills: [], routine: 0 };
        const posData = player.positions?.find(p => p.position?.toLowerCase() === matchPos);
        const r5 = Number(posData?.r5 ?? player.r5 ?? 0);
        const rec = Number(posData?.rec ?? player.rec ?? 0);
        return { Age: player.ageMonths, R5: r5, REC: rec, isGK: player.isGK, skills: player.skills, routine: player.routine };
    };

    // ─── Team statistics (average R5 of 11 starters) ─────────────────────
    const computeTeamStats = async (playerIds, lineup, squadPost) => {
        const starters = playerIds.filter(id => !lineup[id].position.includes('sub'));
        const players = await Promise.all(starters.map(async id => {
            const matchPos = lineup[id].position;
            const p = await getPlayerDataFromSquad(id, squadPost, matchPos);
            return { id, name: lineup[id].name || String(id), pos: matchPos, ...p };
        }));
        const totals = { Age: 0, REC: 0, R5: 0 };
        players.forEach(p => { totals.Age += p.Age; totals.REC += p.REC; totals.R5 += p.R5; });
        return { totals, players };
    };

    // Page type detection
    let pagePath = window.location.pathname;
    let isLeaguePage = /^\/league\//.test(pagePath);
    let lastInitPath = '';
    let leaguePollInterval = null;

    // ─── State ───────────────────────────────────────────────────────────
    let urlParts = pagePath.split('/').filter(Boolean);
    let leagueCountry = isLeaguePage ? urlParts[1] : null;
    let leagueDivision = isLeaguePage ? urlParts[2] : null;
    let leagueGroup = isLeaguePage ? (urlParts[3] || '1') : null;

    let numLastRounds = parseInt(localStorage.getItem(STORAGE_KEY)) || 5;
    let clubDatas = new Map();
    let clubMap = new Map();
    let clubPlayersMap = new Map(); // clubId → Map<playerId, {pos,R5,REC,Age}>
    let totalExpected = 0;
    let totalProcessed = 0;
    let analysisInterval = null;
    let skillData = [];
    let skillSortCol = 'R5';
    let skillSortAsc = false;

    // ─── Rounds state ────────────────────────────────────────────────────
    let allRounds = [];        // [{roundNum, date, matches}] sorted by date asc
    let currentRoundIdx = 0;   // index into allRounds
    let fixturesCache = null;  // raw fixtures response

    // ─── Team of the Round state ─────────────────────────────────────────
    const totrCache = {};      // date → parsed TOTR data
    let totrCurrentDate = null;
    // Correct league params (parsed from nav link, reliable on all subpages)
    let panelCountry = null, panelDivision = null, panelGroup = null;
    let panelLeagueName = '';

    // ─── Standings state ─────────────────────────────────────────────────
    let standingsRows = [];    // parsed from DOM #overall_table
    let liveZoneMap = {};      // rank → zone, built from live #overall_table (reused for history seasons)
    let formOffset = 0;        // 0=default: 5 recent played + 1 upcoming at pos 6; positive=older; negative=more upcoming
    let stdVenue = 'total';    // 'total' | 'home' | 'away'
    let stdFormN = 0;          // 0=All, 5, 10, 15, 20, 25, 30 – last-N-matches filter
    let displayedSeason = null; // null = live current, number = history mode
    let historyFixturesData = null; // null = live, {season, groups} = history mode
    let histFixTooltipCache = {};
    let histFixTooltipEl = null;
    let histFixTooltipTimer = null;
    let histFixTooltipHideTimer = null;

    // ─── Player stats state ────────────────────────────────────────────────
    let statsStatType = 'goals'; // goals | assists | productivity | rating | cards | man-of-the-match
    let statsTeamType = 0;       // 0 = Main team (tab0), 1 = Under 21 (tab1)
    let statsMode = 'players';   // 'players' | 'clubs'
    let statsClubStat = 'goals'; // goals | attendance | injuries | possession | cards
    let transfersView = 'bought'; // 'bought' | 'sold' | 'teams'
    let statsCache = {};         // keyed by `${mode}|${stat}|${season}|${teamIdx}`


    // --- Shared context: all components access state via window.TmLeagueCtx ---
    // Components read/write state through this object; closure vars are the backing store.
    // Getter/setter pairs keep component access in sync with main-script mutations.
    const ctx = window.TmLeagueCtx = { // eslint-disable-line no-unused-vars
        // ── League identity (set by tm-league.user.js; reset on navigation) ──
        get leagueCountry() { return leagueCountry; }, set leagueCountry(v) { leagueCountry = v; },
        get leagueDivision() { return leagueDivision; }, set leagueDivision(v) { leagueDivision = v; },
        get leagueGroup() { return leagueGroup; }, set leagueGroup(v) { leagueGroup = v; },
        // ── Panel state (set by tm-league-panel.js and shared components) ──
        get panelCountry() { return panelCountry; }, set panelCountry(v) { panelCountry = v; },
        get panelDivision() { return panelDivision; }, set panelDivision(v) { panelDivision = v; },
        get panelGroup() { return panelGroup; }, set panelGroup(v) { panelGroup = v; },
        get panelLeagueName() { return panelLeagueName; }, set panelLeagueName(v) { panelLeagueName = v; },
        // ── Rounds analysis (set by tm-league-rounds.js) ──
        get numLastRounds() { return numLastRounds; }, set numLastRounds(v) { numLastRounds = v; },
        get clubDatas() { return clubDatas; }, set clubDatas(v) { clubDatas = v; },
        get clubMap() { return clubMap; }, set clubMap(v) { clubMap = v; },
        get clubPlayersMap() { return clubPlayersMap; }, set clubPlayersMap(v) { clubPlayersMap = v; },
        get totalExpected() { return totalExpected; }, set totalExpected(v) { totalExpected = v; },
        get totalProcessed() { return totalProcessed; }, set totalProcessed(v) { totalProcessed = v; },
        get analysisInterval() { return analysisInterval; }, set analysisInterval(v) { analysisInterval = v; },
        // ── Skill table (set by tm-league-skill-table.js) ──
        get skillData() { return skillData; }, set skillData(v) { skillData = v; },
        get skillSortCol() { return skillSortCol; }, set skillSortCol(v) { skillSortCol = v; },
        get skillSortAsc() { return skillSortAsc; }, set skillSortAsc(v) { skillSortAsc = v; },
        // ── Rounds list (set by tm-league-rounds.js) ──
        get allRounds() { return allRounds; }, set allRounds(v) { allRounds = v; },
        get currentRoundIdx() { return currentRoundIdx; }, set currentRoundIdx(v) { currentRoundIdx = v; },
        get fixturesCache() { return fixturesCache; }, set fixturesCache(v) { fixturesCache = v; },
        // ── Team of the Round (set by tm-league-totr.js) ──
        get totrCache() { return totrCache; },               // only mutated, not reassigned
        get totrCurrentDate() { return totrCurrentDate; }, set totrCurrentDate(v) { totrCurrentDate = v; },
        // ── Standings (set by tm-league-standings.js) ──
        get standingsRows() { return standingsRows; }, set standingsRows(v) { standingsRows = v; },
        get liveZoneMap() { return liveZoneMap; }, set liveZoneMap(v) { liveZoneMap = v; },
        get formOffset() { return formOffset; }, set formOffset(v) { formOffset = v; },
        get stdVenue() { return stdVenue; }, set stdVenue(v) { stdVenue = v; },
        get stdFormN() { return stdFormN; }, set stdFormN(v) { stdFormN = v; },
        // ── History fixtures (set by tm-league-fixtures.js; displayedSeason also by tm-league-panel.js) ──
        get displayedSeason() { return displayedSeason; }, set displayedSeason(v) { displayedSeason = v; },
        get historyFixturesData() { return historyFixturesData; }, set historyFixturesData(v) { historyFixturesData = v; },
        get histFixTooltipCache() { return histFixTooltipCache; },     // only mutated
        get histFixTooltipEl() { return histFixTooltipEl; }, set histFixTooltipEl(v) { histFixTooltipEl = v; },
        get histFixTooltipTimer() { return histFixTooltipTimer; }, set histFixTooltipTimer(v) { histFixTooltipTimer = v; },
        get histFixTooltipHideTimer() { return histFixTooltipHideTimer; }, set histFixTooltipHideTimer(v) { histFixTooltipHideTimer = v; },
        // ── Stats & transfers (set by tm-league-stats.js) ──
        get statsStatType() { return statsStatType; }, set statsStatType(v) { statsStatType = v; },
        get statsTeamType() { return statsTeamType; }, set statsTeamType(v) { statsTeamType = v; },
        get statsMode() { return statsMode; }, set statsMode(v) { statsMode = v; },
        get statsClubStat() { return statsClubStat; }, set statsClubStat(v) { statsClubStat = v; },
        get transfersView() { return transfersView; }, set transfersView(v) { transfersView = v; },
        get statsCache() { return statsCache; },              // only mutated
        // Functions — lazy getters (defined later in IIFE; called only from events/timers)
        get fetchSquad() { return fetchSquad; },
        get computeTeamStats() { return computeTeamStats; },
        get updateProgress() { return updateProgress; },
        get sortData() { return sortData; },
        // Constants — shared display config, injected from main scope
        getColor: window.TmUtils.getColor, STORAGE_KEY, SKILL_NAMES_FIELD, SKILL_NAMES_GK, REC_THRESHOLDS, R5_THRESHOLDS, AGE_THRESHOLDS,
        // ── Coordinated state transitions ─────────────────────────────────────────────────────
        // Use these instead of direct property writes when multiple fields must change together.
        // They prevent the partial-update bugs that arise when callers forget a related field.
        // ───────────────────────────────────────────────────────────────────────
        /** Set the three panel league params (+ optional name) atomically. */
        setPanelLeague(country, division, group, name) {
            panelCountry = country; panelDivision = division; panelGroup = group;
            if (name != null) panelLeagueName = name;
        },
        /** Switch back to live (current-season) standings view. Clears history-mode state. */
        resetToLive() {
            displayedSeason = null; historyFixturesData = null;
            standingsRows = []; formOffset = 0;
        },
        /** Switch to a history season. Clears stale fixtures data so fetchers refill it. */
        setDisplayedSeason(s) {
            displayedSeason = s; historyFixturesData = null;
        },
        /** Set the rounds list and active index atomically (avoids indexing stale allRounds). */
        setRoundsData(rounds, idx) {
            allRounds = rounds; currentRoundIdx = idx;
        },
        /** Reset analysis accumulation state. Call before kicking off a new analysis pass. */
        beginAnalysis() {
            clubDatas.clear(); clubPlayersMap.clear();
            totalExpected = 0; totalProcessed = 0;
        },
    };
    // ─── UI helpers ──────────────────────────────────────────────────────
    const updateProgress = text => {
        const el = document.getElementById('tm_script_progress');
        if (el) el.textContent = text;
    };

    const sortData = (data, col, asc) => {
        data.sort((a, b) => {
            if (col === 'name') return asc ? a.name.localeCompare(b.name) : b.name.localeCompare(a.name);
            return asc ? a[col] - b[col] : b[col] - a[col];
        });
    };

    const patchFeedBox = () => {
        try {
            const feedBox = $('#tabfeed').closest('.box');
            if (!feedBox.length) return;
            feedBox.find('.box_head').removeClass('box_head').addClass('tsa-feed-head');
            feedBox.find('.tabs_outer').removeClass('tabs_outer').addClass('tsa-feed-tabs-outer');
            feedBox.find('.tabs_new').removeClass('tabs_new').addClass('tsa-feed-tabs');
            feedBox.find('.tabs_content').removeClass('tabs_content').addClass('tsa-feed-content');
        } catch (e) { }
    };

    const injectStyles = () => window.TmLeagueStyles.inject();

    const cleanupPage = () => {
        if (leaguePollInterval) { clearInterval(leaguePollInterval); leaguePollInterval = null; }
        if (analysisInterval) { clearInterval(analysisInterval); analysisInterval = null; }
        allRounds = [];
        currentRoundIdx = 0;
        fixturesCache = null;
        totrCurrentDate = null;
        Object.keys(totrCache).forEach(k => delete totrCache[k]);
        panelLeagueName = '';
        clubDatas = new Map();
        clubMap = new Map();
        clubPlayersMap = new Map();
        squadCache.clear();
        tooltipCache.clear();
        totalExpected = 0;
        totalProcessed = 0;
        skillData = [];
        standingsRows = [];
        formOffset = 0;
        const navTabs = document.getElementById('tsa-nav-tabs');
        if (navTabs) navTabs.remove();
        const sp = document.getElementById('tsa-standings-panel');
        if (sp) sp.remove();
        const nativeTable = document.getElementById('overall_table');
        if (nativeTable) {
            const wrapper = nativeTable.closest('.box') || nativeTable.parentElement;
            if (wrapper) wrapper.style.display = '';
        }
    };

    const initForCurrentPage = () => {
        const path = window.location.pathname;
        if (path === lastInitPath) return;
        lastInitPath = path;
        pagePath = path;
        isLeaguePage = /^\/league\//.test(path);
        const urlParts = path.split('/').filter(Boolean);
        leagueCountry = isLeaguePage ? urlParts[1] : null;
        leagueDivision = isLeaguePage ? urlParts[2] : null;
        leagueGroup = isLeaguePage ? (urlParts[3] || '1') : null;
        cleanupPage();
        injectStyles();
        patchFeedBox();

        // Remove TM's default Rounds widget and ad placeholder
        try { $('.banner_placeholder.rectangle')[0].parentNode.removeChild($('.banner_placeholder.rectangle')[0]); } catch (e) { }
        try { $('.column3_a .box').has('h2').filter(function () { return $(this).find('h2').text().trim().toUpperCase() === 'ROUNDS'; }).remove(); } catch (e) { }

        const initUI = () => {
            const clubLinks = $('#overall_table td a[club_link]');
            if (!clubLinks.length) return;
            clearInterval(leaguePollInterval);
            leaguePollInterval = null;

            $('#overall_table td').each(function () {
                const id = $(this).children('a').attr('club_link');
                if (id) clubMap.set(id, $(this).children('a')[0].innerHTML);
            });

            // Inject our custom standings panel & initial render (form added after fixtures load)
            window.TmLeaguePanel.injectStandingsPanel();
            window.TmLeagueStandings.buildStandingsFromDOM();
            window.TmLeagueStandings.renderLeagueTable();

            $(".column3_a").append(`
                <div class="tmu-card" id="rnd-panel">
                    <div class="tmu-card-head rnd-nav">
                        <button id="rnd-prev" class="rnd-nav-btn" title="Previous round"><svg viewBox="0 0 24 24"><path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/></svg></button>
                        <span class="rnd-title" id="rnd-title">Round —</span>
                        <button id="rnd-next" class="rnd-nav-btn" title="Next round"><svg viewBox="0 0 24 24"><path d="M8.59 16.59L10 18l6-6-6-6-1.41 1.41L13.17 12z"/></svg></button>
                    </div>
                    <div id="rnd-content"></div>
                </div>
            `);

            $(".column3_a").append(`
                <div class="tmu-card mt-2">
                    <div class="tmu-card-head">Squad Analysis</div>
                    <div class="tsa-controls">
                        <span>Last</span>
                        <input id="tm_script_num_matches" type="number" class="tsa-input"
                            value="${numLastRounds}" min="1" max="34">
                        <span>rounds</span>
                        <button id="tm_script_analyze_btn" class="tsa-btn">Analyze</button>
                        <span id="tm_script_progress" class="tsa-progress"></span>
                    </div>
                    <div id="tsa-content"></div>
                </div>
            `);

            document.getElementById('tm_script_analyze_btn').addEventListener('click', () => {
                const n = parseInt($('#tm_script_num_matches').val()) || 5;
                localStorage.setItem(STORAGE_KEY, n);
                window.TmLeagueRounds.startAnalysis(n);
            });

            document.getElementById('rnd-prev').addEventListener('click', () => {
                if (currentRoundIdx > 0) { currentRoundIdx--; window.TmLeagueRounds.renderRound(); }
            });
            document.getElementById('rnd-next').addEventListener('click', () => {
                if (currentRoundIdx < allRounds.length - 1) { currentRoundIdx++; window.TmLeagueRounds.renderRound(); }
            });

            window.TmLeagueRounds.startAnalysis(numLastRounds);
        };

        leaguePollInterval = setInterval(initUI, 500);
        initUI();
    };

    window.TmPlayerDB.init().catch(e => console.warn('[League] TmPlayerDB init failed:', e));
    setInterval(initForCurrentPage, 500);
    initForCurrentPage();
})();



// ─── tm-stats.user.js ────────────────────────────────────────────


(function () {
    'use strict';

    // ─── Extract club ID from URL ────────────────────────────────────────
    const urlMatch = location.pathname.match(/\/statistics\/club\/(\d+)/);
    if (!urlMatch) return;
    const CLUB_ID = urlMatch[1];


    // ─── State ───────────────────────────────────────────────────────────
    let allMatchData = [];       // Array of processed match data objects
    let playerAgg = {};          // playerId → aggregated stats
    let teamAggFor = {};         // Our attacking styles (for)
    let teamAggAgainst = {};     // Opponent attacking styles (against)
    let teamOverall = {};        // Overall match stats (shots, cards, etc.)
    let lastFilteredMatches = []; // Filtered match list (after all filters)
    let activeTab = 'player';
    let activeFilter = 'total';  // total | average | per90
    let activeTeamFilter = 'total'; // total | average  (team tab)
    let activeMatchType = 'all'; // all | league | friendly | cup | fl
    let lastAggKey = null; // track when aggregation needs refresh
    // Multi-select tactic filters (null = all selected)
    let filterOurFormation = null;   // Set or null
    let filterOurStyle = null;
    let filterOurMentality = null;
    let filterOppFormation = null;
    let filterOppStyle = null;
    let filterOppMentality = null;
    let activePlayerSubTab = 'basic'; // basic | attacking | defending
    let loadingComplete = false;
    let matchCount = { total: 0, loaded: 0 };

    // ─── Collect played matches from fixtures ────────────────────────────
    const getPlayedMatches = (fixturesData) => {
        const matches = [];
        Object.values(fixturesData).forEach(month => {
            if (!month.matches) return;
            month.matches.forEach(m => {
                if (m.result && m.result !== 'x-x') {
                    matches.push({
                        id: m.id,
                        date: m.date,
                        matchtype: m.matchtype,
                        matchtype_name: m.matchtype_sort || m.matchtype_name,
                        hometeam: String(m.hometeam),
                        awayteam: String(m.awayteam),
                        hometeam_name: m.hometeam_name,
                        awayteam_name: m.awayteam_name,
                        result: m.result,
                        isHome: String(m.hometeam) === CLUB_ID,
                    });
                }
            });
        });
        return matches;
    };

    // ─── Aggregate all match data (only when filters change) ──────────
    const getAggKey = () => JSON.stringify([activeMatchType,
        filterOurFormation ? [...filterOurFormation] : null,
        filterOurStyle ? [...filterOurStyle] : null,
        filterOurMentality ? [...filterOurMentality] : null,
        filterOppFormation ? [...filterOppFormation] : null,
        filterOppStyle ? [...filterOppStyle] : null,
        filterOppMentality ? [...filterOppMentality] : null]);
    const aggregateIfNeeded = () => {
        const key = getAggKey();
        if (lastAggKey === key) return;
        const result = TmStatsAggregator.aggregate(allMatchData, {
            activeMatchType,
            filterOurFormation, filterOurStyle, filterOurMentality,
            filterOppFormation, filterOppStyle, filterOppMentality,
        });
        playerAgg = result.playerAgg;
        teamAggFor = result.teamAggFor;
        teamAggAgainst = result.teamAggAgainst;
        teamOverall = result.teamOverall;
        lastFilteredMatches = result.lastFilteredMatches;
        lastAggKey = key;
    };

    // ─── Render functions ────────────────────────────────────────────────

    // ─── Collect unique tactic values with cascading filters ────────────
    // For each filter field, show only values that exist in matches passing
    // all OTHER active filters (so options narrow as you select).
    // ─── Shared match type filter buttons ────────────────────────────────
    const MATCH_TYPES = [
        { key: 'all', label: 'All' },
        { key: 'league', label: 'League' },
        { key: 'friendly', label: 'Friendly' },
        { key: 'fl', label: 'FL' },
        { key: 'cup', label: 'Cup' },
    ];

    const renderMatchTypeButtons = () => {
        let html = '<div class="tsa-match-filters">';
        MATCH_TYPES.forEach(mt => {
            const count = mt.key === 'all' ? allMatchData.length : allMatchData.filter(m => m.matchType === mt.key).length;
            if (count === 0 && mt.key !== 'all') return;
            const wdl = getWDL(mt.key);
            html += `<div class="tsa-mf-btn${activeMatchType === mt.key ? ' active' : ''}" data-mtype="${mt.key}">${mt.label} (${count}) <span class="tsa-mf-wdl">${wdl.w}W-${wdl.d}D-${wdl.l}L</span></div>`;
        });
        html += '</div>';
        return html;
    };

    // ─── Get W-D-L for a match type filter ────────────────────────────────
    const getWDL = (matchTypeKey) => {
        const matches = matchTypeKey === 'all' ? allMatchData : allMatchData.filter(m => m.matchType === matchTypeKey);
        let w = 0, d = 0, l = 0;
        matches.forEach(md => {
            const [h, a] = md.matchInfo.result.split('-').map(Number);
            const our = md.isHome ? h : a;
            const opp = md.isHome ? a : h;
            if (our > opp) w++; else if (our === opp) d++; else l++;
        });
        return { w, d, l };
    };

    const renderPlayerTab = () => TmStatsPlayerTab.render({
        aggregateIfNeeded,
        renderMatchTypeButtons,
        getTeamOverall: () => teamOverall,
        getPlayerAgg: () => playerAgg,
        getActiveFilter: () => activeFilter,
        setActiveFilter: v => { activeFilter = v; },
        getActiveMatchType: () => activeMatchType,
        setActiveMatchType: v => { activeMatchType = v; },
        getActivePlayerSubTab: () => activePlayerSubTab,
        setActivePlayerSubTab: v => { activePlayerSubTab = v; },
        setFilterOurFormation: v => { filterOurFormation = v; },
        setFilterOurStyle: v => { filterOurStyle = v; },
        setFilterOurMentality: v => { filterOurMentality = v; },
        setFilterOppFormation: v => { filterOppFormation = v; },
        setFilterOppStyle: v => { filterOppStyle = v; },
        setFilterOppMentality: v => { filterOppMentality = v; },
        rerender: () => renderPlayerTab(),
    });

    const renderTeamTab = () => TmStatsTeamTab.render({
        aggregateIfNeeded,
        renderMatchTypeButtons,
        getTeamOverall: () => teamOverall,
        getTeamAggFor: () => teamAggFor,
        getTeamAggAgainst: () => teamAggAgainst,
        getLastFilteredMatches: () => lastFilteredMatches,
        getAllMatchData: () => allMatchData,
        getActiveTeamFilter: () => activeTeamFilter,
        setActiveTeamFilter: v => { activeTeamFilter = v; },
        getActiveMatchType: () => activeMatchType,
        setActiveMatchType: v => { activeMatchType = v; },
        getFilterOurFormation: () => filterOurFormation,
        setFilterOurFormation: v => { filterOurFormation = v; },
        getFilterOurStyle: () => filterOurStyle,
        setFilterOurStyle: v => { filterOurStyle = v; },
        getFilterOurMentality: () => filterOurMentality,
        setFilterOurMentality: v => { filterOurMentality = v; },
        getFilterOppFormation: () => filterOppFormation,
        setFilterOppFormation: v => { filterOppFormation = v; },
        getFilterOppStyle: () => filterOppStyle,
        setFilterOppStyle: v => { filterOppStyle = v; },
        getFilterOppMentality: () => filterOppMentality,
        setFilterOppMentality: v => { filterOppMentality = v; },
        setLastAggKey: v => { lastAggKey = v; },
        rerender: () => renderTeamTab(),
    });

    const renderCurrentTab = () => {
        if (activeTab === 'player') renderPlayerTab();
        else renderTeamTab();
    };

    // ─── Build the main container ────────────────────────────────────────
    const buildUI = () => {
        const container = document.querySelector('.column2_a');
        if (!container) return;

        // Clear existing content
        container.innerHTML = '';

        const wrap = document.createElement('div');
        wrap.className = 'tsa-wrap';
        wrap.innerHTML = `
            <div class="tsa-header">
                <div class="tsa-title">Season Match Analysis</div>
                <div class="tsa-subtitle" id="tsa-subtitle">Loading...</div>
            </div>
            <div class="tsa-tabs">
                <div class="tsa-tab${activeTab === 'player' ? ' active' : ''}" data-tab="player">Player</div>
                <div class="tsa-tab${activeTab === 'team' ? ' active' : ''}" data-tab="team">Team</div>
            </div>
            <div class="tsa-body" id="tsa-body">
                ${TmUI.loading('Loading match data…')}
                <div class="tsa-progress" id="tsa-progress">0 / 0 matches</div>
            </div>
        `;

        container.appendChild(wrap);

        // Tab click handling
        wrap.querySelectorAll('.tsa-tab').forEach(tab => {
            tab.addEventListener('click', () => {
                if (!loadingComplete) return;
                wrap.querySelectorAll('.tsa-tab').forEach(t => t.classList.remove('active'));
                tab.classList.add('active');
                activeTab = tab.dataset.tab;
                renderCurrentTab();
            });
        });
    };

    const updateProgress = () => {
        const el = document.getElementById('tsa-progress');
        if (el) el.textContent = `${matchCount.loaded} / ${matchCount.total} matches`;
    };

    // ─── Main initialization ─────────────────────────────────────────────
    const init = async () => {
        TmStatsStyles.inject();
        buildUI();

        try {
            // 1. Fetch fixtures (TmMatchCacheDB opens lazily on first fetchMatchCached call)
            const fixtures = await window.TmApi.fetchClubFixtures(CLUB_ID);
            if (!fixtures) throw new Error('Failed to fetch fixtures');
            const playedMatches = getPlayedMatches(fixtures);
            matchCount.total = playedMatches.length;
            matchCount.loaded = 0;
            updateProgress();

            // Prune stale entries from previous seasons (fire-and-forget)
            window.TmMatchCacheDB.pruneExcept(playedMatches.map(m => m.id));

            // 2. Fetch each match in batches of 3 — served from IndexedDB cache after first visit
            const BATCH_SIZE = 3;
            for (let i = 0; i < playedMatches.length; i += BATCH_SIZE) {
                const batch = playedMatches.slice(i, i + BATCH_SIZE);
                const results = await Promise.all(
                    batch.map(async (matchInfo) => {
                        try {
                            const mData = await TmApi.fetchMatchCached(matchInfo.id);
                            if (!mData) throw new Error('null response');
                            return TmStatsMatchProcessor.process(matchInfo, mData, CLUB_ID);
                        } catch (err) {
                            console.warn(`Failed to load match ${matchInfo.id}:`, err);
                            return null;
                        }
                    })
                );
                results.forEach(r => { if (r) allMatchData.push(r); });
                matchCount.loaded += batch.length;
                updateProgress();
            }

            // 3. Done loading
            loadingComplete = true;
            lastAggKey = null; // force first aggregation

            // Get club name from first match data if available
            if (allMatchData.length > 0) {
                const firstMatch = allMatchData[0];
                const clubName = firstMatch.matchInfo.isHome
                    ? firstMatch.matchInfo.hometeam_name
                    : firstMatch.matchInfo.awayteam_name;
                const subtitle = document.querySelector('.tsa-subtitle');
                if (subtitle) subtitle.textContent = `${clubName} — ${allMatchData.length} matches analyzed`;
            }

            renderCurrentTab();

        } catch (err) {
            console.error('TM Season Analysis error:', err);
            const body = document.getElementById('tsa-body');
            if (body) body.innerHTML = TmUI.error(`Error loading data: ${err.message}`);
        }
    };

    // Wait for jQuery and page load
    const waitForReady = () => {
        if (typeof $ !== 'undefined' && document.querySelector('.column2_a')) {
            init();
        } else {
            setTimeout(waitForReady, 500);
        }
    };

    waitForReady();
})();



// ─── tm-history.user.js ──────────────────────────────────────────

// ==UserScript==
// @name         TM Club History Enhanced
// @namespace    https://trophymanager.com
// @version      1
// @description  Enhanced club history page with tabbed interface for Records, Transfers, Matches, and League
// @match        https://trophymanager.com/history/club/*
// @grant        none
// @require      file://H:/projects/Moji/tmscripts/lib/tm-constants.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-position.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-utils.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-lib.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-playerdb.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-dbsync.js
// @require      file://H:/projects/Moji/tmscripts/lib/tm-services.js
// @require      file://H:/projects/Moji/tmscripts/components/shared/tm-ui.js
// @require      file://H:/projects/Moji/tmscripts/components/history/tm-history-styles.js
// @require      file://H:/projects/Moji/tmscripts/components/history/tm-history-helpers.js
// @require      file://H:/projects/Moji/tmscripts/components/history/tm-history-records.js
// @require      file://H:/projects/Moji/tmscripts/components/history/tm-history-transfers.js
// @require      file://H:/projects/Moji/tmscripts/components/history/tm-history-matches.js
// @require      file://H:/projects/Moji/tmscripts/components/history/tm-history-league.js
// ==/UserScript==

(function () {
    'use strict';

    const $ = window.jQuery;
    if (!$) return;

    const clubId = $('#club_id').val() || location.pathname.split('/').filter(Boolean)[3];
    if (!clubId) return;

    const seasons = [];
    $('#stats_season option').each(function () {
        const v = $(this).val();
        if (v) seasons.push({ id: v, label: $(this).text().trim() });
    });
    if (!seasons.length) return;

    const clubName = $('.box_sub_header .large strong a').first().text().trim() || 'Club';

    /* ───────── state ───────── */
    let activeTab = 'records';

    /* ───────── CSS ───────── */
    window.TmHistoryStyles.inject();

    /* =========================================================
       BUILD UI
       ========================================================= */
    function buildUI() {
        const boxBody = $('.column2_a .box_body');
        if (!boxBody.length) return;

        const hdr = boxBody.find('.box_sub_header').first();
        const hdrHtml = hdr.length ? hdr[0].outerHTML : '';

        boxBody.html(
            '<div class="box_shadow"></div>' +
            hdrHtml +
            '<div class="tmh-outer tmu-card">' +
            '<div class="tmh-tabs">' +
            '<div class="tmh-tab active" data-t="records">Records</div>' +
            '<div class="tmh-tab" data-t="transfers">Transfers</div>' +
            '<div class="tmh-tab" data-t="matches">Matches</div>' +
            '<div class="tmh-tab" data-t="league">League</div>' +
            '</div>' +
            '<div class="tmh-wrap" id="tmh-wrap"></div>' +
            '</div>'
        );

        boxBody.on('click', '.tmh-tab', function () {
            const t = $(this).data('t');
            if (t === activeTab) return;
            boxBody.find('.tmh-tab').removeClass('active');
            $(this).addClass('active');
            activeTab = t;
            render();
        });

        render();
    }

    function render() {
        const el = $('#tmh-wrap');
        const ctx = { clubId, seasons, clubName };
        switch (activeTab) {
            case 'records': window.TmHistoryRecords.render(el, ctx); break;
            case 'transfers': window.TmHistoryTransfers.render(el, ctx); break;
            case 'matches': window.TmHistoryMatches.render(el, ctx); break;
            case 'league': window.TmHistoryLeague.render(el, ctx); break;
        }
    }

    /* =========================================================
       INIT
       ========================================================= */
    $(document).ready(function () {
        setTimeout(buildUI, 400);
    });

})();



// ─── tm-shortlist.user.js ────────────────────────────────────────


(function () {
    'use strict';

    if (!/^\/shortlist\/?$/.test(location.pathname)) return;

    const FIELD_LABELS = window.TmConst.SKILL_LABELS_OUT;
    const GK_LABELS = window.TmConst.SKILL_LABELS_GK;

    /* Page data lookup — timeleft/bid fields only available from the shortlist page */
    const PAGE_DATA = {};
    if (Array.isArray(window.players_ar)) {
        for (const p of window.players_ar) {
            PAGE_DATA[String(p.id)] = {
                timeleft: parseInt(p.timeleft) || 0,
                timeleft_string: p.timeleft_string || null,
                curbid: p.curbid || null,
                next_bid: parseInt(p.next_bid) || 0,
                bid_level: parseInt(p.bid) || 0,
                txt: p.txt || '',
                ban: p.ban || '0',
                inj: p.inj != null ? String(p.inj) : null,
                locked: typeof p.status === 'string' && p.status.includes('status_unknown'),
                retire: p.retire || '0',
                no: parseInt(p.no) || 0,
                wage: parseInt(p.wage) || 0,
                club: p.club || '0',
            };
        }
    }


    //    ═════════════════════════════════════════════════════════ */
    let allPlayers = [];
    let sortCol = 'r5', sortDir = -1;
    let fPos = new Set(), fSide = new Set();
    let fAgeMin = 0, fAgeMax = 99;
    let fR5Min = '', fR5Max = '', fRecMin = '', fRecMax = '', fTiMin = '', fTiMax = '';
    let shortlistLoading = true;
    let loadProgress = null;       // { done, total } during any fetch
    let loadMoreState = null;      // null | 'loading' | 'done'
    let nextStart = 0;             // offset for next shortlist page fetch
    let totalKnown = 0;            // total IDs discovered across all pages
    let activeTab = 'shortlist';
    let indexedPlayers = null;
    let indexedLoading = false;
    let ixSortCol = 'r5', ixSortDir = -1;
    let ixPage = 0, slPage = 0;
    const IX_PAGE_SIZE = 50, SL_PAGE_SIZE = 50;

    /* ═════════════════════════════════════════════════════════
       INDEXED TAB
       ═════════════════════════════════════════════════════════ */
    function dbRecordToPlayer(pid, dbStore) {
        if (!dbStore || !dbStore.records) return null;
        const keys = Object.keys(dbStore.records).sort((a, b) => {
            const [ay, am] = a.split('.').map(Number);
            const [by, bm] = b.split('.').map(Number);
            return (ay * 12 + am) - (by * 12 + bm);
        });
        if (!keys.length) return null;

        const lastKey = keys[keys.length - 1];
        const [ky, km] = lastKey.split('.').map(Number);
        const weeksSince = (Date.now() - (dbStore.lastSeen || 0)) / 604800000;
        const addMonths = Math.floor(weeksSince);
        const totalM = km + addMonths;
        const newYears = ky + Math.floor(totalM / 12);
        const newMonths = totalM % 12;

        const dbRec = dbStore.records[lastKey] || {};
        const meta = dbStore.meta || {};
        const isGK = !!meta.isGK;
        const favPos = meta.pos || 'mc';
        const skills = (dbRec.skills || []).map(Number);
        const asi = dbRec.SI || 0;
        const routine = dbRec.routine || 0;

        const posKeys = String(favPos).split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
        const positions = posKeys.map(key => {
            const posData = window.TmConst.POSITION_MAP[key] || { position: key, id: 0, ordering: 9, color: '#aaa' };
            if (asi > 0 && skills.length) {
                const fakePlayer = { skills, asi, routine, isGK };
                return { ...posData, r5: parseFloat(window.TmLib.calculatePlayerR5(posData, fakePlayer)) || 0, rec: parseFloat(window.TmLib.calculatePlayerREC(posData, fakePlayer)) || 0 };
            }
            return { ...posData, r5: 0, rec: 0 };
        });
        if (!positions.length) positions.push({ position: 'dc', id: 0, ordering: 0, color: '#60a5fa', r5: 0, rec: 0 });
        const r5 = Math.max(...positions.map(p => p.r5), 0);
        const rec = Math.max(...positions.map(p => p.rec), 0);
        const ti = dbRec.TI != null ? dbRec.TI : null;

        return {
            id: String(pid),
            name: meta.name || '',
            country: meta.country || '',
            favposition: favPos,
            positions, isGK,
            age: newYears,
            months: newMonths,
            asi, r5, rec: Number(rec), ti,
            routine, wage: 0,
            skills,
            labels: isGK ? GK_LABELS : FIELD_LABELS,
            lastSeen: dbStore.lastSeen || 0,
            stale: weeksSince >= 1,
        };
    }

    async function loadIndexedTab() {
        if (indexedLoading) return;
        indexedLoading = true;
        await window.TmPlayerDB.init();
        indexedPlayers = window.TmPlayerDB.allPids()
            .map(pid => dbRecordToPlayer(pid, window.TmPlayerDB.get(pid)))
            .filter(Boolean);
        indexedLoading = false;
        renderPanel();
    }

    /* ═════════════════════════════════════════════════════════
       FETCH MORE  — load subsequent shortlist pages
       ═════════════════════════════════════════════════════════ */
    async function fetchMore() {
        if (loadMoreState === 'loading' || loadMoreState === 'done') return;
        loadMoreState = 'loading';
        renderPanel();

        try {
            const pageData = await window.TmApi.fetchShortlistPage(nextStart);

            if (!pageData.length) {
                loadMoreState = 'done';
                renderPanel();
                return;
            }

            // Merge PAGE_DATA for any new entries
            for (const p of pageData) {
                const key = String(p.id);
                if (!PAGE_DATA[key]) {
                    PAGE_DATA[key] = {
                        timeleft: parseInt(p.timeleft) || 0,
                        timeleft_string: p.timeleft_string || null,
                        curbid: p.curbid || null,
                        next_bid: parseInt(p.next_bid) || 0,
                        bid_level: parseInt(p.bid) || 0,
                        txt: p.txt || '',
                        ban: p.ban || '0',
                        inj: p.inj != null ? String(p.inj) : null,
                        locked: typeof p.status === 'string' && p.status.includes('status_unknown'),
                        retire: p.retire || '0',
                        no: parseInt(p.no) || 0,
                        wage: parseInt(p.wage) || 0,
                        club: p.club || '0',
                    };
                }
            }

            const existingIds = new Set(allPlayers.map(p => String(p.id)));
            const newIds = pageData.map(p => String(p.id)).filter(id => !existingIds.has(id));

            if (!newIds.length) {
                loadMoreState = 'done';
                renderPanel();
                return;
            }

            nextStart += pageData.length;
            totalKnown += newIds.length;

            // Pre-fill new IDs from DB
            for (const pid of newIds) {
                const dbStore = window.TmPlayerDB.get(pid);
                if (dbStore) {
                    const p = dbRecordToPlayer(pid, dbStore);
                    if (p) {
                        Object.assign(p, PAGE_DATA[String(pid)] || {});
                        p.pending = true;
                        allPlayers.push(p);
                    }
                }
            }
            loadProgress = { done: allPlayers.filter(pl => !pl.pending).length, total: totalKnown };
            renderPanel();

            for (const pid of newIds) {
                try {
                    const data = await window.TmApi.fetchPlayerTooltip(pid);
                    const p = data?.player;
                    if (p) {
                        Object.assign(p, PAGE_DATA[String(pid)] || {});
                        const idx = allPlayers.findIndex(pl => pl.id === String(pid));
                        if (idx !== -1) allPlayers[idx] = p;
                        else allPlayers.push(p);
                    }
                } catch (e) {
                    console.warn('[TM Shortlist] fetchMore tooltip failed', pid, e);
                    const stub = allPlayers.find(pl => pl.id === String(pid));
                    if (stub) stub.pending = false;
                }
                loadProgress = { done: allPlayers.filter(pl => !pl.pending).length, total: totalKnown };
                renderPanel();
            }

            // If the page returned fewer entries than a full page, assume we're done
            loadMoreState = pageData.length < 20 ? 'done' : null;
        } catch (e) {
            console.warn('[TM Shortlist] fetchMore failed', e);
            loadMoreState = null;
        }

        loadProgress = null;
        renderPanel();
    }

    /* ═════════════════════════════════════════════════════════
       CSS  — delegated to TmShortlistTable component
       ═════════════════════════════════════════════════════════ */
    function injectCSS() { window.TmShortlistTable.injectCSS(); }

    /* ═════════════════════════════════════════════════════════
       RENDER PANEL  — delegated to TmShortlistPanel component
       ═════════════════════════════════════════════════════════ */
    function buildCtx() {
        return {
            allPlayers, indexedPlayers, activeTab,
            sortCol, sortDir, ixSortCol, ixSortDir, ixPage, IX_PAGE_SIZE, slPage, SL_PAGE_SIZE,
            shortlistLoading, loadProgress, loadMoreState,
            filterState: { fPos, fSide, fAgeMin, fAgeMax, fR5Min, fR5Max, fRecMin, fRecMax, fTiMin, fTiMax },
            onTabChange(t) {
                if (activeTab === t || shortlistLoading) return;
                activeTab = t;
                if (t === 'indexed' && !indexedPlayers && !indexedLoading) loadIndexedTab();
                else renderPanel();
            },
            onGroupFilter(g) { if (fPos.has(g)) fPos.delete(g); else fPos.add(g); ixPage = 0; slPage = 0; renderPanel(); },
            onSideFilter(s) { if (fSide.has(s)) fSide.delete(s); else fSide.add(s); ixPage = 0; slPage = 0; renderPanel(); },
            onNumFilter(id, value) {
                if (id === 'tmsl-agemin') fAgeMin = parseInt(value) || 0;
                else if (id === 'tmsl-agemax') fAgeMax = parseInt(value) || 99;
                else if (id === 'tmsl-r5min') fR5Min = value;
                else if (id === 'tmsl-r5max') fR5Max = value;
                else if (id === 'tmsl-recmin') fRecMin = value;
                else if (id === 'tmsl-recmax') fRecMax = value;
                else if (id === 'tmsl-timin') fTiMin = value;
                else if (id === 'tmsl-timax') fTiMax = value;
                ixPage = 0; slPage = 0;
                renderPanel();
            },
            onSort(col) { const r = window.TmUtils.toggleSort(col, sortCol, sortDir, (col === 'name' || col === 'pos') ? 1 : -1); sortCol = r.key; sortDir = r.dir; slPage = 0; renderPanel(); },
            onIxSort(col) { const r = window.TmUtils.toggleSort(col, ixSortCol, ixSortDir, col === 'name' ? 1 : -1); ixSortCol = r.key; ixSortDir = r.dir; ixPage = 0; renderPanel(); },
            onIxPage(dir) { ixPage = Math.max(0, ixPage + dir); renderPanel(); },
            onSlPage(dir) { slPage = Math.max(0, slPage + dir); renderPanel(); },
            onLoadMore: fetchMore,
        };
    }

    function renderPanel() { window.TmShortlistPanel.render(buildCtx()); }

    /* ═════════════════════════════════════════════════════════
       INIT
       ═════════════════════════════════════════════════════════ */
    async function init() {
        if (!Array.isArray(window.players_ar) || !window.players_ar.length) return;

        const t0 = performance.now();
        let tDiscovery, tPrefill, tFetch;

        injectCSS();
        const firstIds = window.players_ar.map(p => String(p.id));
        shortlistLoading = true;
        loadProgress = null;
        allPlayers = [];
        renderPanel();

        // 1. Discover all IDs — hit the same endpoint 5 more times, collect unique players (endpoint returns random each time)
        const allIds = [...firstIds];
        const seenIds = new Set(firstIds);
        console.log(`[TM Shortlist] Discovery start: firstIds=${firstIds.length}`);
        for (let i = 0; i < 5; i++) {
            try {
                console.log(`[TM Shortlist] Discovery round ${i + 1}/5`);
                const pageData = await window.TmApi.fetchShortlistPage();
                if (!pageData.length) { console.log(`[TM Shortlist] Discovery round ${i + 1}: empty, done`); break; }
                const newBefore = allIds.length;
                for (const p of pageData) {
                    const key = String(p.id);
                    if (!PAGE_DATA[key]) {
                        PAGE_DATA[key] = {
                            timeleft: parseInt(p.timeleft) || 0,
                            timeleft_string: p.timeleft_string || null,
                            curbid: p.curbid || null,
                            next_bid: parseInt(p.next_bid) || 0,
                            bid_level: parseInt(p.bid) || 0,
                            txt: p.txt || '',
                            ban: p.ban || '0',
                            inj: p.inj != null ? String(p.inj) : null,
                            locked: typeof p.status === 'string' && p.status.includes('status_unknown'),
                            retire: p.retire || '0',
                            no: parseInt(p.no) || 0,
                            wage: parseInt(p.wage) || 0,
                            club: p.club || '0',
                        };
                    }
                    if (!seenIds.has(key)) { seenIds.add(key); allIds.push(key); }
                }
                console.log(`[TM Shortlist] Discovery round ${i + 1}: got=${pageData.length}, new=${allIds.length - newBefore}, total=${allIds.length}`);
            } catch (e) { console.warn('[TM Shortlist] Discovery fetch failed', e); break; }
        }

        nextStart = 0;
        totalKnown = allIds.length;
        loadProgress = { done: 0, total: totalKnown };
        loadMoreState = 'done'; // discovery already fetched all available pages
        tDiscovery = performance.now();

        // 2. Pre-fill all known IDs from DB immediately
        await window.TmPlayerDB.init();
        for (const pid of allIds) {
            const dbStore = window.TmPlayerDB.get(pid);
            if (dbStore) {
                const p = dbRecordToPlayer(pid, dbStore);
                if (p) {
                    Object.assign(p, PAGE_DATA[String(pid)] || {});
                    p.pending = true;
                    allPlayers.push(p);
                }
            }
        }
        renderPanel();
        tPrefill = performance.now();

        // 3. Fetch fresh data — squad batching for known clubs, tooltip fallback for rest
        // Players with a fresh DB record (seen < 1 week) are considered current — skip tooltip fetch
        for (const p of allPlayers) {
            if (p.pending && !p.stale) p.pending = false;
        }
        loadProgress = { done: allPlayers.filter(pl => !pl.pending).length, total: totalKnown };
        renderPanel();

        const clubGroups = new Map();
        const tooltipIds = [];

        for (const pid of allIds) {
            const existing = allPlayers.find(pl => pl.id === pid);
            if (existing && !existing.pending) continue; // fresh DB record, no fetch needed
            // PAGE_DATA always has club for IDs from players_ar; DB meta is fallback for fetchMore IDs
            const clubId = PAGE_DATA[pid]?.club || window.TmPlayerDB.get(pid)?.meta?.club_id;
            if (clubId && String(clubId) !== '0') {
                const key = String(clubId);
                if (!clubGroups.has(key)) clubGroups.set(key, []);
                clubGroups.get(key).push(String(pid));
            } else {
                tooltipIds.push(String(pid));
            }
        }

        // Clubs with ≥2 shortlisted players: one squad fetch covers all of them
        for (const [clubId, pids] of clubGroups) {
            if (pids.length < 2) { tooltipIds.push(...pids); continue; }
            try {
                const data = await window.TmApi.fetchSquadRaw(clubId);
                if (data?.post) {
                    const squadMap = new Map(data.post.map(sp => [String(sp.id), sp]));
                    for (const pid of pids) {
                        const sp = squadMap.get(pid);
                        if (sp) {
                            Object.assign(sp, PAGE_DATA[pid] || {});
                            const idx = allPlayers.findIndex(pl => pl.id === pid);
                            if (idx !== -1) allPlayers[idx] = sp;
                            else allPlayers.push(sp);
                        } else {
                            tooltipIds.push(pid); // player left the club
                        }
                    }
                } else {
                    tooltipIds.push(...pids);
                }
            } catch (e) {
                console.warn('[TM Shortlist] squad fetch failed', clubId, e);
                tooltipIds.push(...pids);
            }
            loadProgress = { done: allPlayers.filter(pl => !pl.pending).length, total: totalKnown };
            renderPanel();
        }

        // Individual tooltips for everyone not covered by squad
        for (const pid of tooltipIds) {
            try {
                const data = await window.TmApi.fetchPlayerTooltip(pid);
                const p = data?.player;
                if (p) {
                    Object.assign(p, PAGE_DATA[pid] || {});
                    const idx = allPlayers.findIndex(pl => pl.id === pid);
                    if (idx !== -1) allPlayers[idx] = p;
                    else allPlayers.push(p);
                }
            } catch (e) {
                console.warn('[TM Shortlist] tooltip failed', pid, e);
                const stub = allPlayers.find(pl => pl.id === pid);
                if (stub) stub.pending = false;
            }
            loadProgress = { done: allPlayers.filter(pl => !pl.pending).length, total: totalKnown };
            renderPanel();
        }

        shortlistLoading = false;
        loadProgress = null;
        tFetch = performance.now();

        renderPanel();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

})();



// ─── tm-import.user.js ───────────────────────────────────────────


(function () {
    'use strict';

    const $ = window.jQuery;
    if (!$) return;

    const PlayerDB = window.TmPlayerDB;

    /* ═══════════════════════════════════════════════════════════
       Constants & Calculations
       ═══════════════════════════════════════════════════════════ */
    const getPositionIndex = window.TmLib.getPositionIndex;

    /* R5 / REC calculation — delegates to TmLib */
    const calculateR5F = window.TmLib.calcR5;
    const calculateRemaindersF = (posIdx, skills, asi) => ({ rec: window.TmLib.calcRec(posIdx, skills, asi) });

    const { ageToMonths } = window.TmUtils;
    const buildRoutineMap = window.TmLib.buildRoutineMap;

    /* ═══════════════════════════════════════════════════════════
       Fetch helpers
       ═══════════════════════════════════════════════════════════ */
    const fetchTip = (pid) => window.TmApi.fetchTooltipRaw(pid).then(data => data?.player || null);

    const fetchPlayerInfo = (pid, type) => window.TmApi.fetchPlayerInfo(pid, type);

    /* Fetch squad data for any club — cached per club_id */
    const clubPostCache = {};
    const fetchClubTraining = (clubId) => {
        clubId = String(clubId);
        if (clubPostCache[clubId]) return Promise.resolve(clubPostCache[clubId]);
        return window.TmApi.fetchSquadPost(clubId).then(post => {
            clubPostCache[clubId] = post || {};
            return clubPostCache[clubId];
        });
    };

    const delay = (ms) => new Promise(r => setTimeout(r, ms));

    /* ═══════════════════════════════════════════════════════════
       Import pipeline — delegated to TmImportSync component
       ═══════════════════════════════════════════════════════════ */
    const parseImportFile = window.TmImportSync.parseImportFile;
    const parseAge = window.TmImportSync.parseAge;
    const syncPlayer = window.TmImportSync.syncPlayer;

    /* ═══════════════════════════════════════════════════════════
       CSS
       ═══════════════════════════════════════════════════════════ */
    /* ═══════════════════════════════════════════════════════════
       UI — Render directly into .main_center on /history page
       ═══════════════════════════════════════════════════════════ */
    let parsedPlayers = null;
    let isSyncing = false;

    const buildUI = () => {
        TmImportStyles.inject();

        const allMc = document.querySelectorAll('.main_center');
        const mc = allMc[allMc.length - 1];
        if (!mc) return;

        /* Clear existing content inside the existing .main_center */
        mc.innerHTML = '';
        mc.style.display = '';

        mc.innerHTML = `
            <div class="tmi-page">

            <!-- Import / Export toolbar -->
            <div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap">
                <button class="tmi-btn" id="tmi-import-toggle">Import JSON</button>
                <button class="tmi-btn" id="tmi-export-btn">Export JSON</button>
                <button class="tmi-btn tmi-btn-warn" id="tmi-routine-btn">Bad Routine</button>
                <button class="tmi-btn tmi-btn-dng" id="tmi-purge-btn">Purge Retired</button>
            </div>

            <!-- Collapsible import section -->
            <div class="tmi-import-section" id="tmi-import-section">
              <div class="tmi-wrap">
                <div class="tmi-wrap-body">
                <div class="tmi-dropzone" id="tmi-dropzone">
                    <div class="tmi-dropzone-icon">📄</div>
                    <div class="tmi-dropzone-text">Drop JSON file here or click to browse</div>
                    <div class="tmi-dropzone-sub">Accepts old R6 format: { "playerId": { SI, REREC, R5, skills } }</div>
                    <input type="file" accept=".json,.txt" class="tmi-file-input" id="tmi-file-input">
                </div>
                <div id="tmi-parsed-area"></div>
                <div id="tmi-progress-area" style="display:none">
                    <div class="tmi-progress">
                        <div class="tmi-progress-bar-wrap">
                            <div class="tmi-progress-bar" id="tmi-bar"></div>
                            <div class="tmi-progress-pct" id="tmi-pct">0%</div>
                        </div>
                        <div class="tmi-progress-text" id="tmi-progress-text"></div>
                    </div>
                </div>
                <div class="tmi-log" id="tmi-log" style="display:none"></div>
                <div id="tmi-summary-area"></div>
                <div class="tmi-actions" id="tmi-actions" style="display:none">
                    <button class="tmi-sync-btn" id="tmi-sync-btn">Start Sync</button>
                    <span class="tmi-status" id="tmi-status"></span>
                </div>
                </div>
              </div>
            </div>

            <!-- DB player list -->
            <div id="tmi-db-area"></div>
            </div>
        `;

        /* Toggle import section */
        const toggleBtn = mc.querySelector('#tmi-import-toggle');
        const importSection = mc.querySelector('#tmi-import-section');
        toggleBtn.addEventListener('click', () => {
            const isOpen = importSection.classList.toggle('open');
            toggleBtn.textContent = isOpen ? '▼ Import JSON' : 'Import JSON';
            if (isOpen) toggleBtn.classList.add('active');
            else toggleBtn.classList.remove('active');
        });

        /* File input */
        const dropzone = mc.querySelector('#tmi-dropzone');
        const fileInput = mc.querySelector('#tmi-file-input');
        dropzone.addEventListener('click', () => fileInput.click());
        dropzone.addEventListener('dragover', (e) => { e.preventDefault(); dropzone.classList.add('dragover'); });
        dropzone.addEventListener('dragleave', () => dropzone.classList.remove('dragover'));
        dropzone.addEventListener('drop', (e) => {
            e.preventDefault();
            dropzone.classList.remove('dragover');
            if (e.dataTransfer.files.length > 0) handleFile(e.dataTransfer.files[0]);
        });
        fileInput.addEventListener('change', (e) => {
            if (e.target.files.length > 0) handleFile(e.target.files[0]);
        });

        /* Sync button */
        mc.querySelector('#tmi-sync-btn').addEventListener('click', startSync);

        /* Export */
        mc.querySelector('#tmi-export-btn').addEventListener('click', exportDB);

        /* Purge retired */
        mc.querySelector('#tmi-purge-btn').addEventListener('click', purgeRetired);

        /* Bad routine */
        mc.querySelector('#tmi-routine-btn').addEventListener('click', showBadRoutine);

        /* Render DB player list */
        renderDBList();
    };

    /* ═══════════════════════════════════════════════════════════
       Export DB → JSON file download
       ═══════════════════════════════════════════════════════════ */
    const exportDB = () => {
        const pids = PlayerDB.allPids();
        if (pids.length === 0) { alert('Database is empty — nothing to export.'); return; }

        const dump = {};
        for (const pid of pids) {
            dump[pid] = PlayerDB.get(pid);
        }

        const json = JSON.stringify(dump, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `tm-playerdb-${new Date().toISOString().slice(0, 10)}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    /* ═══════════════════════════════════════════════════════════
       Purge retired players from IndexedDB
       ═══════════════════════════════════════════════════════════ */
    const purgeRetired = async () => {
        const pids = PlayerDB.allPids();
        if (pids.length === 0) { alert('Database is empty.'); return; }
        if (!confirm(`Check ${pids.length} players via tooltip and remove retired ones?`)) return;

        const purgeBtn = document.getElementById('tmi-purge-btn');
        if (purgeBtn) { purgeBtn.disabled = true; purgeBtn.textContent = 'Checking…'; }

        const retired = [];
        let checked = 0;

        for (const pid of pids) {
            checked++;
            if (purgeBtn) purgeBtn.textContent = `${checked}/${pids.length} (${retired.length} retired)`;

            try {
                const tip = await fetchTip(pid);
                await delay(80);

                /* Retired player → tooltip has club: null */
                if (!tip || !tip.club_id) {
                    retired.push({ pid, name: (tip && tip.name) || `#${pid}` });
                }
            } catch (e) {
                console.warn(`[Import] purge check failed for ${pid}:`, e);
            }
        }

        if (retired.length === 0) {
            alert('No retired players found.');
            if (purgeBtn) { purgeBtn.disabled = false; purgeBtn.textContent = 'Purge Retired'; }
            return;
        }

        const names = retired.map(r => `${r.name} (${r.pid})`).join('\n');
        if (!confirm(`Found ${retired.length} retired player(s). Remove them from DB?\n\n${names}`)) {
            if (purgeBtn) { purgeBtn.disabled = false; purgeBtn.textContent = 'Purge Retired'; }
            return;
        }

        for (const r of retired) {
            await PlayerDB.remove(r.pid);
        }

        console.log(`%c[Import] Purged ${retired.length} retired player(s): ${retired.map(r => r.pid).join(', ')}`,
            'font-weight:bold;color:#f87171');

        if (purgeBtn) { purgeBtn.disabled = false; purgeBtn.textContent = 'Purge Retired'; }
        renderDBList();
        alert(`Removed ${retired.length} retired player(s) from database.`);
    };

    /* ═══════════════════════════════════════════════════════════
       Show players with bad routine data
       ═══════════════════════════════════════════════════════════ */
    const showBadRoutine = async () => {
        const pids = PlayerDB.allPids();
        if (pids.length === 0) { alert('Database is empty.'); return; }

        /* Toggle: if panel already shown, remove it and return */
        const existing = document.getElementById('tmi-routine-panel');
        if (existing) { existing.remove(); return; }

        const routineBtn = document.getElementById('tmi-routine-btn');
        const allZeroCandidates = [];  /* players where every routine is 0 or null */
        const bigJumps = [];           /* players with routine jump > 3 between consecutive records */

        for (const pid of pids) {
            const store = PlayerDB.get(pid);
            if (!store || !store.records) continue;
            const meta = store.meta || {};
            const name = meta.name || `#${pid}`;

            const recKeys = Object.keys(store.records).sort((a, b) => ageToMonths(a) - ageToMonths(b));
            if (recKeys.length === 0) continue;

            /* Check all-zero routine */
            const routines = recKeys.map(k => store.records[k].routine);
            const allNull = routines.every(r => r == null || r === 0);
            if (allNull && recKeys.length > 1) {
                allZeroCandidates.push({ pid, name, records: recKeys.length });
            }

            /* Check jumps > 3 between consecutive records */
            const jumps = [];
            for (let i = 1; i < recKeys.length; i++) {
                const prevR = store.records[recKeys[i - 1]].routine;
                const currR = store.records[recKeys[i]].routine;
                if (prevR == null || currR == null) continue;
                const diff = Math.abs(currR - prevR);
                if (diff > 3) {
                    jumps.push({
                        from: recKeys[i - 1], to: recKeys[i],
                        prevR: prevR.toFixed(1), currR: currR.toFixed(1),
                        diff: diff.toFixed(1)
                    });
                }
            }
            if (jumps.length > 0) {
                bigJumps.push({ pid, name, jumps });
            }
        }

        /* For all-zero candidates: fetch history to check if they actually have games */
        const allZero = [];
        if (allZeroCandidates.length > 0) {
            if (routineBtn) { routineBtn.disabled = true; routineBtn.textContent = 'Checking 0s…'; }
            for (let i = 0; i < allZeroCandidates.length; i++) {
                const p = allZeroCandidates[i];
                if (routineBtn) routineBtn.textContent = `Checking ${i + 1}/${allZeroCandidates.length}…`;
                try {
                    const histData = await fetchPlayerInfo(p.pid, 'history');
                    await delay(80);
                    let totalGames = 0;
                    if (histData && histData.table && histData.table.total) {
                        histData.table.total.forEach(r => {
                            totalGames += parseInt(r.games) || 0;
                        });
                    }
                    if (totalGames > 0) {
                        /* Has games but routine=0 → bad, needs fix */
                        allZero.push({ pid: p.pid, name: p.name, records: p.records, games: totalGames });
                    }
                    /* totalGames === 0 → legit zero routine, skip */
                } catch (e) {
                    /* fetch failed, include to be safe */
                    allZero.push({ pid: p.pid, name: p.name, records: p.records, games: '?' });
                }
            }
            if (routineBtn) { routineBtn.disabled = false; routineBtn.textContent = 'Bad Routine'; }
        }

        /* Render results into tmi-db-area (above the table) */
        const area = document.getElementById('tmi-db-area');
        if (!area) return;

        if (allZero.length === 0 && bigJumps.length === 0) {
            alert('No routine issues found.');
            return;
        }

        /* Collect unique PIDs for fix */
        const badPidSet = new Set();
        allZero.forEach(p => badPidSet.add(p.pid));
        bigJumps.forEach(p => badPidSet.add(p.pid));
        const badPids = [...badPidSet];

        let html = '<div id="tmi-routine-panel" class="tmi-routine-panel"><div class="tmi-wrap"><div class="tmi-wrap-head"><h2>Routine Issues</h2><button class="tmi-sync-btn" id="tmi-fix-routine-btn" style="padding:5px 14px;font-size:11px">Fix Routine (' + badPids.length + ')</button></div><div class="tmi-wrap-body">';

        if (allZero.length > 0) {
            html += `<div class="tmi-routine-cat">Routine = 0 but has games <span>${allZero.length}</span></div>`;
            html += '<table class="tmi-db-table"><thead><tr><th>Name</th><th class="c">Records</th><th class="c">Games</th></tr></thead><tbody>';
            for (const p of allZero) {
                html += `<tr><td><a href="https://trophymanager.com/players/${p.pid}/" target="_blank">${p.name}</a></td><td class="c">${p.records}</td><td class="c">${p.games}</td></tr>`;
            }
            html += '</tbody></table>';
        }

        if (bigJumps.length > 0) {
            html += `<div class="tmi-routine-cat">Routine jump &gt; 3 <span>${bigJumps.length}</span></div>`;
            html += '<table class="tmi-db-table"><thead><tr><th>Name</th><th>Age</th><th class="r">From</th><th class="r">To</th><th class="r">Δ</th></tr></thead><tbody>';
            for (const p of bigJumps) {
                for (let j = 0; j < p.jumps.length; j++) {
                    const jmp = p.jumps[j];
                    html += `<tr>
                        <td>${j === 0 ? `<a href="https://trophymanager.com/players/${p.pid}/" target="_blank">${p.name}</a>` : ''}</td>
                        <td>${jmp.from} → ${jmp.to}</td>
                        <td class="r">${jmp.prevR}</td>
                        <td class="r">${jmp.currR}</td>
                        <td class="r" style="color:#fbbf24;font-weight:700">${jmp.diff}</td>
                    </tr>`;
                }
            }
            html += '</tbody></table>';
        }

        html += '</div></div></div>';

        area.insertAdjacentHTML('afterbegin', html);

        /* Wire up Fix button */
        const fixBtn = document.getElementById('tmi-fix-routine-btn');
        if (fixBtn) fixBtn.addEventListener('click', () => fixBadRoutine(badPids));
    };

    /* ═══════════════════════════════════════════════════════════
       Fix routine — re-fetch history & recompute for bad players
       ═══════════════════════════════════════════════════════════ */
    const fixBadRoutine = async (pids) => {
        if (!pids || pids.length === 0) return;

        const fixBtn = document.getElementById('tmi-fix-routine-btn');
        if (fixBtn) { fixBtn.disabled = true; fixBtn.textContent = 'Fixing…'; }

        let fixed = 0, failed = 0;

        for (let i = 0; i < pids.length; i++) {
            const pid = pids[i];
            if (fixBtn) fixBtn.textContent = `${i + 1}/${pids.length} fixing…`;

            try {
                const store = PlayerDB.get(pid);
                if (!store || !store.records) { failed++; continue; }

                const meta = store.meta || {};
                const isGK = !!meta.isGK;
                const favpos = meta.pos || '';
                const firstPos = favpos.split(',')[0].trim();
                const posIdx = isGK ? 9 : getPositionIndex(firstPos);

                /* Re-fetch tooltip for current routine + age */
                const tip = await fetchTip(pid);
                await delay(80);
                if (!tip) { failed++; continue; }

                const curRoutine = parseFloat(tip.routine) || 0;
                const age = parseAge(tip);
                let curAgeTotalMonths = 0;
                if (age) {
                    curAgeTotalMonths = age.years * 12 + age.months;
                } else {
                    const recKeys = Object.keys(store.records);
                    const lastKey = recKeys.sort((a, b) => ageToMonths(b) - ageToMonths(a))[0];
                    const [ly, lm] = lastKey.split('.').map(Number);
                    curAgeTotalMonths = ly * 12 + lm + 1;
                }

                /* Re-fetch history for games per season */
                const histData = await fetchPlayerInfo(pid, 'history');
                await delay(80);

                /* Recompute routine map */
                const recKeys = Object.keys(store.records).sort((a, b) => ageToMonths(a) - ageToMonths(b));
                let gpData = null;
                if (histData?.table?.total) {
                    const totalRows = histData.table.total
                        .map(r => ({ ...r, season: parseInt(r.season) }))
                        .filter(r => isFinite(r.season));
                    if (totalRows.length > 0) {
                        const gpBySeason = {};
                        totalRows.forEach(r => { gpBySeason[r.season] = (gpBySeason[r.season] || 0) + (parseInt(r.games) || 0); });
                        gpData = { gpBySeason, curSeason: Math.max(...totalRows.map(r => r.season)) };
                    }
                }
                const routineMap = buildRoutineMap(
                    curRoutine,
                    Math.floor(curAgeTotalMonths / 12), curAgeTotalMonths % 12,
                    gpData, recKeys
                );

                /* Update each record's routine, R5, REREC */
                for (const ageKey of recKeys) {
                    const rec = store.records[ageKey];
                    const rtn = routineMap[ageKey] ?? curRoutine;
                    rec.routine = rtn;
                    rec.REREC = Number(calculateRemaindersF(posIdx, rec.skills, rec.SI).rec);
                    rec.R5 = Number(calculateR5F(posIdx, rec.skills, rec.SI, rtn));
                }

                await PlayerDB.set(pid, store);
                fixed++;
                console.log(`[Import] Fixed routine for ${meta.name || pid}`);

            } catch (e) {
                console.warn(`[Import] Fix routine failed for ${pid}:`, e);
                failed++;
            }

            await delay(50);
        }

        if (fixBtn) { fixBtn.disabled = false; fixBtn.textContent = `Done (${fixed} fixed)`; }

        /* Remove panel and refresh */
        const panel = document.getElementById('tmi-routine-panel');
        if (panel) panel.remove();
        renderDBList();

        console.log(`%c[Import] Routine fix: ${fixed} fixed, ${failed} failed`,
            'font-weight:bold;color:#6cc040');
    };

    /* ═══════════════════════════════════════════════════════════
       DB Player List — sortable, searchable
       ═══════════════════════════════════════════════════════════ */
    let dbSortCol = 'name';
    let dbSortDir = 1;  // 1 = asc, -1 = desc

    const renderDBList = () => {
        const area = document.getElementById('tmi-db-area');
        if (!area) return;

        const pids = PlayerDB.allPids();
        const players = [];
        for (const pid of pids) {
            const store = PlayerDB.get(pid);
            if (!store) continue;
            const meta = store.meta || {};
            const recKeys = Object.keys(store.records || {}).sort((a, b) => ageToMonths(a) - ageToMonths(b));
            const first = recKeys[0] || '—';
            const last = recKeys[recKeys.length - 1] || '—';
            const lastRec = recKeys.length > 0 ? store.records[recKeys[recKeys.length - 1]] : null;
            const lastR5 = lastRec ? (Number(lastRec.R5) || 0) : 0;
            const lastREREC = lastRec ? (Number(lastRec.REREC) || 0) : 0;
            const lastSI = lastRec ? (Number(lastRec.SI) || 0) : 0;
            const routine = lastRec && lastRec.routine != null ? Number(lastRec.routine) : null;
            players.push({
                pid, name: meta.name || `#${pid}`, pos: meta.pos || '?',
                isGK: !!meta.isGK, records: recKeys.length,
                first, last, lastR5, lastREREC, lastSI, routine
            });
        }

        if (players.length === 0) {
            area.innerHTML = '<div class="tmi-empty">No players in database yet. Import a JSON file to get started.</div>';
            return;
        }

        /* Sort */
        const cmp = (a, b) => {
            let va, vb;
            switch (dbSortCol) {
                case 'name': va = a.name.toLowerCase(); vb = b.name.toLowerCase(); break;
                case 'pos': va = a.pos; vb = b.pos; break;
                case 'records': va = a.records; vb = b.records; break;
                case 'r5': va = a.lastR5; vb = b.lastR5; break;
                case 'rec': va = a.lastREREC; vb = b.lastREREC; break;
                case 'si': va = a.lastSI; vb = b.lastSI; break;
                case 'routine': va = a.routine ?? -1; vb = b.routine ?? -1; break;
                case 'last': va = ageToMonths(a.last || '0.0'); vb = ageToMonths(b.last || '0.0'); break;
                default: va = a.name.toLowerCase(); vb = b.name.toLowerCase();
            }
            if (va < vb) return dbSortDir * -1;
            if (va > vb) return dbSortDir * 1;
            return 0;
        };
        players.sort(cmp);

        const arrow = (col) => dbSortCol === col ? `<span class="sort-arrow">${dbSortDir === 1 ? '▲' : '▼'}</span>` : '';

        let html = `
            <div class="tmi-wrap">
            <div class="tmi-wrap-head">
                <h2>Player Database <span class="tmi-db-count">(${players.length})</span></h2>
                <input type="text" class="tmi-db-search" id="tmi-db-search" placeholder="Search name or ID…">
            </div>
            <div class="tmi-db-scroll">
            <table class="tmi-db-table" id="tmi-db-table">
                <thead><tr>
                    <th data-col="name">Name${arrow('name')}</th>
                    <th data-col="pos">Pos${arrow('pos')}</th>
                    <th data-col="records" class="c">Rec${arrow('records')}</th>
                    <th data-col="last">Last Age${arrow('last')}</th>
                    <th data-col="si" class="r">SI${arrow('si')}</th>
                    <th data-col="r5" class="r">R5${arrow('r5')}</th>
                    <th data-col="rec" class="r">REC${arrow('rec')}</th>
                    <th data-col="routine" class="r">Rtn${arrow('routine')}</th>
                </tr></thead>
                <tbody id="tmi-db-tbody">`;

        for (const p of players) {
            html += `<tr data-search="${p.name.toLowerCase()} ${p.pid}">
                <td><a href="https://trophymanager.com/players/${p.pid}/" target="_blank">${p.name}</a></td>
                <td class="pos-cell">${p.isGK ? '<span class="gk-badge">GK</span>' : p.pos}</td>
                <td class="c">${p.records}</td>
                <td>${p.last}</td>
                <td class="r">${p.lastSI > 0 ? p.lastSI.toLocaleString() : '—'}</td>
                <td class="r">${p.lastR5 > 0 ? p.lastR5.toFixed(2) : '—'}</td>
                <td class="r">${p.lastREREC > 0 ? p.lastREREC.toFixed(2) : '—'}</td>
                <td class="r">${p.routine != null ? p.routine.toFixed(1) : '—'}</td>
            </tr>`;
        }

        html += '</tbody></table></div></div>';
        area.innerHTML = html;

        /* Sort click handlers */
        area.querySelectorAll('.tmi-db-table th[data-col]').forEach(th => {
            th.addEventListener('click', () => {
                const col = th.dataset.col;
                const defaultDir = (col === 'name' || col === 'pos') ? 1 : -1;
                ({ key: dbSortCol, dir: dbSortDir } = window.TmUtils.toggleSort(col, dbSortCol, dbSortDir, defaultDir));
                renderDBList();
            });
        });

        /* Search */
        const searchInput = area.querySelector('#tmi-db-search');
        searchInput.addEventListener('input', () => {
            const q = searchInput.value.toLowerCase();
            area.querySelectorAll('#tmi-db-tbody tr').forEach(tr => {
                tr.style.display = tr.dataset.search.includes(q) ? '' : 'none';
            });
        });
    };

    /* ═══════════════════════════════════════════════════════════
       File handling
       ═══════════════════════════════════════════════════════════ */
    const handleFile = (file) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target.result);
                parsedPlayers = parseImportFile(json);
                if (parsedPlayers.length === 0) {
                    showParsed('<div style="color:#f87171;font-weight:600">No valid players found in file</div>');
                    return;
                }
                displayParsed(parsedPlayers, file.name);
            } catch (err) {
                showParsed(`<div style="color:#f87171;font-weight:600">Parse error: ${err.message}</div>`);
            }
        };
        reader.readAsText(file);
    };

    const showParsed = (html) => {
        const area = document.getElementById('tmi-parsed-area');
        if (area) area.innerHTML = html;
    };

    const displayParsed = (players, filename) => {
        const totalRecs = players.reduce((s, p) => s + p.ageKeys.length, 0);
        const dbCount = players.filter(p => PlayerDB.get(p.pid)).length;

        let html = `
            <div class="tmi-parsed">
                <div class="tmi-parsed-header">
                    Parsed ${players.length} players, ${totalRecs} records from ${filename}
                    ${dbCount > 0 ? `<span style="color:#fbbf24;font-weight:400;font-size:12px"> — ${dbCount} already in DB</span>` : ''}
                </div>
                <div class="tmi-table-scroll">
                    <table class="tmi-table">
                        <thead><tr>
                            <th>#</th>
                            <th>Player ID</th>
                            <th class="c">Records</th>
                            <th class="c">GK</th>
                            <th>Age Range</th>
                            <th class="c">In DB</th>
                        </tr></thead>
                        <tbody>`;

        players.forEach((p, i) => {
            const first = p.ageKeys[0];
            const last = p.ageKeys[p.ageKeys.length - 1];
            const range = first === last ? first : `${first} → ${last}`;
            const inDB = PlayerDB.get(p.pid) ? '✓' : '—';
            html += `<tr>
                <td class="c">${i + 1}</td>
                <td><a href="https://trophymanager.com/players/${p.pid}/" target="_blank">${p.pid}</a></td>
                <td class="c">${p.ageKeys.length}</td>
                <td class="c">${p.isGK ? '🧤' : ''}</td>
                <td>${range}</td>
                <td class="c">${inDB}</td>
            </tr>`;
        });

        html += `</tbody></table></div></div>`;
        showParsed(html);

        /* Show sync button */
        const actions = document.getElementById('tmi-actions');
        if (actions) actions.style.display = 'flex';
    };

    /* ═══════════════════════════════════════════════════════════
       Sync orchestrator
       ═══════════════════════════════════════════════════════════ */
    const startSync = async () => {
        if (!parsedPlayers || parsedPlayers.length === 0 || isSyncing) return;
        isSyncing = true;

        const syncBtn = document.getElementById('tmi-sync-btn');
        const statusEl = document.getElementById('tmi-status');
        const progressArea = document.getElementById('tmi-progress-area');
        const barEl = document.getElementById('tmi-bar');
        const pctEl = document.getElementById('tmi-pct');
        const progressText = document.getElementById('tmi-progress-text');
        const logEl = document.getElementById('tmi-log');
        const summaryArea = document.getElementById('tmi-summary-area');

        if (syncBtn) syncBtn.disabled = true;
        if (progressArea) progressArea.style.display = 'block';
        if (logEl) { logEl.style.display = 'block'; logEl.innerHTML = ''; }
        if (summaryArea) summaryArea.innerHTML = '';

        const logFn = (msg, cls) => {
            if (!logEl) return;
            const span = document.createElement('span');
            if (cls) span.className = cls;
            span.textContent = msg + '\n';
            logEl.appendChild(span);
            logEl.scrollTop = logEl.scrollHeight;
        };

        const updateProgress = (idx, total, text) => {
            const pct = Math.round(((idx + 1) / total) * 100);
            if (barEl) barEl.style.width = pct + '%';
            if (pctEl) pctEl.textContent = pct + '%';
            if (progressText) progressText.textContent = text;
        };

        let successCount = 0;
        let failCount = 0;
        const players = parsedPlayers;

        logFn(`Starting sync for ${players.length} players...`, 'ok');
        console.log(`%c[Import] ═══ Starting sync for ${players.length} players ═══`, 'font-weight:bold;color:#38bdf8');

        for (let i = 0; i < players.length; i++) {
            const p = players[i];
            updateProgress(i, players.length, `Player ${i + 1}/${players.length} — #${p.pid} — Fetching tooltip...`);

            try {
                /* Step 1: Fetch tooltip */
                const tip = await fetchTip(p.pid);
                await delay(80);

                if (!tip) {
                    logFn(`✗ #${p.pid} — tooltip failed, skipping`, 'err');
                    failCount++;
                    continue;
                }

                const playerName = tip.name || `#${p.pid}`;
                logFn(`── ${playerName} (#${p.pid}) ──`);
                updateProgress(i, players.length, `Player ${i + 1}/${players.length} — ${playerName} — Fetching history...`);

                /* Step 2: Fetch history */
                const histData = await fetchPlayerInfo(p.pid, 'history');
                await delay(80);

                /* Step 3: Fetch training via player's club (cached per club) */
                let squadPlayer = null;
                const playerClubId = tip.club_id;
                if (playerClubId) {
                    updateProgress(i, players.length, `Player ${i + 1}/${players.length} — ${playerName} — Fetching club training...`);
                    const clubPost = await fetchClubTraining(playerClubId);
                    squadPlayer = clubPost[String(p.pid)] || null;
                    if (!squadPlayer) logFn(`  ⚠ Player not found in club ${playerClubId} squad data`);
                } else {
                    logFn(`  ⚠ No club_id in tooltip, using balanced training weights`);
                }

                updateProgress(i, players.length, `Player ${i + 1}/${players.length} — ${playerName} — Computing...`);

                /* Step 4: Sync */
                await syncPlayer(p, tip, histData, squadPlayer, logFn);
                successCount++;

            } catch (err) {
                logFn(`✗ #${p.pid} — error: ${err.message}`, 'err');
                console.warn(`[Import] Error syncing player ${p.pid}:`, err);
                failCount++;
            }

            await delay(50);
        }

        /* Done */
        updateProgress(players.length - 1, players.length, 'Complete!');
        if (barEl) barEl.style.width = '100%';
        if (pctEl) pctEl.textContent = '100%';

        logFn('');
        logFn(`═══ Sync complete: ${successCount} OK, ${failCount} failed ═══`, successCount > 0 ? 'ok' : 'warn');
        console.log(`%c[Import] ═══ Sync complete: ${successCount} OK, ${failCount} failed ═══`,
            'font-weight:bold;color:#6cc040');

        if (summaryArea) {
            summaryArea.innerHTML = `
                <div class="tmi-summary">
                    ✓ Synced ${successCount} player(s) to IndexedDB v3
                    ${failCount > 0 ? `<span style="color:#fbbf24"> — ${failCount} failed</span>` : ''}
                </div>
            `;
        }

        if (syncBtn) syncBtn.disabled = false;
        if (statusEl) statusEl.textContent = '';
        isSyncing = false;

        /* Refresh DB player list */
        renderDBList();
    };

    /* ═══════════════════════════════════════════════════════════
       Init
       ═══════════════════════════════════════════════════════════ */
    PlayerDB.init().then(() => {
        buildUI();
        console.log('[Import] History page ready — DB loaded');
    }).catch(e => {
        console.warn('[Import] DB init failed:', e);
    });

})();



// ─── tm-r5history.user.js ────────────────────────────────────────


(function () {
    'use strict';

    const $ = window.jQuery;
    if (!$) return;

    /* Abort if this is a specific player page like /players/12345/ */
    if (/\/players\/\d+/.test(location.pathname)) return;

    /* ═══════════════════════════════════════════════════════════
       CONSTANTS
       ═══════════════════════════════════════════════════════════ */
    const { R5_THRESHOLDS } = window.TmConst;

    /* Position group labels for filters */
    const POS_GROUPS = [
        { key: 'all', label: 'All', match: () => true },
        { key: 'gk', label: 'GK', match: idx => idx === 9 },
        { key: 'dc', label: 'DC', match: idx => idx === 0 },
        { key: 'dlr', label: 'DR/DL', match: idx => idx === 1 },
        { key: 'dmc', label: 'DMC', match: idx => idx === 2 },
        { key: 'dmlr', label: 'DMR/DML', match: idx => idx === 3 },
        { key: 'mc', label: 'MC', match: idx => idx === 4 },
        { key: 'mlr', label: 'MR/ML', match: idx => idx === 5 },
        { key: 'omc', label: 'OMC', match: idx => idx === 6 },
        { key: 'omlr', label: 'OMR/OML', match: idx => idx === 7 },
        { key: 'f', label: 'FC', match: idx => idx === 8 }
    ];

    /* Distinct line colors per player */
    const LINE_COLORS = [
        '#ff6384', '#36a2eb', '#ffce56', '#4bc0c0', '#9966ff', '#ff9f40',
        '#e56b6f', '#57cc99', '#80b1d3', '#fdb462', '#b3de69', '#fb8072',
        '#bc80bd', '#8dd3c7', '#fccde5', '#bebada', '#d9d9d9', '#ccebc5',
        '#ff7043', '#ab47bc', '#26c6da', '#9ccc65', '#ef5350', '#42a5f5',
        '#66bb6a', '#ffa726', '#8d6e63', '#78909c', '#ec407a', '#5c6bc0',
        '#29b6f6', '#d4e157', '#ff7043', '#26a69a', '#7e57c2', '#c62828',
        '#00897b', '#f06292', '#ba68c8', '#4dd0e1', '#aed581', '#ffb74d'
    ];

    /* ═══════════════════════════════════════════════════════════
       UTILITIES
       ═══════════════════════════════════════════════════════════ */
    const getColor = window.TmUtils.getColor;

    const getPositionIndex = window.TmLib.getPositionIndex;

    const posGroupColor = posIdx => window.TmPosition.groupColor(posIdx);
    const posLabel = posIdx => window.TmPosition.groupLabel(posIdx);

    /* ═══════════════════════════════════════════════════════════
       IndexedDB — read-only access to TMPlayerData
       ═══════════════════════════════════════════════════════════ */
    const openDB = () => new Promise((resolve, reject) => {
        const req = indexedDB.open('TMPlayerData', 1);
        req.onupgradeneeded = e => {
            const d = e.target.result;
            if (!d.objectStoreNames.contains('players'))
                d.createObjectStore('players');
        };
        req.onsuccess = e => resolve(e.target.result);
        req.onerror = e => reject(e.target.error);
    });

    const loadAllPlayers = async () => {
        const db = await openDB();
        return new Promise((resolve, reject) => {
            const tx = db.transaction('players', 'readonly');
            const store = tx.objectStore('players');
            const reqAll = store.getAll();
            const reqKeys = store.getAllKeys();
            tx.oncomplete = () => {
                const result = {};
                for (let i = 0; i < reqKeys.result.length; i++)
                    result[reqKeys.result[i]] = reqAll.result[i];
                resolve(result);
            };
            tx.onerror = e => reject(e.target.error);
        });
    };

    /* ═══════════════════════════════════════════════════════════
       PARSE SQUAD TABLE — get current squad player IDs + positions
       ═══════════════════════════════════════════════════════════ */
    const parseSquadTable = () => {
        const players = {};
        document.querySelectorAll('#sq a[player_link]').forEach(a => {
            const pid = a.getAttribute('player_link');
            const name = a.textContent.trim();
            const tr = a.closest('tr');
            if (!tr || !pid) return;

            /* Position from favposition span */
            const fpSpan = tr.querySelector('.favposition');
            let pos = '';
            if (fpSpan) {
                /* Extract position text: spans like <span class="d">D</span>/<span class="dm">DM</span> C */
                pos = fpSpan.textContent.trim().replace(/\s+/g, ' ');
            }

            players[pid] = { name, pos };
        });
        return players;
    };

    /* Resolve position index: prefer meta.pos, else parse from squad table, else detect GK */
    const resolvePosition = (store, sqInfo) => {
        if (store.meta && store.meta.pos) {
            const p = store.meta.pos.split(',')[0].trim();
            return getPositionIndex(p);
        }
        if (sqInfo && sqInfo.pos) {
            /* Parse e.g. "D/DM C" → "D" or "Gk" → "GK" */
            const raw = sqInfo.pos.split(/[\/,]/)[0].replace(/\s+/g, '').trim();
            const idx = getPositionIndex(raw);
            if (idx !== 0 || raw.toLowerCase().startsWith('d')) return idx;
        }
        /* Detect GK from skill count */
        const recs = store.records ? Object.values(store.records) : [];
        const firstRec = recs.find(r => r.skills && r.skills.length > 0);
        if (firstRec && firstRec.skills.length === 11) return 9;
        return 0;
    };

    /* ═══════════════════════════════════════════════════════════
       BUILD PLAYER DATA SERIES
       ═══════════════════════════════════════════════════════════ */
    const buildPlayerSeries = (allStores, squadInfo) => {
        const series = [];
        let colorIdx = 0;

        for (const [pid, store] of Object.entries(allStores)) {
            if (!store || !store.records) continue;
            const keys = Object.keys(store.records).sort((a, b) => {
                const [ay, am] = a.split('.').map(Number);
                const [by, bm] = b.split('.').map(Number);
                return (ay * 12 + am) - (by * 12 + bm);
            });
            if (keys.length < 2) continue;

            const posIdx = resolvePosition(store, squadInfo[pid]);
            const name = (store.meta && store.meta.name) || (squadInfo[pid] && squadInfo[pid].name) || `Player ${pid}`;

            const ages = [];
            const r5Values = [];

            for (const key of keys) {
                const rec = store.records[key];
                const r5 = Number(rec.R5);
                if (!r5 || isNaN(r5) || r5 <= 0) continue;

                const [yr, mo] = key.split('.').map(Number);
                const age = yr + mo / 12;
                if (age < 15 || age > 37) continue;

                ages.push(age);
                r5Values.push(r5);
            }

            if (ages.length < 2) continue;

            const color = LINE_COLORS[colorIdx % LINE_COLORS.length];
            colorIdx++;

            if (pid === '139497948') {
                console.log(r5Values);
            }
            series.push({
                pid,
                name,
                posIdx,
                posLabel: posLabel(posIdx),
                color,
                ages,
                values: r5Values,
                visible: true,
                highlighted: false
            });
        }

        /* Sort by position group then name */
        series.sort((a, b) => {
            const pa = a.posIdx === 9 ? -1 : a.posIdx;
            const pb = b.posIdx === 9 ? -1 : b.posIdx;
            if (pa !== pb) return pa - pb;
            return a.name.localeCompare(b.name);
        });

        /* Re-assign colors after sort */
        series.forEach((s, i) => { s.color = LINE_COLORS[i % LINE_COLORS.length]; });

        return series;
    };



    /* ═══════════════════════════════════════════════════════════
       DIALOG STATE + RENDERING
       ═══════════════════════════════════════════════════════════ */
    let allSeries = [];
    let currentFilter = 'all';
    let myPlayersOnly = false;
    let legendSearch = '';
    let squadPids = new Set();
    let syncIssues = [];
    let chartInfo = null;
    let overlay = null;

    /* Zoom state */
    let zoomAgeMin = null, zoomAgeMax = null;
    let zoomYMin = null, zoomYMax = null;
    let isPanning = false, panStart = null, panAgeRange = null, panYRange = null;

    const getVisibleSeries = () => {
        const grp = POS_GROUPS.find(g => g.key === currentFilter);
        return allSeries.filter(s => {
            if (!s.visible) return false;
            if (grp && !grp.match(s.posIdx)) return false;
            if (myPlayersOnly && !squadPids.has(s.pid)) return false;
            return true;
        });
    };

    const createDialog = () => {
        const ov = document.createElement('div');
        ov.className = 'tmrc-overlay';
        ov.innerHTML = `
            <div class="tmrc-modal">
                <div class="tmrc-head">
                    <div class="tmrc-title">📊 Squad R5 History
                        <button class="tmrc-issues-btn" id="tmrc-issues-btn" style="display:none" title="Players with incomplete sync">⚠ Sync Issues</button>
                    </div>
                    <button class="tmrc-close" title="Close">✕</button>
                </div>
                <div class="tmrc-issues-panel" id="tmrc-issues-panel" style="display:none"></div>
                <div class="tmrc-filters" id="tmrc-filters"></div>
                <div class="tmrc-body">
                    <div class="tmrc-chart-area">
                        <canvas class="tmrc-canvas" id="tmrc-canvas"></canvas>
                        <div class="tmrc-tooltip" id="tmrc-tip"></div>
                        <div class="tmrc-zoom-controls" id="tmrc-zoom-controls">
                            <button class="tmrc-zoom-btn" id="tmrc-zoom-in" title="Zoom In">+</button>
                            <button class="tmrc-zoom-btn" id="tmrc-zoom-out" title="Zoom Out">−</button>
                            <button class="tmrc-zoom-btn" id="tmrc-zoom-reset" title="Reset Zoom">↺</button>
                        </div>
                    </div>
                    <div class="tmrc-legend" id="tmrc-legend"></div>
                </div>
                <div class="tmrc-stats" id="tmrc-stats"></div>
            </div>
        `;
        document.body.appendChild(ov);

        /* Close handlers */
        ov.querySelector('.tmrc-close').addEventListener('click', () => ov.classList.remove('open'));
        document.addEventListener('keydown', e => { if (e.key === 'Escape' && ov.classList.contains('open')) ov.classList.remove('open'); });

        /* Issues button toggle */
        ov.querySelector('#tmrc-issues-btn').addEventListener('click', () => {
            const panel = ov.querySelector('#tmrc-issues-panel');
            if (panel.style.display === 'none') {
                renderIssuesPanel(panel);
                panel.style.display = 'block';
            } else {
                panel.style.display = 'none';
            }
        });

        return ov;
    };

    const renderIssuesPanel = (panel) => {
        if (!syncIssues.length) { panel.innerHTML = '<div style="color:#4ade80;padding:8px">All players fully synced!</div>'; return; }
        const tag = (v, total) => v > 0 ? `<span class="tmrc-null">${v}/${total}</span>` : `<span class="tmrc-ok">✓</span>`;
        let h = `<table><thead><tr><th>Player</th><th>Pos</th><th>v</th><th>Records</th><th>R5 null</th><th>REREC null</th><th>Routine null</th><th>No pos</th></tr></thead><tbody>`;
        syncIssues.forEach(p => {
            h += `<tr>
                <td><a href="https://trophymanager.com/players/${p.pid}/" target="_blank">${p.name}</a></td>
                <td>${p.pos || '<span class="tmrc-null">—</span>'}</td>
                <td>${p.v}</td>
                <td>${p.total}</td>
                <td>${tag(p.nullR5, p.total)}</td>
                <td>${tag(p.nullRerec, p.total)}</td>
                <td>${tag(p.nullRoutine, p.total)}</td>
                <td>${p.noMeta ? '<span class="tmrc-null">YES</span>' : '<span class="tmrc-ok">✓</span>'}</td>
            </tr>`;
        });
        h += '</tbody></table>';
        panel.innerHTML = h;
    };

    const renderFilters = () => {
        const container = overlay.querySelector('#tmrc-filters');
        let h = '<span class="tmrc-filter-label">Position:</span>';
        POS_GROUPS.forEach(g => {
            const active = currentFilter === g.key ? ' active' : '';
            h += `<button class="tmrc-filter-btn${active}" data-filter="${g.key}">${g.label}</button>`;
        });
        h += `<span style="margin-left:12px;display:inline-flex;align-items:center;gap:4px;cursor:pointer" id="tmrc-myplayers">
            <input type="checkbox" id="tmrc-myplayers-cb" style="cursor:pointer;accent-color:#4a8a30"${myPlayersOnly ? ' checked' : ''}/>
            <label for="tmrc-myplayers-cb" style="font-size:11px;font-weight:600;color:#8abc78;cursor:pointer">My Players</label>
        </span>`;
        container.innerHTML = h;

        container.querySelectorAll('.tmrc-filter-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                currentFilter = btn.dataset.filter;
                legendSearch = '';
                zoomAgeMin = zoomAgeMax = zoomYMin = zoomYMax = null;
                renderAll();
            });
        });

        const cb = container.querySelector('#tmrc-myplayers-cb');
        if (cb) {
            cb.addEventListener('change', () => {
                myPlayersOnly = cb.checked;
                zoomAgeMin = zoomAgeMax = zoomYMin = zoomYMax = null;
                renderAll();
            });
        }
    };

    const renderLegend = (visibleSeries) => {
        const container = overlay.querySelector('#tmrc-legend');
        /* Sort legend by current R5 descending */
        const sorted = [...visibleSeries].sort((a, b) => {
            const aLast = a.values[a.values.length - 1] || 0;
            const bLast = b.values[b.values.length - 1] || 0;
            return bLast - aLast;
        });

        /* Also include hidden (unchecked) players that pass filter */
        const grp = POS_GROUPS.find(g => g.key === currentFilter);
        const hiddenInFilter = allSeries.filter(s => {
            if (s.visible) return false;
            if (grp && !grp.match(s.posIdx)) return false;
            if (myPlayersOnly && !squadPids.has(s.pid)) return false;
            return true;
        }).sort((a, b) => a.name.localeCompare(b.name));

        const allInLegend = [...sorted, ...hiddenInFilter];
        const totalCount = allInLegend.length;

        /* Apply search filter */
        const searchLower = legendSearch.toLowerCase();
        const filteredLegend = searchLower
            ? allInLegend.filter(s => s.name.toLowerCase().includes(searchLower))
            : allInLegend;
        const filteredChecked = filteredLegend.filter(s => s.visible).length;

        let h = `<div class="tmrc-legend-hdr">
            <span class="tmrc-legend-hdr-title">Players (${filteredChecked}/${filteredLegend.length}${searchLower ? ' / ' + totalCount : ''})</span>
            <div class="tmrc-legend-hdr-btns">
                <button class="tmrc-legend-hdr-btn" id="tmrc-sel-all" title="Select All">All</button>
                <button class="tmrc-legend-hdr-btn" id="tmrc-sel-none" title="Deselect All">None</button>
            </div>
        </div>
        <div class="tmrc-legend-search">
            <input type="text" id="tmrc-legend-search-input" placeholder="Search players..." value="${legendSearch.replace(/"/g, '&quot;')}">
        </div>`;

        filteredLegend.forEach(s => {
            const lastR5 = s.values[s.values.length - 1];
            const lastAge = s.ages[s.ages.length - 1];
            const ageY = Math.floor(lastAge);
            const ageM = Math.round((lastAge - ageY) * 12);
            const hlClass = s.highlighted ? ' highlighted' : '';
            const hidClass = !s.visible ? ' hidden-player' : '';
            h += `<div class="tmrc-legend-item${hlClass}${hidClass}" data-pid="${s.pid}" style="border-left-color:${s.color}">
                <input type="checkbox" class="tmrc-legend-cb" data-pid="${s.pid}" ${s.visible ? 'checked' : ''}>
                <div class="tmrc-legend-swatch" style="background:${s.color}"></div>
                <a class="tmrc-legend-name" href="https://trophymanager.com/players/${s.pid}/" target="_blank" title="${s.name}">${s.name}</a>
                <div class="tmrc-legend-pos" style="color:${posGroupColor(s.posIdx)}">${s.posLabel}</div>
                <div class="tmrc-legend-age">${ageY}.${ageM}</div>
                <div class="tmrc-legend-r5" style="color:${getColor(lastR5, R5_THRESHOLDS)}">${Number(lastR5).toFixed(1)}</div>
            </div>`;
        });
        container.innerHTML = h;

        /* Checkbox toggle */
        container.querySelectorAll('.tmrc-legend-cb').forEach(cb => {
            cb.addEventListener('change', (e) => {
                e.stopPropagation();
                const pid = cb.dataset.pid;
                const s = allSeries.find(x => x.pid === pid);
                if (s) { s.visible = cb.checked; }
                renderAll();
            });
        });

        /* Search input */
        const searchInput = container.querySelector('#tmrc-legend-search-input');
        if (searchInput) {
            searchInput.addEventListener('input', () => {
                legendSearch = searchInput.value;
                renderAll();
            });
            /* Keep focus + cursor position after re-render */
            requestAnimationFrame(() => {
                searchInput.focus();
                searchInput.selectionStart = searchInput.selectionEnd = searchInput.value.length;
            });
        }

        /* All / None buttons — apply only to filtered (visible in legend) players */
        const allBtn = container.querySelector('#tmrc-sel-all');
        const noneBtn = container.querySelector('#tmrc-sel-none');
        const filteredPids = new Set(filteredLegend.map(s => s.pid));
        if (allBtn) allBtn.addEventListener('click', () => {
            allSeries.forEach(s => { if (filteredPids.has(s.pid)) s.visible = true; });
            renderAll();
        });
        if (noneBtn) noneBtn.addEventListener('click', () => {
            allSeries.forEach(s => { if (filteredPids.has(s.pid)) s.visible = false; });
            renderAll();
        });

        /* Hover = highlight (on the row area, not the checkbox) */
        container.querySelectorAll('.tmrc-legend-item').forEach(el => {
            const pid = el.dataset.pid;
            el.addEventListener('mouseenter', () => {
                const vis = getVisibleSeries();
                vis.forEach(s => { s.highlighted = (s.pid === pid); });
                redrawChart();
                updateLegendHighlights(container, filteredLegend);
            });
            el.addEventListener('mouseleave', () => {
                const vis = getVisibleSeries();
                vis.forEach(s => { s.highlighted = false; });
                redrawChart();
                updateLegendHighlights(container, filteredLegend);
            });
        });
    };

    const updateLegendHighlights = (container, visibleSeries) => {
        container.querySelectorAll('.tmrc-legend-item').forEach(el => {
            const pid = el.dataset.pid;
            const s = visibleSeries.find(x => x.pid === pid);
            el.classList.toggle('highlighted', s ? s.highlighted : false);
        });
    };

    const renderStats = (visibleSeries) => {
        const container = overlay.querySelector('#tmrc-stats');
        if (!visibleSeries.length) { container.innerHTML = '<span style="color:#6a9a58">No data</span>'; return; }
        const lastVals = visibleSeries.map(s => s.values[s.values.length - 1]);
        const avg = lastVals.reduce((a, b) => a + b, 0) / lastVals.length;
        const max = Math.max(...lastVals);
        const min = Math.min(...lastVals);
        const best = visibleSeries.find(s => s.values[s.values.length - 1] === max);
        const totalWeeks = visibleSeries.reduce((s, p) => s + p.ages.length, 0);
        container.innerHTML = `
            <div class="tmrc-stat"><span class="tmrc-stat-lbl">Players:</span> <span class="tmrc-stat-val">${visibleSeries.length}</span></div>
            <div class="tmrc-stat"><span class="tmrc-stat-lbl">Total records:</span> <span class="tmrc-stat-val">${totalWeeks}</span></div>
            <div class="tmrc-stat"><span class="tmrc-stat-lbl">Avg R5:</span> <span class="tmrc-stat-val" style="color:${getColor(avg, R5_THRESHOLDS)}">${avg.toFixed(2)}</span></div>
            <div class="tmrc-stat"><span class="tmrc-stat-lbl">Best:</span> <span class="tmrc-stat-val" style="color:${getColor(max, R5_THRESHOLDS)}">${max.toFixed(2)}</span> <span style="color:#6a9a58;font-size:10px">(${best?.name || '?'})</span></div>
            <div class="tmrc-stat"><span class="tmrc-stat-lbl">Min:</span> <span class="tmrc-stat-val" style="color:${getColor(min, R5_THRESHOLDS)}">${min.toFixed(2)}</span></div>
        `;
    };

    const redrawChart = () => {
        const canvas = document.getElementById('tmrc-canvas');
        if (!canvas) return;
        const vis = getVisibleSeries();
        const zoomState = zoomAgeMin !== null
            ? { ageMin: zoomAgeMin, ageMax: zoomAgeMax, yMin: zoomYMin, yMax: zoomYMax }
            : null;
        chartInfo = TmR5HistoryChart.draw(canvas, vis, undefined, zoomState);
    };

    const renderAll = () => {
        if (!overlay) return;
        renderFilters();
        const vis = getVisibleSeries();
        renderLegend(vis);
        renderStats(vis);
        redrawChart();

        /* Update issues button visibility */
        const issBtn = overlay.querySelector('#tmrc-issues-btn');
        if (issBtn) {
            if (syncIssues.length > 0) {
                issBtn.style.display = 'inline-block';
                issBtn.textContent = `⚠ Sync Issues (${syncIssues.length})`;
            } else {
                issBtn.style.display = 'none';
            }
        }

        /* Zoom button handlers (attach once) */
        attachZoomHandlers();
    };

    /* ═══════════════════════════════════════════════════════════
       ZOOM HANDLERS
       ═══════════════════════════════════════════════════════════ */
    let zoomHandlersAttached = false;
    const attachZoomHandlers = () => {
        if (zoomHandlersAttached) return;
        zoomHandlersAttached = true;

        const canvas = document.getElementById('tmrc-canvas');
        if (!canvas) return;

        /* Wheel zoom: centered on mouse position */
        canvas.addEventListener('wheel', (e) => {
            e.preventDefault();
            if (!chartInfo) return;

            const rect = canvas.getBoundingClientRect();
            const mx = e.clientX - rect.left;
            const my = e.clientY - rect.top;

            /* Current ranges */
            const aMin = zoomAgeMin !== null ? zoomAgeMin : chartInfo.ageMin;
            const aMax = zoomAgeMax !== null ? zoomAgeMax : chartInfo.ageMax;
            const vMin = zoomYMin !== null ? zoomYMin : chartInfo.yMin;
            const vMax = zoomYMax !== null ? zoomYMax : chartInfo.yMax;

            /* Mouse position as fraction of chart area */
            const pL = 52, pT = 14, pR = 14, pB = 32;
            const cW = canvas.clientWidth - pL - pR;
            const cH = canvas.clientHeight - pT - pB;
            const fx = Math.max(0, Math.min(1, (mx - pL) / cW));
            const fy = Math.max(0, Math.min(1, 1 - (my - pT) / cH));

            const factor = e.deltaY > 0 ? 1.15 : 0.87;

            /* Zoom age axis around mouse X */
            const ageRange = aMax - aMin;
            const newAgeRange = ageRange * factor;
            const ageAtMouse = aMin + fx * ageRange;
            zoomAgeMin = ageAtMouse - fx * newAgeRange;
            zoomAgeMax = ageAtMouse + (1 - fx) * newAgeRange;

            /* Zoom Y axis around mouse Y */
            const yRange = vMax - vMin;
            const newYRange = yRange * factor;
            const yAtMouse = vMin + fy * yRange;
            zoomYMin = yAtMouse - fy * newYRange;
            zoomYMax = yAtMouse + (1 - fy) * newYRange;

            redrawChart();
        }, { passive: false });

        /* Drag to pan */
        canvas.addEventListener('mousedown', (e) => {
            if (e.button !== 0) return;
            if (zoomAgeMin === null) return; /* no zoom = no pan */
            isPanning = true;
            panStart = { x: e.clientX, y: e.clientY };
            panAgeRange = { min: zoomAgeMin, max: zoomAgeMax };
            panYRange = { min: zoomYMin, max: zoomYMax };
            canvas.style.cursor = 'grabbing';
            e.preventDefault();
        });

        window.addEventListener('mousemove', (e) => {
            if (!isPanning || !panStart) return;
            const canvas = document.getElementById('tmrc-canvas');
            if (!canvas) return;

            const pL = 52, pR = 14, pT = 14, pB = 32;
            const cW = canvas.clientWidth - pL - pR;
            const cH = canvas.clientHeight - pT - pB;
            const dx = e.clientX - panStart.x;
            const dy = e.clientY - panStart.y;

            const ageRange = panAgeRange.max - panAgeRange.min;
            const yRange = panYRange.max - panYRange.min;
            const ageDelta = -(dx / cW) * ageRange;
            const yDelta = (dy / cH) * yRange;

            zoomAgeMin = panAgeRange.min + ageDelta;
            zoomAgeMax = panAgeRange.max + ageDelta;
            zoomYMin = panYRange.min + yDelta;
            zoomYMax = panYRange.max + yDelta;

            redrawChart();
        });

        window.addEventListener('mouseup', () => {
            if (isPanning) {
                isPanning = false;
                const canvas = document.getElementById('tmrc-canvas');
                if (canvas) canvas.style.cursor = 'crosshair';
            }
        });

        /* Button handlers */
        const zoomIn = document.getElementById('tmrc-zoom-in');
        const zoomOut = document.getElementById('tmrc-zoom-out');
        const zoomReset = document.getElementById('tmrc-zoom-reset');

        const btnZoom = (factor) => {
            if (!chartInfo) return;
            const aMin = zoomAgeMin !== null ? zoomAgeMin : chartInfo.ageMin;
            const aMax = zoomAgeMax !== null ? zoomAgeMax : chartInfo.ageMax;
            const vMin = zoomYMin !== null ? zoomYMin : chartInfo.yMin;
            const vMax = zoomYMax !== null ? zoomYMax : chartInfo.yMax;

            const aMid = (aMin + aMax) / 2, yMid = (vMin + vMax) / 2;
            const aHalf = (aMax - aMin) / 2 * factor;
            const yHalf = (vMax - vMin) / 2 * factor;
            zoomAgeMin = aMid - aHalf; zoomAgeMax = aMid + aHalf;
            zoomYMin = yMid - yHalf; zoomYMax = yMid + yHalf;
            redrawChart();
        };

        if (zoomIn) zoomIn.addEventListener('click', () => btnZoom(0.7));
        if (zoomOut) zoomOut.addEventListener('click', () => btnZoom(1.4));
        if (zoomReset) zoomReset.addEventListener('click', () => {
            zoomAgeMin = zoomAgeMax = zoomYMin = zoomYMax = null;
            redrawChart();
        });
    };

    const openDialog = async () => {
        try {
            const allStores = await loadAllPlayers();
            const squadInfo = parseSquadTable();
            squadPids = new Set(Object.keys(squadInfo));

            allSeries = buildPlayerSeries(allStores, squadInfo);

            /* Build sync issues list — players with null REREC/R5/routine */
            syncIssues = [];
            for (const [pid, store] of Object.entries(allStores)) {
                if (!store || !store.records) continue;
                const name = (store.meta && store.meta.name) || (squadInfo[pid] && squadInfo[pid].name) || `Player ${pid}`;
                const pos = (store.meta && store.meta.pos) || '';
                const recs = Object.entries(store.records);
                const nullRerec = recs.filter(([, r]) => r.REREC === null || r.REREC === undefined).length;
                const nullR5 = recs.filter(([, r]) => r.R5 === null || r.R5 === undefined).length;
                const nullRoutine = recs.filter(([, r]) => r.routine === null || r.routine === undefined).length;
                const noMeta = !store.meta || !store.meta.pos;
                if (nullRerec || nullR5 || nullRoutine || noMeta) {
                    syncIssues.push({ pid, name, pos, total: recs.length, nullRerec, nullR5, nullRoutine, noMeta, v: store._v || 1 });
                }
            }
            syncIssues.sort((a, b) => (b.nullR5 + b.nullRerec + b.nullRoutine) - (a.nullR5 + a.nullRerec + a.nullRoutine));
            console.log(`[R5 History] Sync issues: ${syncIssues.length} players with null values`);

            if (!allSeries.length) {
                alert('No player R5 history data found in IndexedDB.\nVisit individual player pages first to sync data.');
                return;
            }

            console.log(`[R5 History] Loaded ${allSeries.length} players from IndexedDB`);

            if (!overlay) {
                overlay = createDialog();
            }

            overlay.classList.add('open');
            currentFilter = 'all';
            legendSearch = '';

            /* Render after a tick so the modal is visible and canvas has dimensions */
            requestAnimationFrame(() => {
                requestAnimationFrame(() => {
                    renderAll();

                    /* Attach tooltip once */
                    const canvas = document.getElementById('tmrc-canvas');
                    const tipEl = document.getElementById('tmrc-tip');
                    if (canvas && tipEl && !canvas._tmrcTipAttached) {
                        TmR5HistoryChart.attachTooltip(canvas, tipEl, getVisibleSeries, () => chartInfo);
                        canvas._tmrcTipAttached = true;
                    }
                });
            });

        } catch (err) {
            console.error('[R5 History] Error:', err);
            alert('Error loading player data: ' + err.message);
        }
    };

    /* ═══════════════════════════════════════════════════════════
       INJECT BUTTON
       ═══════════════════════════════════════════════════════════ */
    const injectButton = () => {
        const h2 = document.querySelector('.box_head h2');
        if (!h2) return;

        const btn = document.createElement('span');
        btn.className = 'tmrc-btn';
        btn.textContent = '📊 R5 History';
        btn.title = 'Show R5 rating history for all tracked players';
        btn.addEventListener('click', openDialog);

        h2.appendChild(btn);
    };

    /* ═══════════════════════════════════════════════════════════
       RESIZE HANDLER
       ═══════════════════════════════════════════════════════════ */
    let resizeTimer;
    window.addEventListener('resize', () => {
        if (!overlay || !overlay.classList.contains('open')) return;
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(redrawChart, 200);
    });

    /* ═══════════════════════════════════════════════════════════
       INIT
       ═══════════════════════════════════════════════════════════ */
    TmR5HistoryStyles.inject();

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', () => setTimeout(injectButton, 500));
    } else {
        setTimeout(injectButton, 500);
    }

})();



// ─── tm-dbinspect.user.js ────────────────────────────────────────


(function () {
    'use strict';

    const DB_NAME = 'TMPlayerData';
    const STORE_NAME = 'players';

    // Abbreviated names for display in the table
    const SKILL_NAMES_FIELD = window.TmConst.SKILL_LABELS_OUT;
    const SKILL_NAMES_GK = window.TmConst.SKILL_LABELS_GK;
    // Full names as returned by tooltip API (must match exactly)
    const TOOLTIP_NAMES_FIELD = window.TmConst.SKILL_DEFS_OUT.map(s => s.name);
    const _gkNameMap = Object.fromEntries(window.TmConst.SKILL_DEFS_GK.flatMap(s =>
        [[s.key, s.name], ...(s.key2 ? [[s.key2, s.name]] : [])]));
    const TOOLTIP_NAMES_GK = window.TmConst.GRAPH_KEYS_GK.map(k => _gkNameMap[k]);



    const ageToM = window.TmUtils.ageToMonths;
    const mToAge = window.TmUtils.monthsToAge;
    const { ASI_WEIGHT_OUTFIELD, ASI_WEIGHT_GK } = window.TmConst;

    const getPosIndex = window.TmLib.getPositionIndex;

    /* ═══ R5 / REC calculation — delegates to TmLib ═══ */
    const calcR5 = window.TmLib.calcR5;
    const calcRemainders = (posIdx, skills, asi) => ({ rec: window.TmLib.calcRec(posIdx, skills, asi) });

    const computeDecimalSkills = (intSkills, asi, isGK, gw) => window.TmLib.calcSkillDecimals(intSkills, asi, isGK, gw);

    /* ═══ Season / routine helpers ═══ */

    const fetchHistoryGP = pid => window.TmApi.fetchPlayerInfo(pid, 'history').then(data => {
        try {
            const total = data?.table?.total;
            if (!total) return null;
            const rows = total.filter(r => typeof r.season === 'number');
            const gpBySeason = {};
            rows.forEach(r => { gpBySeason[r.season] = (gpBySeason[r.season] || 0) + (parseInt(r.games) || 0); });
            const curSeason = rows.length ? Math.max(...rows.map(r => r.season)) : 0;
            return { gpBySeason, curSeason };
        } catch (e) { return null; }
    });

    const buildRoutineMap = window.TmLib.buildRoutineMap;

    /* ═══ Fetch training data for a player (returns group weights) ═══ */
    const STD_FOCUS = window.TmConst.STD_FOCUS;
    const fetchTrainingWeights = (pid, isGK) => {
        if (isGK) return Promise.resolve(null); // GK: single group, balanced
        return window.TmApi.fetchPlayerInfo(pid, 'training').then(data => {
            try {
                const c = data?.custom;
                if (!c) return null;
                const cd = c.custom;
                if (c.custom_on && cd) {
                    const dots = [];
                    let dtot = 0;
                    for (let i = 0; i < 6; i++) {
                        const d = parseInt(cd['team' + (i + 1)]?.points) || 0;
                        dots.push(d); dtot += d;
                    }
                    const sm = 0.5;
                    const den = dtot + 6 * sm;
                    const gw = dots.map(d => (d + sm) / den);
                    console.log(`[DBI] Player ${pid}: custom training dots=[${dots.join(',')}]`);
                    return gw;
                } else {
                    const t = String(c.team || '3');
                    const fg = STD_FOCUS[t] ?? 1;
                    const gw = new Array(6).fill(0.125);
                    gw[fg] = 0.375;
                    console.log(`[DBI] Player ${pid}: standard training type=${t} focus=${fg}`);
                    return gw;
                }
            } catch (e) { return null; }
        });
    };

    /* ═══ IndexedDB helpers ═══ */
    let db = null;
    const openDB = () => new Promise((resolve, reject) => {
        const req = indexedDB.open(DB_NAME, 1);
        req.onupgradeneeded = e => {
            const d = e.target.result;
            if (!d.objectStoreNames.contains(STORE_NAME)) d.createObjectStore(STORE_NAME);
        };
        req.onsuccess = e => { db = e.target.result; resolve(db); };
        req.onerror = () => reject(req.error);
    });

    const loadAll = () => new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readonly');
        const store = tx.objectStore(STORE_NAME);
        const all = store.getAll();
        const keys = store.getAllKeys();
        tx.oncomplete = () => {
            const result = {};
            for (let i = 0; i < keys.result.length; i++) result[keys.result[i]] = all.result[i];
            resolve(result);
        };
        tx.onerror = () => reject(tx.error);
    });

    const savePlayer = (pid, data) => new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readwrite');
        tx.objectStore(STORE_NAME).put(data, String(pid));
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });

    /* ═══ Re-interpolate a player's gaps ═══ */
    const reInterpolate = (store, isGK, gw) => {
        const posIdx = getPosIndex((store.meta && store.meta.pos || 'mc').split(',')[0].trim());
        // Gather only real keys (non-interpolated, non-interpolated2)
        const realKeys = Object.keys(store.records)
            .filter(k => !store.records[k]._interpolated && !store.records[k]._interpolated2)
            .sort((a, b) => ageToM(a) - ageToM(b));

        // Delete all old _interpolated records
        for (const k of Object.keys(store.records)) {
            if (store.records[k]._interpolated) delete store.records[k];
        }

        if (realKeys.length < 2) return;

        const makeInterp = (siA, skAint, rouA, siB, skBint, rouB, mA, mB) => {
            const gap = mB - mA;
            if (gap <= 1) return;
            for (let step = 1; step < gap; step++) {
                const t = step / gap;
                const ik = mToAge(mA + step);
                // Don't overwrite real records
                if (store.records[ik] && !store.records[ik]._interpolated && !store.records[ik]._interpolated2) continue;
                const iSI = Math.round(siA + (siB - siA) * t);
                const iInt = skAint.map((sa, j) => sa + Math.floor(((skBint[j] !== undefined ? skBint[j] : sa) - sa) * t));
                const iRou = Math.round((rouA + (rouB - rouA) * t) * 10) / 10;
                const iFullSk = (iSI > 0 && iInt.length) ? computeDecimalSkills(iInt, iSI, isGK, gw) : iInt;
                store.records[ik] = {
                    SI: iSI,
                    REREC: Number(calcRemainders(posIdx, iFullSk, iSI).rec),
                    R5: Number(calcR5(posIdx, iFullSk, iSI, iRou)),
                    skills: iFullSk,
                    routine: iRou,
                    _interpolated2: true,
                };
            }
        };

        // Fill gaps between consecutive real records
        for (let i = 0; i < realKeys.length - 1; i++) {
            const kA = realKeys[i], kB = realKeys[i + 1];
            const rA = store.records[kA], rB = store.records[kB];
            if (!rA.skills || !rB.skills) continue;
            const skAint = rA.skills.map(v => Math.floor(typeof v === 'string' ? parseFloat(v) : v));
            const skBint = rB.skills.map(v => Math.floor(typeof v === 'string' ? parseFloat(v) : v));
            makeInterp(parseInt(rA.SI) || 0, skAint, rA.routine || 0,
                parseInt(rB.SI) || 0, skBint, rB.routine || 0,
                ageToM(kA), ageToM(kB));
        }

        // Recompute TI for all records
        const allKeys = Object.keys(store.records).sort((a, b) => ageToM(a) - ageToM(b));
        for (let i = 1; i < allKeys.length; i++) {
            const rec = store.records[allKeys[i]];
            const prevSI = Number(store.records[allKeys[i - 1]].SI) || 0;
            const curSI = Number(rec.SI) || 0;
            if (prevSI > 0 && curSI > 0) {
                const K = isGK ? ASI_WEIGHT_GK : ASI_WEIGHT_OUTFIELD;
                rec.TI = Math.round((Math.pow(curSI * K, 1 / 7) - Math.pow(prevSI * K, 1 / 7)) * 10);
            } else {
                rec.TI = null;
            }
        }
    };

    /* ═══ Compute decimal skills anchored on a previous record (tm-player.user.js style) ═══
       - Skills that crossed an integer boundary since prevRec → decimal snaps to 0.00
       - Skills at same integer level → keep prevRec decimals (proportional)
       - Normalize so Σ decimals = asiRemainder
       Falls back to training-aware computeDecimalSkills if no useful anchor.
    ═══════════════════════════════════════════════════════════════════ */
    const computeDecimalSkillsAnchored = (prevRec, intSk, liveAsi, isGK, gw) => {
        const KASIW = isGK ? ASI_WEIGHT_GK : ASI_WEIGHT_OUTFIELD;
        const totalPtsLive = Math.pow(2, Math.log(KASIW * liveAsi) / Math.log(128));
        const asiRemainder = totalPtsLive - intSk.reduce((a, b) => a + b, 0);
        const N = intSk.length;

        if (!prevRec || !prevRec.skills || prevRec.skills.length !== N || asiRemainder <= 0) {
            return computeDecimalSkills(intSk, liveAsi, isGK, gw);
        }

        const prevInt = prevRec.skills.map(v => Math.floor(typeof v === 'string' ? parseFloat(v) : v));
        const prevDec = prevRec.skills.map(v => {
            const f = typeof v === 'string' ? parseFloat(v) : v;
            return f >= 20 ? 0 : f - Math.floor(f);
        });

        // Skills that crossed at least one integer → snap decimal to 0.00
        // Skills at same integer → keep previous decimal as seed
        let newDec = prevDec.map((d, i) => (intSk[i] >= 20 || intSk[i] > prevInt[i]) ? 0 : d);

        // Normalize seed to asiRemainder
        const decSum = newDec.reduce((a, b) => a + b, 0);
        if (decSum > 0.001) {
            const scale = asiRemainder / decSum;
            newDec = newDec.map((d, i) => intSk[i] >= 20 ? 0 : d * scale);
        } else {
            // All skills improved (or no seed) — fall back to training-aware
            return computeDecimalSkills(intSk, liveAsi, isGK, gw);
        }

        // Cap at 0.99 with overflow redistribution (identical to player script Step 6)
        const CAP = 0.99;
        let passes = 0;
        do {
            let ovfl = 0, freeCount = 0;
            for (let i = 0; i < N; i++) {
                if (intSk[i] >= 20) { newDec[i] = 0; continue; }
                if (newDec[i] > CAP) { ovfl += newDec[i] - CAP; newDec[i] = CAP; }
                else if (newDec[i] < CAP) freeCount++;
            }
            if (ovfl > 0.0001 && freeCount > 0) {
                const add = ovfl / freeCount;
                for (let i = 0; i < N; i++) if (intSk[i] < 20 && newDec[i] < CAP) newDec[i] += add;
            } else break;
        } while (++passes < 20);

        return intSk.map((v, i) => v >= 20 ? 20 : v + newDec[i]);
    };

    /* ═══ Apply sync-real preview to store and save ═══ */
    const applySyncReal = async (pid, store, isGK, proposed) => {
        for (const { ageKey, rec } of proposed) {
            if (store.records[ageKey] && store.records[ageKey].locked) continue;
            store.records[ageKey] = rec;
        }
        // Recompute TI for all records
        const allKeys = Object.keys(store.records).sort((a, b) => ageToM(a) - ageToM(b));
        for (let i = 1; i < allKeys.length; i++) {
            const rec = store.records[allKeys[i]];
            const prevSI = Number(store.records[allKeys[i - 1]].SI) || 0;
            const curSI = Number(rec.SI) || 0;
            if (prevSI > 0 && curSI > 0) {
                const K = isGK ? ASI_WEIGHT_GK : ASI_WEIGHT_OUTFIELD;
                rec.TI = Math.round((Math.pow(curSI * K, 1 / 7) - Math.pow(prevSI * K, 1 / 7)) * 10);
            } else {
                rec.TI = null;
            }
        }
        await savePlayer(pid, store);
    };

    /* ═══ Compute sync-real preview (no save) ═══
       Walks ALL records chronologically:
         - LOCKED record → resets the chain anchor to that locked rec
         - non-locked record → recompute decimals anchored on prevRec, chain forward
       Handles INTERP between two LOCKED records as well as after the last one.
       Outputs _interpolated3 records. Live tooltip becomes new REAL.
       Returns array of proposed records WITHOUT modifying the store.
    ═══════════════════════════════════════════════════════════════════ */
    const computeSyncRealPreview = (store, isGK, livePlayer, gw, gpData) => {
        const favPos = livePlayer ? String(livePlayer.favposition) : (store.meta && store.meta.pos || 'mc');
        const posIdx = getPosIndex(favPos.split(',')[0].trim());
        const liveAsi = livePlayer ? Number(String(livePlayer.skill_index || 0).replace(/,/g, '')) || 0 : 0;
        const liveAgeY = livePlayer ? parseInt(livePlayer.age) || 0 : 0;
        const liveAgeM_months = livePlayer ? parseInt(livePlayer.months) || 0 : 0;
        const liveRou = livePlayer ? parseFloat(livePlayer.routine) || 0 : 0;
        const liveAgeKey = livePlayer ? `${liveAgeY}.${liveAgeM_months}` : null;

        const intSk = livePlayer ? skillsFromTooltip(livePlayer, isGK) : [];

        // Last locked key (for display in preview header)
        const lockedKeys = Object.keys(store.records)
            .filter(k => store.records[k].locked)
            .sort((a, b) => ageToM(a) - ageToM(b));
        const lastLockedKey = lockedKeys.length ? lockedKeys[lockedKeys.length - 1] : null;

        // All records sorted chronologically
        const allKeys = Object.keys(store.records).sort((a, b) => ageToM(a) - ageToM(b));

        // Build routineMap only when live data is available
        const routineMap = livePlayer
            ? buildRoutineMap(liveRou, liveAgeY, liveAgeM_months, gpData,
                [...allKeys.filter(k => !store.records[k].locked), ...(liveAgeKey ? [liveAgeKey] : [])])
            : {};

        const proposed = [];
        let prevRec = null;

        // Walk chronologically: locked resets anchor, non-locked gets recomputed and chains forward
        for (const k of allKeys) {
            const rec = store.records[k];
            if (rec.locked) {
                prevRec = rec;
            } else {
                const iIntSk = (rec.skills || []).map(v => Math.floor(typeof v === 'string' ? parseFloat(v) : v));
                const iSI = Number(rec.SI) || 0;
                // Use routineMap (live-based) when available, else fall back to stored routine
                const iRou = routineMap[k] !== undefined ? routineMap[k] : (rec.routine || liveRou);
                const iF = iSI > 0 && iIntSk.length ? computeDecimalSkillsAnchored(prevRec, iIntSk, iSI, isGK, gw) : iIntSk;
                const newRec = {
                    SI: iSI,
                    REREC: Number(calcRemainders(posIdx, iF, iSI).rec),
                    R5: Number(calcR5(posIdx, iF, iSI, iRou)),
                    skills: iF, routine: iRou, _estimated: true,
                };
                proposed.push({ ageKey: k, isNewReal: false, rec: newRec });
                prevRec = newRec;
            }
        }

        // Live tooltip endpoint — only when player data is available
        if (livePlayer && liveAgeKey) {
            const liveRouFinal = routineMap[liveAgeKey] !== undefined ? routineMap[liveAgeKey] : liveRou;
            const fullSk = liveAsi > 0 && intSk.length
                ? computeDecimalSkillsAnchored(prevRec, intSk, liveAsi, isGK, gw)
                : intSk;
            const liveR5 = Number(calcR5(posIdx, fullSk, liveAsi, liveRouFinal));
            const liveREC = Number(calcRemainders(posIdx, fullSk, liveAsi).rec);

            proposed.push({
                ageKey: liveAgeKey,
                isNewReal: true,
                rec: { SI: liveAsi, REREC: liveREC, R5: liveR5, skills: fullSk, routine: liveRouFinal },
            });
        }

        return { lastLockedKey, proposed };
    };

    /* ═══ Fetch live player data from tooltip endpoint ═══ */
    const fetchPlayerTooltip = pid => window.TmApi.fetchTooltipRaw(pid);

    const skillsFromTooltip = (player, isGK) => {
        const names = isGK ? TOOLTIP_NAMES_GK : TOOLTIP_NAMES_FIELD;
        return names.map(name => {
            const sk = (player.skills || []).find(s => s.name === name);
            if (!sk) return 0;
            const v = sk.value;
            if (typeof v === 'string') {
                if (v.includes('star_silver') || v.includes('19')) return 19;
                if (v.includes('star') || v.includes('20')) return 20;
                return parseInt(v) || 0;
            }
            return Math.floor(Number(v)) || 0;
        });
    };

    /* ═══ Format helpers ═══ */
    const fmtSkills = (skills, isGK) => {
        if (!skills || !skills.length) return '—';
        const names = isGK ? SKILL_NAMES_GK : SKILL_NAMES_FIELD;
        return names.map((n, i) => {
            const v = skills[i];
            const vStr = typeof v === 'number' && v % 1 !== 0 ? v.toFixed(2) : String(v != null ? v : '?');
            return `<span style="color:#aaa">${n}:</span>${vStr}`;
        }).join(' ');
    };


    /* ═══ Main state ═══ */
    let allDB = {};
    let containerRef = null;

    const getPlayerList = () => {
        const playerList = [];
        for (const [pid, store] of Object.entries(allDB)) {
            if (!store || !store.records) continue;
            const keys = Object.keys(store.records);
            const interpKeys = keys.filter(k => store.records[k]._interpolated);
            const interp2Keys = keys.filter(k => store.records[k]._interpolated2);
            const estimatedKeys = keys.filter(k => store.records[k]._estimated);
            const lockedKeys = keys.filter(k => store.records[k].locked);
            const plainRealKeys = keys.filter(k => !store.records[k].locked && !store.records[k]._interpolated && !store.records[k]._interpolated2 && !store.records[k]._estimated);
            playerList.push({
                pid, store,
                name: (store.meta && store.meta.name) || '?',
                country: (store.meta && store.meta.country) || '',
                isGK: !!(store.meta && store.meta.isGK),
                pos: (store.meta && store.meta.pos) || '',
                totalRecords: keys.length,
                interpCount: interpKeys.length,
                interp2Count: interp2Keys.length,
                estimatedCount: estimatedKeys.length,
                realCount: keys.length - interpKeys.length - interp2Keys.length - estimatedKeys.length,
                lockedCount: lockedKeys.length,
                plainRealCount: plainRealKeys.length,
            });
        }
        return playerList;
    };

    const render = () => {
        const allPlayers = getPlayerList();
        const playersWithInterp = allPlayers.filter(p => p.interpCount > 0 || p.interp2Count > 0);
        playersWithInterp.sort((a, b) => b.interpCount - a.interpCount);

        const totalPlayers = Object.keys(allDB).length;
        const withOldInterp = allPlayers.filter(p => p.interpCount > 0).length;
        const cleanEstimated = allPlayers.filter(p => p.estimatedCount > 0 && p.lockedCount + p.interp2Count + p.estimatedCount >= p.totalRecords).length;

        let html = `<div class="dbi-wrap">`;
        html += `<div class="dbi-title">DB Inspector</div>`;
        html += `<div class="dbi-stats">${totalPlayers} players total — ${withOldInterp} with old interp — <span style="color:#c090ff">${cleanEstimated} clean (estimated)</span> — <strong style="color:#e0e0e0">${playersWithInterp.length} shown</strong></div>`;
        html += `<div class="dbi-filter">
            <label>Sort by:</label>
            <select id="dbi-sort">
                <option value="interp">Most interpolated</option>
                <option value="name">Name</option>
                <option value="ratio">Interp ratio</option>
            </select>
            <label>Search:</label>
            <input type="text" id="dbi-search" placeholder="Player name or ID...">
            <button class="dbi-sync-all" id="dbi-sync-all">🔄 Re-sync All</button>
            <button class="dbi-syncreal-all" id="dbi-syncreal-all">🔧 Sync Real All</button>
            <button class="dbi-migrate-btn" id="dbi-migrate-i3">🔁 Migrate interp3→estimated</button>
            <label style="margin-left:12px"><input type="checkbox" id="dbi-invert"> Invert</label>
            <span class="dbi-status" id="dbi-global-status"></span>
            <span class="dbi-status" id="dbi-syncreal-all-status"></span>
            <span class="dbi-status" id="dbi-migrate-status"></span>
        </div>`;

        html += `<div id="dbi-list">`;
        playersWithInterp.forEach((p, idx) => { html += buildPlayerHTML(p, idx); });
        html += `</div></div>`;

        TmDbInspectStyles.inject();

        containerRef = document.createElement('div');
        containerRef.innerHTML = html;

        const main = document.querySelector('#content') || document.querySelector('.container') || document.body;
        main.prepend(containerRef);

        bindEvents(playersWithInterp);
    };

    const bindEvents = (playersList) => {
        // Expand/collapse
        containerRef.querySelectorAll('.dbi-header').forEach(hdr => {
            hdr.addEventListener('click', e => {
                if (e.target.closest('.dbi-sync-btn')) return; // don't toggle on sync click
                const arrow = hdr.querySelector('.dbi-arrow');
                const recs = hdr.nextElementSibling;
                arrow.classList.toggle('open');
                recs.classList.toggle('open');
            });
        });

        // Per-player Sync Real (preview) buttons
        containerRef.querySelectorAll('.dbi-syncreal-btn').forEach(btn => {
            btn.addEventListener('click', async e => {
                e.stopPropagation();
                const pid = btn.dataset.pid;
                const p = playersList.find(x => x.pid === pid);
                if (!p) return;
                btn.disabled = true;
                btn.textContent = '⏳…';
                try {
                    const [tooltipData, gw, gpData] = await Promise.all([
                        fetchPlayerTooltip(pid),
                        fetchTrainingWeights(pid, p.isGK),
                        fetchHistoryGP(pid),
                    ]);
                    const player = tooltipData && tooltipData.player;
                    if (!player) { btn.textContent = '❌ No data'; btn.disabled = false; return; }

                    const { lastLockedKey, proposed } = computeSyncRealPreview(p.store, p.isGK, player, gw, gpData);

                    const playerEl = btn.closest('.dbi-player');
                    const recsEl = playerEl.querySelector('.dbi-records');

                    // Remove previous preview
                    const oldPreview = recsEl.querySelector('.dbi-preview-wrap');
                    if (oldPreview) oldPreview.remove();

                    // Build preview HTML
                    let ph = `<div class="dbi-preview-wrap">`;
                    ph += `<div class="dbi-preview-title">⚠️ PREVIEW — proposed changes (not saved)</div>`;
                    ph += `<div class="dbi-preview-anchor">Anchor: ${lastLockedKey ? `LOCKED @ ${lastLockedKey}` : 'no locked record — full fill from nothing'}</div>`;
                    ph += `<table class="dbi-rec-tbl"><thead><tr>`;
                    ph += `<th>Age</th><th>Type</th><th>SI</th><th>R5</th><th>REC</th><th>Rtn</th><th>Skills</th>`;
                    ph += `</tr></thead><tbody>`;
                    for (const { ageKey, rec, isNewReal } of proposed) {
                        const cls = isNewReal ? 'preview-real' : 'preview-interp';
                        const badge = isNewReal
                            ? '<span class="dbi-badge dbi-badge-preview-real">NEW REAL</span>'
                            : '<span class="dbi-badge dbi-badge-preview-interp">NEW ESTIMATED</span>';
                        ph += `<tr class="${cls}">`;
                        ph += `<td>${ageKey}</td><td>${badge}</td><td>${rec.SI}</td>`;
                        ph += `<td>${Number(rec.R5).toFixed(2)}</td><td>${Number(rec.REREC).toFixed(2)}</td>`;
                        ph += `<td>${rec.routine}</td>`;
                        ph += `<td class="dbi-skills">${fmtSkills(rec.skills, p.isGK)}</td>`;
                        ph += `</tr>`;
                    }
                    ph += `</tbody></table></div>`;

                    recsEl.insertAdjacentHTML('beforeend', ph);
                    recsEl.classList.add('open');
                    playerEl.querySelector('.dbi-arrow').classList.add('open');

                    btn.textContent = '✅ Preview ready';
                    btn.disabled = false;
                } catch (err) {
                    btn.textContent = '❌ Error';
                    btn.disabled = false;
                    console.error('[DBI] syncreal failed', pid, err);
                }
            });
        });

        // Per-player fetch buttons
        containerRef.querySelectorAll('.dbi-fetch-btn').forEach(btn => {
            btn.addEventListener('click', async e => {
                e.stopPropagation();
                const pid = btn.dataset.pid;
                const p = playersList.find(x => x.pid === pid);
                if (!p) return;
                btn.disabled = true;
                btn.textContent = '⏳…';
                try {
                    const data = await fetchPlayerTooltip(pid);
                    const player = data && data.player;
                    if (!player) { btn.textContent = '❌ No data'; btn.disabled = false; return; }
                    const liveIsGK = String(player.favposition).split(',')[0].trim().toLowerCase() === 'gk';
                    const liveAsi = Number(String(player.skill_index || 0).replace(/,/g, '')) || 0;
                    const liveAgeY = parseInt(player.age) || 0;
                    const liveAgeM = parseInt(player.months) || 0;
                    const liveRou = parseFloat(player.routine) || 0;
                    const liveFP = String(player.favposition);
                    const livePosIdx = getPosIndex(liveFP.split(',')[0].trim());
                    const intSk = skillsFromTooltip(player, liveIsGK);
                    const gw = null; // balanced for preview — training fetch separate
                    const fullSk = liveAsi > 0 && intSk.length ? computeDecimalSkills(intSk, liveAsi, liveIsGK, gw) : intSk;
                    const liveREC = Number(calcRemainders(livePosIdx, fullSk, liveAsi).rec);
                    const liveR5 = Number(calcR5(livePosIdx, fullSk, liveAsi, liveRou));
                    const ageKey = `${liveAgeY}.${liveAgeM}`;
                    // Inject live row into this player's table
                    const playerEl = btn.closest('.dbi-player');
                    const tbl = playerEl.querySelector('.dbi-rec-tbl tbody');
                    if (tbl) {
                        // Remove previous live rows
                        tbl.querySelectorAll('tr.live').forEach(r => r.remove());
                        const badge = '<span class="dbi-badge dbi-badge-live">LIVE</span>';
                        const tr = document.createElement('tr');
                        tr.className = 'live';
                        tr.innerHTML = `<td>${ageKey}</td><td>${badge}</td><td>${liveAsi}</td>` +
                            `<td>${liveR5.toFixed(2)}</td><td>${liveREC.toFixed(2)}</td>` +
                            `<td>${liveRou}</td><td>—</td>` +
                            `<td class="dbi-skills">${fmtSkills(fullSk, liveIsGK)}</td>`;
                        tbl.appendChild(tr);
                        // Ensure table is visible
                        const recsEl = playerEl.querySelector('.dbi-records');
                        const arrow = playerEl.querySelector('.dbi-arrow');
                        recsEl.classList.add('open');
                        arrow.classList.add('open');
                    }
                    btn.textContent = '✅ Fetched';
                    btn.disabled = false;
                } catch (err) {
                    btn.textContent = '❌ Error';
                    btn.disabled = false;
                    console.error('[DBI] fetch failed', pid, err);
                }
            });
        });

        // Per-player sync buttons
        containerRef.querySelectorAll('.dbi-sync-btn').forEach(btn => {
            btn.addEventListener('click', async e => {
                e.stopPropagation();
                const pid = btn.dataset.pid;
                const p = playersList.find(x => x.pid === pid);
                if (!p) return;
                btn.disabled = true;
                btn.textContent = '⏳…';
                try {
                    const gw = await fetchTrainingWeights(pid, p.isGK);
                    reInterpolate(p.store, p.isGK, gw);
                    await savePlayer(pid, p.store);
                    allDB[pid] = p.store;
                    btn.textContent = '✅ Done';
                    // Refresh this player's record table
                    const playerEl = btn.closest('.dbi-player');
                    const recsEl = playerEl.querySelector('.dbi-records');
                    recsEl.innerHTML = buildRecordsHTML(p.store, p.isGK);
                    // Update counts in header
                    const keys = Object.keys(p.store.records);
                    const ic = keys.filter(k => p.store.records[k]._interpolated).length;
                    const i2c = keys.filter(k => p.store.records[k]._interpolated2).length;
                    const i3c = keys.filter(k => p.store.records[k]._estimated).length;
                    const rc = keys.length - ic - i2c - i3c;
                    const countEl = playerEl.querySelector('.dbi-interp-count');
                    if (countEl) countEl.textContent = ic > 0
                        ? `${ic} interp / ${keys.length} total (${rc} real)`
                        : i3c > 0
                            ? `${i3c} estimated / ${keys.length} total (${rc} real)`
                            : `${i2c} interp2 / ${keys.length} total (${rc} real)`;
                } catch (err) {
                    btn.textContent = '❌ Error';
                    console.error('[DBI] sync failed', pid, err);
                }
            });
        });

        // Sort
        const isInverted = () => document.getElementById('dbi-invert')?.checked;
        const filterPlayers = () => {
            const inv = isInverted();
            return getPlayerList().filter(p => inv
                ? p.lockedCount + p.interp2Count + p.estimatedCount >= p.totalRecords || p.totalRecords <= 1
                : p.lockedCount + p.interp2Count + p.estimatedCount < p.totalRecords && p.totalRecords > 1
            );
        };

        document.getElementById('dbi-invert').addEventListener('change', () => {
            const q = document.getElementById('dbi-search').value.toLowerCase().trim();
            const list = filterPlayers();
            reRenderList(q ? list.filter(p => p.name.toLowerCase().includes(q) || p.pid.includes(q)) : list);
        });

        document.getElementById('dbi-sort').addEventListener('change', e => {
            const v = e.target.value;
            const list = filterPlayers();
            if (v === 'name') list.sort((a, b) => a.name.localeCompare(b.name));
            else if (v === 'ratio') list.sort((a, b) => (b.interpCount / b.totalRecords) - (a.interpCount / a.totalRecords));
            else list.sort((a, b) => b.interpCount - a.interpCount);
            reRenderList(list);
        });

        // Search
        document.getElementById('dbi-search').addEventListener('input', e => {
            const q = e.target.value.toLowerCase().trim();
            const list = filterPlayers();
            const filtered = q ? list.filter(p => p.name.toLowerCase().includes(q) || p.pid.includes(q)) : list;
            reRenderList(filtered);
        });

        // Sync All
        document.getElementById('dbi-sync-all').addEventListener('click', async () => {
            const btn = document.getElementById('dbi-sync-all');
            const statusEl = document.getElementById('dbi-global-status');
            btn.disabled = true;
            const list = getPlayerList().filter(p => p.interpCount > 0); // only those with old _interpolated
            for (let i = 0; i < list.length; i++) {
                const p = list[i];
                statusEl.textContent = `Syncing ${i + 1}/${list.length}: ${p.name}…`;
                try {
                    const gw = await fetchTrainingWeights(p.pid, p.isGK);
                    reInterpolate(p.store, p.isGK, gw);
                    await savePlayer(p.pid, p.store);
                    allDB[p.pid] = p.store;
                } catch (err) {
                    console.error('[DBI] sync all failed for', p.pid, err);
                }
                // Small delay between API calls
                if (i < list.length - 1) await new Promise(r => setTimeout(r, 200));
            }
            statusEl.textContent = `✅ Done — ${list.length} players re-synced`;
            btn.disabled = false;
            // Refresh full list
            reRenderList(getPlayerList().filter(p => p.lockedCount + p.interp2Count + p.estimatedCount < p.totalRecords && p.totalRecords > 1));
        });

        // Sync Real All
        document.getElementById('dbi-syncreal-all').addEventListener('click', async () => {
            const btn = document.getElementById('dbi-syncreal-all');
            const statusEl = document.getElementById('dbi-syncreal-all-status');
            btn.disabled = true;
            document.getElementById('dbi-sync-all').disabled = true;
            let done = 0, failed = 0;
            const syncList = playersList.filter(p => p.interpCount > 0 || p.interp2Count > 0);
            const total = syncList.length;
            statusEl.textContent = `0/${total} (0.00%) synced…`;
            for (let i = 0; i < syncList.length; i++) {
                const p = syncList[i];
                const pct = ((i + 1) / total * 100).toFixed(2);
                statusEl.textContent = `${i + 1}/${total} (${pct}%): ${p.name}…`;
                try {
                    // All data is already in DB — no network requests needed for bulk sync
                    const { proposed } = computeSyncRealPreview(p.store, p.isGK, null, null, null);
                    await applySyncReal(p.pid, p.store, p.isGK, proposed);
                    allDB[p.pid] = p.store;
                    done++;
                } catch (err) {
                    failed++;
                    console.error('[DBI] sync real all failed for', p.pid, err);
                }
            }
            statusEl.textContent = `✅ Done — ${done}/${total} synced${failed ? `, ${failed} failed` : ''}`;
            btn.disabled = false;
            document.getElementById('dbi-sync-all').disabled = false;
        });

        // Migrate _interpolated3 → _estimated
        document.getElementById('dbi-migrate-i3').addEventListener('click', async () => {
            const btn = document.getElementById('dbi-migrate-i3');
            const statusEl = document.getElementById('dbi-migrate-status');
            btn.disabled = true;
            let migrated = 0, skipped = 0;
            for (const [pid, store] of Object.entries(allDB)) {
                let changed = false;
                for (const k of Object.keys(store.records)) {
                    const rec = store.records[k];
                    if (rec._interpolated3) {
                        delete rec._interpolated3;
                        rec._estimated = true;
                        changed = true;
                    }
                }
                if (changed) {
                    await savePlayer(pid, store);
                    allDB[pid] = store;
                    migrated++;
                } else {
                    skipped++;
                }
            }
            statusEl.textContent = `✅ Migrated ${migrated} players (${skipped} already clean)`;
            btn.disabled = false;
            render();
        });
    };

    const reRenderList = (players) => {
        const list = containerRef.querySelector('#dbi-list');
        let html = '';
        players.forEach((p, idx) => { html += buildPlayerHTML(p, idx); });
        list.innerHTML = html;
        bindEvents(players);
    };

    const buildRecordsHTML = (store, isGK) => {
        const keys = Object.keys(store.records).sort((a, b) => ageToM(a) - ageToM(b));
        let html = `<table class="dbi-rec-tbl"><thead><tr>`;
        html += `<th>Age</th><th>Type</th><th>SI</th><th>R5</th><th>REC</th><th>Rtn</th><th>TI</th><th>Skills</th>`;
        html += `</tr></thead><tbody>`;
        keys.forEach(k => {
            const rec = store.records[k];
            const isInterp = !!rec._interpolated;
            const isInterp2 = !!rec._interpolated2;
            const isEstimated = !!rec._estimated;
            const isLocked = !!rec.locked;
            let cls = 'real', badge = '';
            if (isInterp) { cls = 'interp'; badge = '<span class="dbi-badge dbi-badge-interp">INTERP</span>'; }
            else if (isInterp2) { cls = 'interp2'; badge = '<span class="dbi-badge dbi-badge-interp2">INTERP2</span>'; }
            else if (isEstimated) { cls = 'estimated'; badge = '<span class="dbi-badge dbi-badge-estimated">ESTIMATED</span>'; }
            else if (isLocked) { badge = '<span class="dbi-badge dbi-badge-locked">LOCKED</span>'; }
            else { badge = '<span class="dbi-badge dbi-badge-real">REAL</span>'; }
            html += `<tr class="${cls}">`;
            html += `<td>${k}</td><td>${badge}</td>`;
            html += `<td>${rec.SI || '—'}</td>`;
            html += `<td>${rec.R5 != null ? Number(rec.R5).toFixed(2) : '—'}</td>`;
            html += `<td>${rec.REREC != null ? Number(rec.REREC).toFixed(2) : '—'}</td>`;
            html += `<td>${rec.routine != null ? rec.routine : '—'}</td>`;
            html += `<td>${rec.TI != null ? rec.TI : '—'}</td>`;
            html += `<td class="dbi-skills">${fmtSkills(rec.skills, isGK)}</td>`;
            html += `</tr>`;
        });
        html += `</tbody></table>`;
        return html;
    };

    const buildPlayerHTML = (p) => {
        const keys = Object.keys(p.store.records);
        const ic = keys.filter(k => p.store.records[k]._interpolated).length;
        const i2c = keys.filter(k => p.store.records[k]._interpolated2).length;
        const i3c = keys.filter(k => p.store.records[k]._estimated).length;
        const rc = keys.length - ic - i2c - i3c;
        const countText = ic > 0
            ? `${ic} interp / ${keys.length} total (${rc} real)`
            : i3c > 0
                ? `${i3c} estimated / ${keys.length} total (${rc} real)`
                : i2c > 0
                    ? `${i2c} interp2 / ${keys.length} total (${rc} real)`
                    : `${keys.length} records (${rc} real)`;
        const showSync = ic > 0; // only show sync if old _interpolated exist

        let html = `<div class="dbi-player">`;
        html += `<div class="dbi-header">`;
        html += `<span class="dbi-arrow">▶</span>`;
        html += `<span class="dbi-pid">#${p.pid}</span>`;
        html += `<a class="dbi-name" href="https://trophymanager.com/players/${p.pid}/" target="_blank" rel="noopener">${p.name}</a>`;
        html += `<span class="dbi-country">${p.country}</span>`;
        html += `<span class="dbi-meta">${p.pos} ${p.isGK ? '(GK)' : ''}</span>`;
        html += `<span class="dbi-interp-count">${countText}</span>`;
        if (showSync) html += `<button class="dbi-sync-btn" data-pid="${p.pid}">🔄 Sync</button>`;
        html += `<button class="dbi-fetch-btn" data-pid="${p.pid}">📡 Fetch</button>`;
        html += `<button class="dbi-syncreal-btn" data-pid="${p.pid}">🔧 Sync Real</button>`;
        html += `</div>`;
        html += `<div class="dbi-records">${buildRecordsHTML(p.store, p.isGK)}</div>`;
        html += `</div>`;
        return html;
    };

    // Wait for page + jQuery, then open DB, load all, render
    const init = async () => {
        await openDB();
        allDB = await loadAll();
        render();
    };

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', () => init().catch(e => console.error('[DBInspect]', e)));
    } else {
        init().catch(e => console.error('[DBInspect]', e));
    }
})();



// ─── tm-dbrepair.user.js ─────────────────────────────────────────


(function () {
    'use strict';

    /* ─────────────────────────────────────────────────────────
       HELPERS
       ───────────────────────────────────────────────────────── */

    /**
     * Returns true if DBPlayer needs re-analysis:
     *   - any record has R5 or REREC null, OR
     *   - any record has all integer skills (no decimal portion stored)
     */
    const needsRepair = (DBPlayer) => {
        if (!DBPlayer?.records) return false;
        const recs = Object.values(DBPlayer.records);
        if (!recs.length) return false;
        return recs.some(r => {
            if (r.R5 == null || r.REREC == null) return true;
            if (!Array.isArray(r.skills)) return false;
            return r.skills.every(s => {
                const v = typeof s === 'object' ? parseFloat(s?.value) : parseFloat(s);
                return isFinite(v) && v % 1 === 0;
            });
        });
    };

    const META_FIELDS = ['name', 'pos', 'isGK', 'country', 'club_id'];

    const missingMetaFields = (DBPlayer) => {
        if (!DBPlayer?.meta) return META_FIELDS;
        return META_FIELDS.filter(f => DBPlayer.meta[f] == null || DBPlayer.meta[f] === '');
    };

    const needsMetaRepair = (DBPlayer) => missingMetaFields(DBPlayer).length > 0;

    const formatEta = (startTime, done, total) => {
        if (done <= 0) return '';
        const etaMs = (total - done) * (Date.now() - startTime) / done;
        if (!isFinite(etaMs) || etaMs < 1500) return '';
        const sec = Math.round(etaMs / 1000);
        if (sec < 60) return `~${sec}s left`;
        const min = Math.floor(sec / 60), s = sec % 60;
        return s > 0 ? `~${min}m ${s}s left` : `~${min}m left`;
    };

    /** Reconstruct trainingInfo from squad player object (has .training + .training_custom) */
    const buildTrainingInfoFromPlayer = (p) => {
        if (!p || (!p.training && !p.training_custom)) return null;
        const raw = p.training_custom;
        const customParsed = raw
            ? (typeof raw === 'object' ? raw : (() => { try { return JSON.parse(raw); } catch (e) { return null; } })())
            : null;
        return { custom: { team: String(p.training || '3'), custom_on: customParsed ? 1 : 0, custom: customParsed || {} } };
    };

    /**
     * Build a minimal fake player object from stored DB meta so we can call
     * analyzeGrowth without a live API-fetched player.
     * The multi-record analyzeGrowth path only needs: id, isGK, positions, routine.
     * Training and history are passed as null so no API calls are made.
     */
    const buildFakePlayer = (pid, DBPlayer) => {
        const meta = DBPlayer.meta || {};
        const recs = DBPlayer.records || {};
        const keys = Object.keys(recs).sort((a, b) =>
            window.TmUtils.ageToMonths(b) - window.TmUtils.ageToMonths(a));
        const latestKey = keys[0] || '18.0';
        const [ageStr, monthStr] = latestKey.split('.');
        const age = parseInt(ageStr) || 18;
        const months = parseInt(monthStr) || 0;

        // Determine isGK from meta, or infer from skill count (11 = GK, 14 = outfield)
        const firstSkills = recs[keys[0]]?.skills;
        const skillCount = Array.isArray(firstSkills) ? firstSkills.length : 14;
        const isGK = meta.isGK != null ? meta.isGK : (skillCount === 11);

        // Build positions array from stored favposition string
        let positions = [];
        if (meta.pos) {
            positions = String(meta.pos).split(',').map(s => {
                return window.TmConst.POSITION_MAP[s.trim().toLowerCase()];
            }).filter(Boolean);
        }
        if (!positions.length) {
            positions = isGK
                ? [window.TmConst.POSITION_MAP.gk]
                : [window.TmConst.POSITION_MAP.dc || { id: 0 }];
        }

        // skills from latest record — needed for single-record analyzeGrowth path (calcSkillDecimalsSimple)
        const latestSkills = recs[latestKey]?.skills;
        const skills = Array.isArray(latestSkills)
            ? latestSkills.map(v => typeof v === 'object' && v !== null ? parseFloat(v.value) || 0 : parseFloat(v) || 0)
            : [];

        return {
            id: pid,
            isGK,
            positions,
            skills,
            routine: recs[latestKey]?.routine ?? 0,
            age,
            months,
            ageMonthsString: latestKey,
            asi: parseInt(recs[latestKey]?.SI) || 0,
        };
    };

    /* ─────────────────────────────────────────────────────────
       UI
       ───────────────────────────────────────────────────────── */

    const injectUI = () => {
        TmDbRepairStyles.inject();

        const panel = document.createElement('div');
        panel.id = 'tmrep-panel';
        panel.innerHTML = `
            <h2>🔧 DB Repair Tool</h2>
            <div id="tmrep-stats">Scanning...</div>
            <button id="tmrep-btn" class="tmrep-btn" disabled>Repair All</button>
            <button id="tmrep-btn-others" class="tmrep-btn" disabled>Repair Others</button>
            <div class="tmrep-bar-wrap"><div id="tmrep-bar"></div></div>
            <div id="tmrep-status"></div>
            <div id="tmrep-log"></div>
        `;

        const target = document.querySelector('#middle_column') || document.body;
        target.insertBefore(panel, target.firstChild);

        // Meta repair panel
        const metaPanel = document.createElement('div');
        metaPanel.id = 'tmmeta-panel';
        metaPanel.innerHTML = `
            <h2>🏷️ Meta Repair Tool</h2>
            <div id="tmmeta-stats">Scanning...</div>
            <button id="tmmeta-btn" class="tmrep-btn" disabled>Fix Meta</button>
            <div class="tmrep-bar-wrap"><div id="tmmeta-bar"></div></div>
            <div id="tmmeta-status"></div>
            <div id="tmmeta-log"></div>
        `;
        target.insertBefore(metaPanel, target.firstChild);

        // Routine repair panel
        const rtnPanel = document.createElement('div');
        rtnPanel.id = 'tmrtn-panel';
        rtnPanel.innerHTML = `
            <h2>&#x23f1;&#xfe0f; Routine Repair Tool</h2>
            <div id="tmrtn-stats">Scanning...</div>
            <button id="tmrtn-btn" class="tmrep-btn" disabled>Fix Routine</button>
            <div class="tmrep-bar-wrap"><div id="tmrtn-bar"></div></div>
            <div id="tmrtn-status"></div>
            <div id="tmrtn-log"></div>
        `;
        target.insertBefore(rtnPanel, target.firstChild);

        // Key type fix panel
        const keyPanel = document.createElement('div');
        keyPanel.id = 'tmkey-panel';
        keyPanel.innerHTML = `
            <h2>&#x1f511; Key Type Fix</h2>
            <div id="tmkey-stats">Scanning...</div>
            <button id="tmkey-btn" class="tmrep-btn" disabled>Fix String Keys</button>
            <button id="tmkey-del-btn" class="tmrep-btn" disabled>Delete String Keys</button>
            <div class="tmrep-bar-wrap"><div id="tmkey-bar"></div></div>
            <div id="tmkey-status"></div>
            <div id="tmkey-log"></div>
        `;
        target.insertBefore(keyPanel, target.firstChild);
    };

    /* ─────────────────────────────────────────────────────────
       META SCAN + REPAIR LOGIC
       ───────────────────────────────────────────────────────── */

    let brokenMetaPids = [];
    let isMetaRunning = false;

    const logMeta = (msg, cls = 'tmrep-info') => {
        const el = document.getElementById('tmmeta-log');
        if (!el) return;
        const line = document.createElement('div');
        line.className = cls;
        line.textContent = msg;
        el.appendChild(line);
        el.scrollTop = el.scrollHeight;
    };

    const scanMeta = () => {
        const all = window.TmPlayerDB.allPids();
        brokenMetaPids = all.filter(pid => needsMetaRepair(window.TmPlayerDB.get(pid)));

        const statsEl = document.getElementById('tmmeta-stats');
        if (statsEl) {
            const breakdown = META_FIELDS.map(f => {
                const count = brokenMetaPids.filter(pid => {
                    const db = window.TmPlayerDB.get(pid);
                    return db?.meta == null || db.meta[f] == null || db.meta[f] === '';
                }).length;
                return count ? `${f}: ${count}` : null;
            }).filter(Boolean).join(', ');
            statsEl.innerHTML =
                `Tracked: <strong>${all.length}</strong> players — ` +
                `Missing meta: <strong style="color:#6cc040">${brokenMetaPids.length}</strong>` +
                (breakdown ? ` (${breakdown})` : '');
        }

        const btn = document.getElementById('tmmeta-btn');
        if (btn) btn.disabled = brokenMetaPids.length === 0;
    };

    const runMetaRepair = async () => {
        if (isMetaRunning || !brokenMetaPids.length) return;
        isMetaRunning = true;

        const btn = document.getElementById('tmmeta-btn');
        if (btn) btn.disabled = true;

        const logEl = document.getElementById('tmmeta-log');
        if (logEl) logEl.innerHTML = '';

        const total = brokenMetaPids.length;
        let done = 0, fixed = 0, failed = 0;

        const updateBar = () => {
            const bar = document.getElementById('tmmeta-bar');
            if (bar) bar.style.width = Math.round((done / total) * 100) + '%';
        };

        const startTime = Date.now();
        const updateStatus = (name = '') => {
            updateBar();
            const eta = formatEta(startTime, done, total);
            const statusEl = document.getElementById('tmmeta-status');
            if (statusEl) statusEl.textContent = `${done} / ${total}${name ? '  —  ' + name : ''}${eta ? '  |  ' + eta : ''}`;
        };

        // remaining: every broken pid — removed as soon as found in any squad response
        const remaining = new Set(brokenMetaPids.map(String));

        // stillBrokenAfterSquad: found in squad but meta still incomplete → needs tooltip
        const stillBrokenAfterSquad = [];

        // Clubs to fetch squads for — deduplicated list from players with a known club_id
        const clubsToFetch = [...new Set(
            brokenMetaPids
                .map(pid => window.TmPlayerDB.get(pid)?.meta?.club_id)
                .filter(Boolean)
        )];

        const noClubCount = brokenMetaPids.length - clubsToFetch.reduce(
            (acc, cid) => acc + brokenMetaPids.filter(p => window.TmPlayerDB.get(p)?.meta?.club_id === cid).length, 0);

        logMeta(`Phase 1: ${clubsToFetch.length} squad fetch(es) — scanning all squad members against ${total} tracked players (${noClubCount} have no club_id, may be caught opportunistically)...`);

        // Phase 1 — squad fetches
        // For each squad response we scan ALL players in post, not just expected ones.
        // This opportunistically resolves even "no club_id" players if they happen to be in fetched squads.
        for (const clubId of clubsToFetch) {
            // Skip if all known members of this club were already resolved by a previous squad fetch
            const hasAnyLeft = brokenMetaPids.some(p =>
                remaining.has(String(p)) && window.TmPlayerDB.get(p)?.meta?.club_id === clubId
            );
            if (!hasAnyLeft && !remaining.size) break;

            updateStatus(`Club ${clubId}…`);
            try {
                const squadData = await window.TmApi.fetchSquadRaw(clubId);
                // fetchSquadRaw already called normalizePlayer → _migratePlayerMeta for every player in the squad,
                // which auto-fills name/country/pos/isGK/club_id in the DB cache.

                for (const sp of (squadData?.post || [])) {
                    const pid = String(sp.id || sp.player_id);
                    if (!remaining.has(pid)) continue;  // not one of ours (or already resolved)
                    remaining.delete(pid);  // claim immediately — won't be picked up again

                    // patch name if _migratePlayerMeta left it empty (player_name alias timing)
                    const db = window.TmPlayerDB.get(pid);
                    if (db?.meta && !db.meta.name && sp.player_name) {
                        db.meta.name = sp.player_name;
                        await window.TmPlayerDB.set(pid, db);
                    }

                    done++;

                    if (needsMetaRepair(window.TmPlayerDB.get(pid))) {
                        logMeta(`~ ${sp.player_name || '#' + pid} (${pid}) still incomplete → tooltip fallback`, 'tmrep-info');
                        stillBrokenAfterSquad.push(pid);
                    } else {
                        fixed++;
                        logMeta(`✓ ${sp.player_name || '#' + pid} (${pid}) [squad]`, 'tmrep-ok');
                    }
                    updateStatus(sp.player_name || '#' + pid);
                }

                // Any expected pids from this club not found in squad → transferred
                for (const pid of (brokenMetaPids.filter(p =>
                    remaining.has(String(p)) && window.TmPlayerDB.get(p)?.meta?.club_id === clubId
                ))) {
                    remaining.delete(pid);
                    done++;
                    logMeta(`~ #${pid} not in squad ${clubId} → tooltip fallback`, 'tmrep-info');
                    stillBrokenAfterSquad.push(pid);
                    updateStatus(`#${pid}`);
                }
            } catch (e) {
                // Squad fetch failed — move all known members of this club to tooltip fallback
                for (const pid of brokenMetaPids.filter(p =>
                    remaining.has(String(p)) && window.TmPlayerDB.get(p)?.meta?.club_id === clubId
                )) {
                    remaining.delete(pid);
                    done++;
                    stillBrokenAfterSquad.push(pid);
                }
                logMeta(`✗ squad ${clubId}: ${e.message} — falling back to tooltip`, 'tmrep-err');
                updateStatus(`Club ${clubId} error`);
            }
            await new Promise(r => setTimeout(r, 50));
        }

        // Phase 2 — tooltip for: still broken after squad + never found in any squad (remaining)
        const phase2 = [...stillBrokenAfterSquad, ...remaining];
        if (phase2.length) {
            logMeta(`Phase 2: tooltip for ${phase2.length} players...`);
            for (const pid of phase2) {
                const db = window.TmPlayerDB.get(pid);
                const nameHint = db?.meta?.name || `#${pid}`;
                // remaining pids were never counted in phase 1
                const wasCounted = !remaining.has(String(pid));
                if (!db) {
                    if (!wasCounted) { done++; updateStatus(nameHint); }
                    continue;
                }
                const missing = missingMetaFields(db);
                try {
                    const resp = await window.TmApi.fetchPlayerTooltip(pid);
                    const p = resp?.player;
                    if (!p) throw new Error('no player in response');
                    if (!db.meta) db.meta = {};
                    if (missing.includes('name') && p.name) db.meta.name = p.name;
                    if (missing.includes('pos') && p.favposition) db.meta.pos = p.favposition;
                    if (missing.includes('isGK')) db.meta.isGK = String(p.favposition || '').split(',')[0].trim().toLowerCase() === 'gk';
                    if (missing.includes('country') && p.country) db.meta.country = p.country;
                    if (p.club_id) db.meta.club_id = String(p.club_id);
                    await window.TmPlayerDB.set(pid, db);
                    fixed++;
                    logMeta(`✓ ${p.name || nameHint} (${pid}) — ${missing.join(', ')} [tooltip]`, 'tmrep-ok');
                } catch (e) {
                    failed++;
                    logMeta(`✗ ${nameHint} (${pid}): ${e.message}`, 'tmrep-err');
                }
                if (!wasCounted) { done++; }
                updateStatus(nameHint);
                await new Promise(r => setTimeout(r, 11));
            }
        }

        const bar = document.getElementById('tmmeta-bar');
        if (bar) bar.style.width = '100%';
        const statusEl = document.getElementById('tmmeta-status');
        if (statusEl) statusEl.textContent = `Done — ${fixed} fixed, ${failed} errors.`;
        logMeta(`─── Meta repair complete: ${fixed} fixed, ${failed} errors ───`);

        isMetaRunning = false;
    };

    /* ─────────────────────────────────────────────────────────
       ROUTINE SCAN + REPAIR LOGIC
       Players with null routine need historyInfo so
       buildRoutineMap can back-calculate per-week routine.
       ───────────────────────────────────────────────────────── */

    let brokenRtnPids = [];
    let isRtnRunning = false;

    const logRtn = (msg, cls = 'tmrep-info') => {
        const el = document.getElementById('tmrtn-log');
        if (!el) return;
        const line = document.createElement('div');
        line.className = cls;
        line.textContent = msg;
        el.appendChild(line);
        el.scrollTop = el.scrollHeight;
    };

    const needsRoutineRepair = (DBPlayer) => {
        if (!DBPlayer?.records) return false;
        return Object.values(DBPlayer.records).some(r => r.routine == null);
    };

    const scanRoutine = () => {
        const all = window.TmPlayerDB.allPids();
        brokenRtnPids = all.filter(pid => needsRoutineRepair(window.TmPlayerDB.get(pid)));
        const statsEl = document.getElementById('tmrtn-stats');
        if (statsEl) {
            statsEl.innerHTML =
                `Tracked: <strong>${all.length}</strong> players &mdash; ` +
                `Null routine: <strong style="color:#6cc040">${brokenRtnPids.length}</strong>`;
        }
        const btn = document.getElementById('tmrtn-btn');
        if (btn) btn.disabled = brokenRtnPids.length === 0;
    };

    const runRoutineRepair = async () => {
        if (isRtnRunning || !brokenRtnPids.length) return;
        isRtnRunning = true;

        const btn = document.getElementById('tmrtn-btn');
        if (btn) btn.disabled = true;

        const logEl = document.getElementById('tmrtn-log');
        if (logEl) logEl.innerHTML = '';

        const total = brokenRtnPids.length;
        let done = 0, fixed = 0, failed = 0;
        const startTime = Date.now();

        logRtn(`Fetching history for ${total} players with null routine...`);

        for (const pid of brokenRtnPids) {
            const db = window.TmPlayerDB.get(pid);
            if (!db) { done++; continue; }

            const name = db.meta?.name || `#${pid}`;
            const nullCount = Object.values(db.records || {}).filter(r => r.routine == null).length;

            try {
                const fakePlayer = buildFakePlayer(pid, db);
                const [tooltipResp, historyInfo] = await Promise.all([
                    window.TmApi.fetchPlayerTooltip(pid),
                    window.TmApi.fetchPlayerInfo(pid, 'history'),
                ]);
                // fakePlayer.routine comes from DB (null→0), so override with the live value
                const liveRoutine = tooltipResp?.player?.routine;
                if (liveRoutine != null) fakePlayer.routine = liveRoutine;
                await window.TmSync.analyzeGrowth(fakePlayer, db, null, historyInfo);

                fixed++;
                logRtn(`✓ ${name} (${pid}) — ${nullCount} null routines filled`, 'tmrep-ok');
            } catch (e) {
                failed++;
                logRtn(`✗ ${name} (${pid}): ${e.message}`, 'tmrep-err');
            }

            done++;
            const bar = document.getElementById('tmrtn-bar');
            if (bar) bar.style.width = Math.round((done / total) * 100) + '%';
            const eta = formatEta(startTime, done, total);
            const statusEl = document.getElementById('tmrtn-status');
            if (statusEl) statusEl.textContent = `${done} / ${total}  —  ${name}${eta ? '  |  ' + eta : ''}`;

            await new Promise(r => setTimeout(r, 200));
        }

        const bar = document.getElementById('tmrtn-bar');
        if (bar) bar.style.width = '100%';
        const statusEl = document.getElementById('tmrtn-status');
        if (statusEl) statusEl.textContent = `Done — ${fixed} fixed, ${failed} errors.`;
        logRtn(`─── Routine repair complete: ${fixed} fixed, ${failed} errors ───`);

        isRtnRunning = false;
    };

    /* ─────────────────────────────────────────────────────────
       KEY TYPE FIX
       Copies string-keyed IDB records to integer keys.
       String keys are NOT deleted yet.
       ───────────────────────────────────────────────────────── */

    const logKey = (msg, cls = 'tmrep-info') => {
        const el = document.getElementById('tmkey-log');
        if (!el) return;
        const line = document.createElement('div');
        line.className = cls;
        line.textContent = msg;
        el.appendChild(line);
        el.scrollTop = el.scrollHeight;
    };

    const openRawDB = () => new Promise((resolve, reject) => {
        const req = indexedDB.open('TMPlayerData', 1);
        req.onsuccess = (e) => resolve(e.target.result);
        req.onerror = (e) => reject(e.target.error);
    });

    const getRawKeys = (db) => new Promise((resolve, reject) => {
        const tx = db.transaction('players', 'readonly');
        const req = tx.objectStore('players').getAllKeys();
        req.onsuccess = () => resolve(req.result);
        req.onerror = (e) => reject(e.target.error);
    });

    const getRawValue = (db, key) => new Promise((resolve, reject) => {
        const tx = db.transaction('players', 'readonly');
        const req = tx.objectStore('players').get(key);
        req.onsuccess = () => resolve(req.result);
        req.onerror = (e) => reject(e.target.error);
    });

    const putRawValue = (db, key, value) => new Promise((resolve, reject) => {
        const tx = db.transaction('players', 'readwrite');
        tx.objectStore('players').put(value, key);
        tx.oncomplete = () => resolve();
        tx.onerror = (e) => reject(e.target.error);
    });

    let stringKeyPids = [];
    let isKeyRunning = false;

    const scanKeyTypes = async () => {
        try {
            const db = await openRawDB();
            const keys = await getRawKeys(db);
            db.close();
            // string keys that look like integers
            stringKeyPids = keys.filter(k => typeof k === 'string' && /^\d+$/.test(k));
            const statsEl = document.getElementById('tmkey-stats');
            if (statsEl) {
                const intCount = keys.filter(k => typeof k === 'number').length;
                statsEl.innerHTML =
                    `Total IDB keys: <strong>${keys.length}</strong> — ` +
                    `Integer keys: <strong>${intCount}</strong> — ` +
                    `String keys to fix: <strong style="color:#6cc040">${stringKeyPids.length}</strong>`;
            }
            const btn = document.getElementById('tmkey-btn');
            if (btn) btn.disabled = stringKeyPids.length === 0;
            const delBtn = document.getElementById('tmkey-del-btn');
            if (delBtn) delBtn.disabled = stringKeyPids.length === 0;
        } catch (e) {
            const statsEl = document.getElementById('tmkey-stats');
            if (statsEl) statsEl.textContent = `Error scanning: ${e.message}`;
        }
    };

    const runKeyDelete = async () => {
        if (isKeyRunning || !stringKeyPids.length) return;
        isKeyRunning = true;
        document.getElementById('tmkey-btn')?.setAttribute('disabled', '');
        document.getElementById('tmkey-del-btn')?.setAttribute('disabled', '');
        document.getElementById('tmkey-log').innerHTML = '';

        const db = await openRawDB();
        const total = stringKeyPids.length;
        let done = 0, deleted = 0, failed = 0;
        const startTime = Date.now();

        logKey(`Deleting ${total} string-keyed records from IDB...`);

        for (const strKey of stringKeyPids) {
            try {
                await new Promise((resolve, reject) => {
                    const tx = db.transaction('players', 'readwrite');
                    tx.objectStore('players').delete(strKey);
                    tx.oncomplete = () => resolve();
                    tx.onerror = (e) => reject(e.target.error);
                });
                deleted++;
                logKey(`✓ deleted ${strKey}`, 'tmrep-ok');
            } catch (e) {
                failed++;
                logKey(`✗ ${strKey}: ${e.message}`, 'tmrep-err');
            }
            done++;
            const bar = document.getElementById('tmkey-bar');
            if (bar) bar.style.width = Math.round((done / total) * 100) + '%';
            const eta = formatEta(startTime, done, total);
            document.getElementById('tmkey-status').textContent = `${done} / ${total}${eta ? '  |  ' + eta : ''}`;
        }

        db.close();
        stringKeyPids = [];
        document.getElementById('tmkey-bar').style.width = '100%';
        document.getElementById('tmkey-status').textContent =
            `Done — ${deleted} deleted, ${failed} errors.`;
        logKey(`─── Delete complete: ${deleted} deleted, ${failed} errors ───`);
        isKeyRunning = false;
        // rescan to confirm
        await scanKeyTypes();
    };

    const runKeyFix = async () => {
        if (isKeyRunning || !stringKeyPids.length) return;
        isKeyRunning = true;
        document.getElementById('tmkey-btn')?.setAttribute('disabled', '');
        document.getElementById('tmkey-log').innerHTML = '';

        const db = await openRawDB();
        const allKeys = new Set(await getRawKeys(db));
        const total = stringKeyPids.length;
        let done = 0, copied = 0, skipped = 0, failed = 0;
        const startTime = Date.now();

        logKey(`Copying ${total} string-keyed records to integer keys (originals kept)...`);

        for (const strKey of stringKeyPids) {
            const intKey = parseInt(strKey);
            try {
                if (allKeys.has(intKey)) {
                    skipped++;
                    logKey(`~ ${strKey} — integer key already exists, skipped`, 'tmrep-info');
                } else {
                    const value = await getRawValue(db, strKey);
                    await putRawValue(db, intKey, value);
                    copied++;
                    logKey(`✓ ${strKey} → ${intKey}`, 'tmrep-ok');
                }
            } catch (e) {
                failed++;
                logKey(`✗ ${strKey}: ${e.message}`, 'tmrep-err');
            }
            done++;
            const bar = document.getElementById('tmkey-bar');
            if (bar) bar.style.width = Math.round((done / total) * 100) + '%';
            const eta = formatEta(startTime, done, total);
            document.getElementById('tmkey-status').textContent = `${done} / ${total}${eta ? '  |  ' + eta : ''}`;
        }

        db.close();
        document.getElementById('tmkey-bar').style.width = '100%';
        document.getElementById('tmkey-status').textContent =
            `Done — ${copied} copied, ${skipped} skipped (already existed), ${failed} errors.`;
        logKey(`─── Key fix complete: ${copied} copied, ${skipped} skipped, ${failed} errors ───`);
        isKeyRunning = false;
        // Enable delete button now that copies exist
        const delBtn = document.getElementById('tmkey-del-btn');
        if (delBtn && copied > 0) delBtn.removeAttribute('disabled');
    };

    /* ─────────────────────────────────────────────────────────
       SCAN + REPAIR LOGIC
       ───────────────────────────────────────────────────────── */

    let brokenPids = [];
    let otherPids = [];  // all non-own tracked players (independent of needsRepair)
    let isRunning = false;

    const log = (msg, cls = 'tmrep-info') => {
        const el = document.getElementById('tmrep-log');
        if (!el) return;
        const line = document.createElement('div');
        line.className = cls;
        line.textContent = msg;
        el.appendChild(line);
        el.scrollTop = el.scrollHeight;
    };

    const scan = () => {
        const all = window.TmPlayerDB.allPids();
        brokenPids = all.filter(pid => needsRepair(window.TmPlayerDB.get(pid)));

        const nullCount = brokenPids.filter(pid => {
            const db = window.TmPlayerDB.get(pid);
            return Object.values(db.records || {}).some(r => r.R5 == null || r.REREC == null);
        }).length;

        const intCount = brokenPids.filter(pid => {
            const db = window.TmPlayerDB.get(pid);
            return Object.values(db.records || {}).some(r =>
                r.R5 != null && r.REREC != null &&
                Array.isArray(r.skills) &&
                r.skills.every(s => { const v = typeof s === 'object' ? parseFloat(s?.value) : parseFloat(s); return isFinite(v) && v % 1 === 0; })
            );
        }).length;

        const s = window.SESSION;
        const ownClubIds = s ? [s.main_id, s.b_team].filter(Boolean).map(Number) : [];
        otherPids = all.filter(pid => {
            const clubId = window.TmPlayerDB.get(pid)?.meta?.club_id;
            if (clubId == null) return true;  // no club_id stored → assume non-own
            return !ownClubIds.includes(Number(clubId));
        });

        const statsEl = document.getElementById('tmrep-stats');
        if (statsEl) {
            statsEl.innerHTML =
                `Tracked: <strong>${all.length}</strong> players — ` +
                `Needs repair: <strong style="color:#6cc040">${brokenPids.length}</strong> ` +
                `(${nullCount} null R5/REREC, ${intCount} integer-only skills) — ` +
                `Others tracked: <strong style="color:#6cc040">${otherPids.length}</strong>`;
        }

        const btn = document.getElementById('tmrep-btn');
        if (btn) btn.disabled = brokenPids.length === 0;
        const btnOthers = document.getElementById('tmrep-btn-others');
        if (btnOthers) btnOthers.disabled = otherPids.length === 0;
    };

    const runRepair = async (pids) => {
        if (isRunning || !pids?.length) return;
        isRunning = true;

        document.getElementById('tmrep-btn')?.setAttribute('disabled', '');
        document.getElementById('tmrep-btn-others')?.setAttribute('disabled', '');

        const logEl = document.getElementById('tmrep-log');
        if (logEl) logEl.innerHTML = '';

        const total = pids.length;
        let done = 0, fixed = 0, failed = 0;
        const startTime = Date.now();

        const s = window.SESSION;
        const ownClubIds = s ? [s.main_id, s.b_team].filter(Boolean).map(Number) : [];
        const squadCache = {};  // clubId → fetchSquadRaw response (cached)

        log(`Fetching training and running analyzeGrowth for ${total} players...`);

        for (const pid of pids) {
            const db = window.TmPlayerDB.get(pid);
            if (!db) { done++; continue; }

            const name = db.meta?.name || `#${pid}`;
            const recCount = Object.keys(db.records || {}).length;

            try {
                const fakePlayer = buildFakePlayer(pid, db);

                const clubId = db.meta?.club_id ? String(db.meta.club_id) : null;
                const isOwnPlayer = clubId != null && ownClubIds.includes(Number(clubId));

                // Fetch training: own players → training endpoint; others → squad (cached per club)
                let trainingInfo = null;
                if (!fakePlayer.isGK) {
                    if (isOwnPlayer) {
                        trainingInfo = await window.TmApi.fetchPlayerInfo(pid, 'training');
                    } else {
                        let resolvedClubId = clubId;

                        // If we have a club_id, try squad first
                        if (resolvedClubId) {
                            if (!squadCache[resolvedClubId]) squadCache[resolvedClubId] = await window.TmApi.fetchSquadRaw(resolvedClubId);
                            const sp = (squadCache[resolvedClubId]?.post || []).find(p => String(p.id) === String(pid));
                            if (sp) {
                                trainingInfo = buildTrainingInfoFromPlayer(sp);
                            } else {
                                resolvedClubId = null;  // not in squad → transferred
                            }
                        }

                        // No club_id or player not found in old squad → fetch tooltip for current club
                        if (!resolvedClubId) {
                            const tooltipResp = await window.TmApi.fetchPlayerTooltip(pid);
                            const newClubId = tooltipResp?.player?.club_id ? String(tooltipResp.player.club_id) : null;
                            if (newClubId && newClubId !== clubId) {
                                if (!db.meta) db.meta = {};
                                db.meta.club_id = newClubId;
                                window.TmPlayerDB.set(pid, db);
                            }
                            resolvedClubId = newClubId;
                            if (resolvedClubId && !ownClubIds.includes(Number(resolvedClubId))) {
                                if (!squadCache[resolvedClubId]) squadCache[resolvedClubId] = await window.TmApi.fetchSquadRaw(resolvedClubId);
                                const sp = (squadCache[resolvedClubId]?.post || []).find(p => String(p.id) === String(pid));
                                trainingInfo = buildTrainingInfoFromPlayer(sp);
                            }
                        }
                    }
                }

                const historyInfo = null;  // routine already stored per record; buildRoutineMap falls back to rec.routine

                await window.TmSync.analyzeGrowth(fakePlayer, db, trainingInfo, historyInfo);

                // Small delay to avoid hammering the server
                await new Promise(r => setTimeout(r, 10));

                fixed++;
                log(`✓ ${name} (${pid}) — ${recCount} records`, 'tmrep-ok');
            } catch (e) {
                failed++;
                log(`✗ ${name} (${pid}): ${e.message}`, 'tmrep-err');
                const db2 = window.TmPlayerDB.get(pid);
                const fakeP2 = (() => { try { return buildFakePlayer(pid, db2); } catch (_) { return null; } })();
                console.group(`[REPAIR ERROR] pid=${pid} name=${name}`);
                console.error('Error:', e);
                console.log('fakePlayer:', fakeP2);
                console.log('DBPlayer.meta:', db2?.meta);
                console.log('DBPlayer.records:', db2?.records);
                console.groupEnd();
            }

            done++;
            const bar = document.getElementById('tmrep-bar');
            if (bar) bar.style.width = Math.round((done / total) * 100) + '%';
            const eta = formatEta(startTime, done, total);
            const statusEl = document.getElementById('tmrep-status');
            if (statusEl) statusEl.textContent = `${done} / ${total}  —  ${name}${eta ? '  |  ' + eta : ''}`;
        }

        const bar = document.getElementById('tmrep-bar');
        if (bar) bar.style.width = '100%';
        const statusEl = document.getElementById('tmrep-status');
        if (statusEl) statusEl.textContent = `Done — ${fixed} fixed, ${failed} errors.`;
        log(`─── Repair complete: ${fixed} fixed, ${failed} errors ───`, 'tmrep-info');

        isRunning = false;
    };

    /* ─────────────────────────────────────────────────────────
       INIT
       ───────────────────────────────────────────────────────── */

    const init = () => {
        injectUI();
        window.TmPlayerDB.init().then(() => {
            scan();
            const btn = document.getElementById('tmrep-btn');
            if (btn) btn.addEventListener('click', () => runRepair(brokenPids));
            const btnOthers = document.getElementById('tmrep-btn-others');
            if (btnOthers) btnOthers.addEventListener('click', () => runRepair(otherPids));

            scanMeta();
            const metaBtn = document.getElementById('tmmeta-btn');
            if (metaBtn) metaBtn.addEventListener('click', runMetaRepair);

            scanRoutine();
            const rtnBtn = document.getElementById('tmrtn-btn');
            if (rtnBtn) rtnBtn.addEventListener('click', runRoutineRepair);

            scanKeyTypes();
            const keyBtn = document.getElementById('tmkey-btn');
            if (keyBtn) keyBtn.addEventListener('click', runKeyFix);
            const keyDelBtn = document.getElementById('tmkey-del-btn');
            if (keyDelBtn) keyDelBtn.addEventListener('click', runKeyDelete);
        });
    };

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

})();

